            const filterList = (list, key) => list.filter(item => item[key].toLowerCase().includes(searchQuery));

            if (evt && (evt.key !== 'Backspace' || evt.key === 'Backspace')) {
                if (vm.activeTabs === 'AllUsers') {
                    vm.ChatUserListData = filterList(vm.tmpChatUserList, 'GROUP_NAME');
                    vm.pinnedArray = filterList(vm.tmpAllpinnedArray, 'GROUP_NAME');
                    vm.AllContactList = filterList(vm.tmpAllContactUserList, 'CONTACTNAME');
                } else if (vm.activeTabs === 'Group') {
                    if (vm.newChatOrGroup) {
                        vm.AllContactList = filterList(vm.tmpAllContactUserList, 'CONTACTNAME')
                    } else {
                        vm.groupRecords = filterList(vm.tmpgroupRecords, 'GROUP_NAME');
                    }
                } else if (vm.activeTabs === 'Archived') {

                    vm.AarchivedUsersList = filterList(vm.tmpArchiveList, 'GROUP_NAME');

                }
            } else {
                vm.ChatUserListData = vm.tmpChatUserList;
                vm.AllContactList = vm.tmpAllContactUserList;
                vm.pinnedArray = vm.tmpAllpinnedArray;
                vm.groupRecords = vm.tmpgroupRecords;
                vm.AarchivedUsersList = vm.tmpArchiveList;
            }
        },

