        SendAttachment: async function () {

            this.token = this.store.getUserInformation.Token
            this.filesdetails=[];
            const vm = this;
            let parent_id = '';
            let parent_text = ''
            var formData = new FormData();
            formData.append("fileId", 0);
            formData.append("folderId", 0);
            formData.append("moduleName", 'UnifiedCommunication');
            formData.append("subModuleName", '');
            formData.append("isGlobal", 0);
            formData.append("file", vm.AttachmentFileDetail[0]);
            // vm.closeAttachmentPop();
            axios.post(this.uploadUrl, formData, {
                    headers: {
                        'Authorization': 'Bearer ' + this.token
                    },
                })
                .then((response) => {
                    if (response.data.errorMsg == null) {

                        if (JSON.parse(response.data.FileID)[0].Value > 0) {
                            vm.SavedFileId = JSON.parse(response.data.FileID)[0].Value;
                            console.log()
                            this.filesdetails.push({
                                fileType: response.data.FileType === 'image' ? 'attachment' : response.data.FileType,
                                file: response.data.FileName,
                                size: response.data.FileSize,
                                url: response.data.FilePath,
                                from: vm.sender.id,
                                typePath: response.data.FileType,
                                fileId: vm.SavedFileId
                            });
                            // vm.ShowAlert("File new version has been upload successfully", "success", true);
                            // vm.$socket.emit('Send attachments', params)
                            //  vm.ReplyCross();
                            // vm.isLoading = false;
                            // setTimeout(() => {
                            //     vm.fileInProgress = false
                            // }, 100)

                        }
                        vm.AttachmentFileDetail = []
                    } else {
                        vm.fileInProgress = false;
                        vm.ShowAlert(response.data.errorMsg, "failure", vm.$t('Alert'));
                        vm.AttachmentFileDetail = []
                    }

                })

                .catch((err) => {
                    console.error(err);
                    vm.isLoading = false;
                });
            let myObj = {
                companyId: vm.sender.companyId,
                userId: vm.sender.id,
                emaiId: vm.sender.emaiId,
                name: vm.sender.name,
                imgPath: vm.store.getBlobUserUrl + vm.sender.imgPath,
                type: vm.type
            }
            vm.$socket.emit('user total', myObj);

        },
        async addNewChatOrGroup() {
            //debugger
            const vm = this;
            let status =  await checkPrivilege('Communication','addnewcontect',vm)
            if(status){            
            
            this.txtSearchChatGroups = ''
            this.newChatOrGroup = true
            this.GetContactList();
            }
        },
        getUser(id) {
            return this.store.getContactList.find(item => item.USER_ID == id)
        },
        nextTocreateGroup() {
            if (this.selectedMembers.length >= 2) { 
                this.addGroupMember =  false;
            } else {
                this.addGroupMember = true
                this.ShowAlert(this.$t("Pleaseselectatleast3userfromuserlist"), "warning", true, this.$t("Alert"));
                
            }

        },
        triggerFileInput() {
            this.$refs.fileInput.click();
        },
        backToChat() {
            this.txtSearchChatGroups = ''
            this.newChatOrGroup = false
            this.selectedMembers = []
            this.grouptitle = ''
            this.groupDescription = ''
            this.group = '-1'
            this.ConnectIO();
            this.addGroupMember=true
        }

    },
    setup() {

        return {
            
        }
    }
}
</script>
