                <div class="btn dropdown-toggle fw-bold show" type="button" id="dropdownMenuButton1" data-bs-toggle="dropdown" aria-expanded="true" @click="isExpanded =!isExpanded">Call from: {{ store.getTwilioAccountDetails ? store.getTwilioAccountDetails.NUMBER : ''}} <i class="fa fa-angle-down"></i></div>
