<script>
import DialPadDigit from './DialPadDigit.vue';
import {
    secondsToHms
} from "@/assets/common/vue-common"
export default {
    components: {
        DialPadDigit
    },
    props: {
        store: {
            type: Object
        }
    },
    data() {
        return {
            dialInput: '',
            contactsearch: [],
            isExpanded: false,
            isExpandedCalling: false,
            isMuted: false,
            isOnHold: false,
            callStatus:'',
            headphonesConnected:false

        };
    },
    computed: {
        muteUnmuteIcon() {
            return this.isMuted ? 'fa-microphone-slash' : 'fa-microphone';
        },
        muteUnmuteLabel() {
            return this.isMuted ? 'Unmute' : 'Mute';
        },
        holdLabel() {
            return this.isOnHold ? 'Unhold' : 'Hold';
        },
    },
    sockets: {
        call_status: function (message) {
            const vm = this;
            this.callStatus = message.call.CallStatus
        }
    },
    methods: {

        // Mute the call
        toggleMute() {
            let callRunningData = this.store.getIncomingCallData ? this.store.getIncomingCallData : this.store.getOutGoingcallData
            if (callRunningData) {
                this.isMuted = !this.isMuted;
                callRunningData.mute(this.isMuted);
            }
        },
        toggleHold() {
            let callRunningData = this.store.getIncomingCallData ? this.store.getIncomingCallData : this.store.getOutGoingcallData
            if (callRunningData) {
        this.isOnHold = !this.isOnHold;
        const event = this.isOnHold ? 'hold-call' : 'resume-call';
        this.$socket.emit(event, callRunningData.parameters.CallSid);
      }
    },
        transferCall() {
            let callRunningData = this.store.getIncomingCallData ? this.store.getIncomingCallData : this.store.getOutGoingcallData
      if (callRunningData) {
        this.$socket.emit('transfer', { number: '+918209463215' });
        this.$socket.on('transferred', (response) => {
          console.log('Call transferred:', response);
          // Handle the response (e.g., update UI or notify the user)
        });
        this.$socket.on('transfer_error', (error) => {
          console.error('Transfer failed:', error);
          // Handle the error (e.g., show an error message)
        });
      }
    },

        dialpaidValue(event) {
            this.dialInput += event
            this.searchContact()

        },
        makeCall() {
            if (this.store.$state.callToken) {
                var params = {
                    To: this.dialInput,
                };
                this.store.makeOutgoingCall(params)
                //this.store.insertNotifications({type:'call'})
            } else {
                this.getToken()
            }

        },
        async getToken() {
            const vm = this;
            await vm.updateDevices()
            if (!vm.headphonesConnected) {
                vm.ShowAlert(vm.$t("ConnectDevice"), "warning", true, vm.$t("Alert"));
                return;
            } else {
                if (vm.store.getTwilioAccountDetails) {
                    const Orte = ['first', 'second', 'third', 'user', 'callUser']
                    const randomWord = Orte[Math.random() * Orte.length | 0]
                    await vm.$socket.emit('getToken', {
                        identity: randomWord,
                    }, function (deviceToken) {
                        vm.store.$state.callToken = deviceToken.deviceToken
                        vm.store.intitializeDevice()
                    });
                } else {
                    vm.ShowAlert(vm.$t("CreateAccount"), "warning", true, vm.$t("Alert"));
                }
            }
        },
        async updateDevices() {
            try {
                const stream = await navigator.mediaDevices.getUserMedia({
                    audio: true
                });

                this.headphonesConnected = true
            } catch (error) {
                this.headphonesConnected = false
            }

        },
        searchContact() {
            const filter = this.store.getContactList.filter(item => item.USER_PHONE ? item.USER_PHONE.includes(this.dialInput) : "")
            console.log("checkkk", filter)
        }
    },
    setup() {
        return {
            secondsToHms
        }
    }
}
</script>

