<template>
<section>
    <!-- forward new contact end  Modal -->
    <div class="modal d-block forwardmodal" id="forwarcontactModal" tabindex="-1" aria-hidden="true">

        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content p-0">
                <div class="modal-header ">
                    <h5 class="modal-title"><i v-if="isNewContact==true" class="fas fa-arrow-left pe-2" v-on:click="backToRecentChat"></i>{{ isNewContact ? ' Forward to new contact' : 'Forward To'}} </h5>
                    <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close" v-on:click="ForwardClose"></button>
                </div>
                <div class="modal-body">
                    <div class="d-flex p-0 align-items-center mb-3">
                        <div class="search-box chat-search-box w-100">
                            <div class="input-group mb-0 rounded-3">
                                <input type="text" class="form-control bg-light" :placeholder="searchPlaceholder" v-model="txtSearchForward" v-on:keyup="SearchUsears($event)" aria-label="Search messages or users" aria-describedby="basic-addon1">
                                <span class="input-group-text text-muted bg-light pe-3 ps-3 border-0" id="basic-addon1">
                                    <i v-if="txtSearchForward" class="ri-close-line search-icon font-size-18" @click="txtSearchForward='';SearchUsears()"></i>
                                    <i v-else class="ri-search-line search-icon font-size-18"></i>
                                </span>
                            </div>
                        </div>
                        <div class="adduser" v-if="isNewContact==false">
                            <a  v-on:click="contactPreview" data-bs-toggle="modal" data-bs-target="#forwarcontactModal"><i class="fas fa-user-plus"></i></a>
                        </div>
                    </div>
                    <h6> {{ isNewContact ? 'Contacts' : 'Recent Chats'}}</h6>
                    <div class="recentchats ">
						<div v-if="isNewContact">
						<span class="no_record_found" v-if="filterRecentUser(ForwardUsersList).length==0">{{ $t('NoDataTodisplay') }}</span></div>
						<div v-else>
							<span class="no_record_found" v-if="recentChatUserList.length==0">{{ $t('NoDataTodisplay') }}</span></div>
                        <ul>
                            <template v-if="isNewContact==true">
                                <li v-for="(items,ForwardItemIndex) in filterRecentUser(ForwardUsersList)" :key="ForwardItemIndex">
                                    <div class="d-flex p-0 align-items-center">
                                        <ImageORColor imageUperDivClass="chat-user-img  align-self-center me-3 ms-0" imageClass="rounded-circle avatar-xs" spanUperDivClass="avatar-xs" spanClass="avatar-title rounded-circle bg-red-subtle" :name="items.CONTACTNAME" :image="items.USER_IMAGE">

                                        </ImageORColor>

                                        <h5 class="text-truncate mb-0 me-auto">{{ items.CONTACTNAME}}</h5>
                                        <div class="form-check ">
                                            <input type="checkbox" @change="handleCheckboxChange" :disabled="forwardCheckBox.length >= 10 && !forwardCheckBox.includes(items.USER_ID)" v-model="forwardCheckBox" :value="items.USER_ID" class="form-check-input" id="privacy-lastseenSwitch">
                                            <label class="form-check-label" for="privacy-lastseenSwitch"></label>
                                        </div>
                                    </div>
                                </li>
                            </template>
                            <template v-if="isNewContact==false">
                                <li v-for="(items,ForwardItemIndex) in recentChatUserList" :key="ForwardItemIndex">
                                    <div class="d-flex p-0 align-items-center">
                                        <ImageORColor imageUperDivClass="chat-user-img  align-self-center me-3 ms-0" imageClass="rounded-circle avatar-xs" spanUperDivClass="avatar-xs" spanClass="avatar-title rounded-circle bg-red-subtle" :name="items.GROUP_NAME" :image="items.AVATAR">

                                        </ImageORColor>

                                        <h5 class="text-truncate mb-0 me-auto">{{ items.GROUP_NAME}}</h5>
                                        <div class="form-check ">
                                            <input type="checkbox" @change="handleCheckboxChange" :disabled="forwardCheckBox.length >= 10  && !forwardCheckBox.includes(items.GROUP_ID)" v-model="forwardCheckBox" :value="items.GROUP_ID" class="form-check-input" id="privacy-lastseenSwitch">
                                            <label class="form-check-label" for="privacy-lastseenSwitch"></label>
                                        </div>
                                    </div>
                                </li>
                            </template>
                        </ul>

                    </div>

                </div>
                <div class="modal-footer">
                    <div class="added-members px-3 pt-0 w-100">
                        <div class="select-viwer-box mb-3 horrizontal" v-if="Ismemeberselected">
                            
                                <div class="select-viwer-right-box d-flex align-items-center chat-user-list"  v-for="member,index in forwardCheckBox" :key="index">
                                    <ImageORColor imageUperDivClass="chat-user-img  align-self-center me-0 ms-0" imageClass="rounded-circle avatar-xs" spanUperDivClass="avatar-xs" spanClass="avatar-title rounded-circle bg-red-subtle" :name="getUser(member).CONTACTNAME ? getUser(member).CONTACTNAME : getUser(member).GROUP_NAME" :image="getUser(member).USER_IMAGE ? getUser(member).USER_IMAGE :getUser(member).AVATAR" />

                                    <h5 class="select-sub-heading text-truncate">{{ getUser(member).CONTACTNAME ? getUser(member).CONTACTNAME : getUser(member).GROUP_NAME  }}</h5>
                                    <i class="fa fa-times" @click="forwardCheckBox = forwardCheckBox.filter(item => item !== member)"></i>
                                </div>

                            
                        </div>
                        <button :class="{'disabled':forwardCheckBox.length==0}" type="submit" class="btn btn-primary font-size-16 btn-lg chat-send waves-effect waves-light float-right" v-on:click="ForwardToUser(forwardCheckBox)">
                            <svg height="20" viewBox="0 0 20 20" width="20" xmlns="http://www.w3.org/2000/svg">
                                <path d="m2.72112607 2.05149449 15.35446653 7.565969c.247703.12205658.3495596.42180601.227503.66950901-.048698.0988284-.1286747.1788051-.227503.2275031l-15.3541508 7.5658134c-.24770306.1220566-.54745246.0202-.66950904-.227503-.0533719-.1083136-.06574404-.2322825-.03483109-.3490077l1.52125123-5.7446792c.05030971-.1899839.20725125-.3328751.40110728-.3651979l6.88094892-1.1473027c.0842946-.0140491.1539978-.0697032.1874987-.1453514l.018-.0601474c.0194561-.11673645-.0453599-.22804672-.1500414-.27176154l-.0554573-.01593664-6.91980045-1.15330008c-.1939323-.03232205-.35092201-.17529727-.401185-.36537116l-1.48266862-5.60684181c-.07063055-.26695681.08852333-.54062543.35548014-.61125598.11669248-.03087411.24061464-.01849152.3488909.034862z" fill="#fff"></path>
                            </svg>
                        </button>
                    </div>
                </div>
            </div>
        </div>
    </div>
    <!-- forward new contact end modal -->
</section>
</template>

<script>
import DataService from '../services/DataService';
import {
    communicationStore
} from "@/stores/Communication.js"
export default {

    data() {
        return {
            defaultImg: 'https://talygenv.github.io/Vue-UI-Content/images/DefaultImages/uc_user_new.jpg',
            selectUserIds: [],
            txtSearchForward: '',
            isNewContact: false,
            recentChatUserList: [],
            forwardCheckBox: [],
            ForwardUsersList: [],
            Ismemeberselected:false
        }
    },
    computed: {
        searchPlaceholder() {
            return this.isNewContact ? 'Search by name email and number' : 'Search by name email';
        }
    },
    created: async function () {
        this.tmpFilter = this.store.getContactList
        this.recentChatUserList = this.store.getRecentChatUser
        this.searchFilterRecentChatUser = this.recentChatUserList
    },
    methods: {
        handleCheckboxChange(event) { 
             
            if(this.forwardCheckBox.length >0 )
            {
               this.Ismemeberselected=true
            }
            else
            {
                this.Ismemeberselected=false
            } 
            if (this.forwardCheckBox.length == 10) {

                this.ShowAlert(this.$t("ForwardUserLimit"), "warning", true, this.$t("Alert"));
                return false;
            }
        },

        filterRecentUser: function () {
            const vm = this;
            vm.recentChatUserList.forEach((itm) => {
                var curIndx = vm.ForwardUsersList.findIndex(x => x.USER_ID == itm.RECEIVER_ID);
                if (curIndx != -1) {
                    vm.ForwardUsersList.splice(curIndx, 1);
                }
            });
            return vm.ForwardUsersList
        },
        SearchUsears: function (evt) {
            const vm = this;
            let result = '';
            let result2 = '';
            let searchText = vm.txtSearchForward.toLowerCase();

            if (evt && evt.key != 'Backspace') {
				vm.ForwardUsersList = [];
				result = vm.tmpFilter.filter(x => {
					return ((x.CONTACTNAME && x.CONTACTNAME.toLowerCase().includes(searchText))  ||
							(x.EMAIL_ID && x.EMAIL_ID.toLowerCase().includes(searchText)) ||
							(x.USER_PHONE && x.USER_PHONE.toLowerCase().includes(searchText)));
				});
				vm.ForwardUsersList = result;

					vm.recentChatUserList = [];
					result2 = vm.searchFilterRecentChatUser.filter(x => {
						return ((x.GROUP_NAME && x.GROUP_NAME.toLowerCase().includes(searchText)) ||
								(x.EMAIL_ID && x.EMAIL_ID.toLowerCase().includes(searchText)) );
					});
					vm.recentChatUserList = result2;
				} else if (evt && evt.key == 'Backspace') {
					vm.ForwardUsersList = [];
					result = vm.tmpFilter.filter(x => {
						return ((x.CONTACTNAME && x.CONTACTNAME.toLowerCase().includes(searchText)) ||
								(x.EMAIL_ID && x.EMAIL_ID.toLowerCase().includes(searchText)) ||
								(x.USER_PHONE && x.USER_PHONE.toLowerCase().includes(searchText)));
					});
					vm.ForwardUsersList = result;

					vm.recentChatUserList = [];
					result2 = vm.searchFilterRecentChatUser.filter(x => {
						
						return ((x.GROUP_NAME && x.GROUP_NAME.toLowerCase().includes(searchText)) ||
						(x.EMAIL_ID && x.EMAIL_ID.toLowerCase().includes(searchText)) );
					});
					vm.recentChatUserList = result2;
				} else {
					vm.ForwardUsersList = vm.tmpFilter;
					vm.recentChatUserList = this.store.getRecentChatUser;
				}
			},
        contactPreview: function () {
            this.txtSearchForward = '';
            this.ForwardUsersList = this.tmpFilter;
            this.recentChatUserList = this.searchFilterRecentChatUser
            this.isNewContact = true;
        },
        backToRecentChat: function () {
            this.txtSearchForward = '';
            this.ForwardUsersList = this.tmpFilter;
            this.recentChatUserList = this.searchFilterRecentChatUser
            this.isNewContact = false;
        },
        isSelected(id) {
            if (this.selectedUserIds != undefined)
                return this.selectedUserIds.includes(id);
        },

        ForwardToUser: function (users) {
            this.$parent.messageForward(users);
        },
        ForwardClose: function () {
            this.$parent.forwardCancel();
        },
        getUser(id) {
            let recent = this.store.getRecentChatUser.find(item => item.GROUP_ID == id)
			console.log("checkkkkk",recent)
            let contact = this.store.getContactList.find(item => item.USER_ID == id)
            return recent ? recent : contact
        },
    },
    setup() {
        const store = communicationStore()
        return {
            store,
        }
    }
}
</script>
