            </section>
            <section class="main-content">
                <ValidationObserver ref="form" v-slot="{ handleSubmit }">
                    <form v-on:submit.prevent="handleSubmit(formSubmit)" ref="commentForm">
                        <div class="container-fluid px-0">
                            <div class="border p-3 bg-white">
                                <div class="row">
                                    <div class="col-lg-6">
                                        <div class="form-group">
                                            <label class="" for="Title">{{ $t('Twilio_title') }}</label>:
                                            <span class="mandatory">*</span>
                                            <ValidationProvider rules="required" v-slot="{ errors }">
                                                <input class="form-control" v-model="deviceSetup.Title" id="Title" name="Title" type="text" autocomplete="off" :class="errors[0] ? 'is-invalid error' : ''">
