                                    </div>
                                    <div class="col-lg-6">
                                        <div class="form-group">
                                            <label>{{ $t('Status') }}:</label>
                                            <ValidationProvider rules="required" v-slot="{ errors }">
                                                <select class="form-control valid" name="StatusId" v-model="deviceSetup.StatusId" :class="errors[0] ? 'is-invalid error' : ''">
                                                    <option value="1001">Active</option>
