                                            </ValidationProvider>
    
                                        </div>
                                    </div>
                                    <div class="col-lg-6">
                                        <div class="form-group">
                                            <label class="" for="AccountSid">{{ $t('AccountSid') }}</label>:
                                            <span class="mandatory">*</span>
                                            <ValidationProvider rules="required" v-slot="{ errors }">
                                                <input :disabled="update" class="form-control textfield form-control " :class="errors[0] ? 'is-invalid error' : ''" v-model="deviceSetup.AccountSid" name="AccountSid" type="text">
                                                <span v-if="errors[0]" class="invalid-feedback">
                                                    {{ errors[0] }}
                                                </span>
                                            </ValidationProvider>
    
                                        </div>
                                    </div>
                                    <div class="col-lg-6">
                                        <div class="form-group">
                                            <label class="" for="AuthToken">{{ $t('AuthToken') }}</label>:<span class="mandatory">*</span>
                                            <ValidationProvider rules="required" v-slot="{ errors }">
                                                <input :disabled="update" class="form-control textfield form-control" :class="errors[0] ? 'is-invalid error' : ''" v-model="deviceSetup.AuthToken" maxlength="100" name="AuthToken" type="text" autocomplete="off">
                                                <span v-if="errors[0]" class="invalid-feedback">{{ errors[0] }}</span>
                                            </ValidationProvider>
                                        </div>
                                    </div>
                                    <div class="col-lg-12 mt-1">
                                        <div class="form-group">
                                            <label class="" for="Description">{{ $t('description') }}</label>:
                                            <textarea v-model="deviceSetup.Description" class="form-control form-control" cols="10" id="Description" maxlength="250" name="Description" rows="5"></textarea>
                                        </div>
                                    </div>
                                </div>
                                <div class="row flex-row-reverse mt-3">
                                    <div class="col-lg-6 d-flex justify-content-end">
                                        <button type="submit" class="btn btn-success me-2" id="btnSave">
                                            <i class="fa fa-save me-2"></i>{{ update ? $t('Update') : $t('Save') }}
                                        </button>
                                        <button title="" @click="cancel()" class="btn btn-danger" data-toggle-tooltip="tooltip" data-original-title="Cancel">
                                            <i class="fa fa-close me-2"></i>{{ $t('Cancel') }}</button>
                                    </div>
                                    <div class="col-lg-6">
                                        <div class="py-2">
                                            <span class="mandatory">{{ $t('MandatoryString') }}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </form>
                </ValidationObserver>
            </section>
            <div class="container-fluid padding-t_10">
                <div class="theme-primary partition-full mt-4">
                    <div class="p-name text-black pb-2">{{ $t('ListOfPurchased') }}</div>
                </div>
                <div class="table-responsive">
                    <table id="mainTable1" class="table table-bordered dataTable no-footer">
                        <thead class="thead-bg">
                            <tr>
                                <th scope="col"><span>{{ $t('FriendlyName') }}</span></th>
                                <th scope="col"><span>{{ $t('SelectPhoneNumber') }}</span></th>
                                <th scope="col"><span>{{ $t('IsoCountry') }}</span></th>
                                <th scope="col" class="text-center" name="SMS"><span>{{ $t('SMS') }}</span></th>
                                <th scope="col" class="text-center" name="Voice"><span>{{ $t('Voice') }}</span></th>
                                <th scope="col" class="text-center"><span>{{ $t('Assign') }}</span></th>
                                <!-- <th scope="col" class="text-center" name="Voice"><span>{{ $t('IVR') }}</span></th> -->
                            </tr>
                        </thead>
                        <tbody>
                            <tr v-for="info,numberIndex in numberInfo" :key="numberIndex">
                                <td>{{ info.friendlyName }}</td>
                                <td>{{ info.phoneNumber }}</td>
                                <td>{{ '-' }}</td>
                                <td>{{ info.capabilities ? info.capabilities.sms : '-' }}</td>
                                <td>{{ info.capabilities ? info.capabilities.voice : '-' }}</td>
                                <td><button class="btn btn-success" @click="numberAssignTouserShowPopup(info)">{{ $t('UserAssign') }}</button></td>
                            </tr>
                            <tr v-if="numberInfo.length == 0">
                                <td class="text-center" colspan="6">
                                    <span class="text-danger">{{ $t('No_Record_Found') }}</span>
                                </td>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    
        <div class="modal d-block forwardmodal" style="opacity:1;display: block;" v-if="userAssignPopup">
            <div class="modal-dialog modal-dialog-centered maxwidth800">
                <div class="modal-content p-0">
                    <div class="modal-header">
                        <h5 class="modal-title">
                            <!---->{{ assignUserInfo.phoneNumber + ' ' + $t('NumberAssignToUser') }} </h5><button type="button" data-bs-dismiss="modal" aria-label="Close" class="btn-close" v-on:click="userAssignClose()"></button>
                    </div>
    
                    <div class="modal-body" style="overflow: auto;">
    
                        <div class="col-12 p-0">
                            <div class="col-12 p-0 mt-0 mb-3 float-left">
    
                                <div class="d-flex p-0 align-items-center mb-3">
                                    <div class="search-box chat-search-box w-100">
                                        <div class="input-group mb-0 rounded-3">
                                            <input type="text" placeholder="Search By Title" aria-label="Search messages or users" aria-describedby="basic-addon1" class="form-control bg-light" v-model="userSearch">
                                            <span id="basic-addon1" class="input-group-text text-muted bg-light pe-3 ps-3 border-0">
                                                <i class="ri-search-line search-icon font-size-18"></i></span>
                                        </div>
                                    </div>
    
                                </div>
    
                            </div>
    
                            <div class="col-12 mt-0 mb-4 float-left px-3" style="max-height: 250px; overflow-y: auto;">
                                <div class="recentchats ">
    <div>
                                    <span class="no_record_found" v-if="userSearchGetData(store.getContactList).length==0">{{ $t('NoDataTodisplay') }}</span>
    
                                    <ul>
                                        
                                       
                                        <li v-for="item,index in userSearchGetData(store.getContactList)">
                                            <div class="d-flex p-0 align-items-center">
                                                <ImageORColor imageUperDivClass="chat-user-img  align-self-center me-3 ms-0" imageClass="rounded-circle avatar-xs" spanUperDivClass="avatar-xs" spanClass="avatar-title rounded-circle bg-red-subtle" :name="item.CONTACTNAME" :image="item.USER_IMAGE">
    
                                                </ImageORColor>
    
                                                <h5 class="text-truncate mb-0 me-auto">{{ item.CONTACTNAME}}</h5>
                                                <div class="form-check ">
                                                    <input type="checkbox" v-model="users" :value="item.USER_ID" class="form-check-input" id="privacy-lastseenSwitch">
                                                    <label class="form-check-label" for="privacy-lastseenSwitch"></label>
                                                </div>
                                            </div>
                                        </li>
    
                                    </ul>
    
                                </div>
                                </div>
                            </div>
                        </div>
    
                    </div>
                    <div class="modal-footer">
                        <a href="javascript:;" class="btn btn-success" v-on:click="assignUser()"> {{ $t('Assign') }}</a>
                    </div>
                </div>
            </div>
        </div>
    </div>
    </template>
    
    <script>
    import {
        ValidationProvider,
    
        ValidationObserver
    } from 'vee-validate';
    import DataService from '../services/DataService';
    import Pager from '@/components/Common/Pager.vue';
    export default {
        name: "Tokbox",
        components: {
            ValidationProvider,
            ValidationObserver,
            Pager
        },
        props: {
            store: {
                type: Object
            },
            addDeviceSetup: {
                type: Boolean
            }
        },
        data() {
            return {
                deviceSetup: {
                    Title: '',
                    StatusId: '',
                    AccountSid: '',
                    AuthToken: '',
                    Description: '',
                },
                form: {},
                numberInfo: [],
                TotalRecords: 0,
                CurrentPageNumber: 0,
                PageNumber: 1,
                PageSize: 10,
                SortBy: '',
                SortExp: '',
                PageSizeOption: null,
                update: false,
                userAssignPopup: false,
                assignUserInfo: '',
                users: [],
                userSearch: ''
            }
        },
        created() {
            this.FetchData() 
            //  this.$socket.emit('twilioSendMessage', {from:'+12513095602',to:'+918209463215' },function (record) {
            //             console.log("createApiKey",record)
    
            //     })
            let url = `search=&pageSize=&pageNum=&sortBy=&sortExp=&type=company&city=&departmentId=`;
            this.store.getContact(url)
            Object.assign(this.form, this.deviceSetup)
        },
        watch: {
            //twilioSetup: function() { // watch it
            // this.update = false
            // Object.assign(this.deviceSetup, this.form)
            //}
        },
        methods: {
            async FetchData() {
                var vueObj = this;
                let url = `pageSize=${vueObj.PageSize}&pageNum=${vueObj.PageNumber}&sortBy=${vueObj.SortBy}&sortExp=${vueObj.SortExp}`
                await vueObj.store.twilioList(url)
                vueObj.TotalRecords = this.store.getTwilioList.length > 0 ? vueObj.store.getTwilioList[0].TotalRecord : 0
            },
            sortdata: function (sortBy) {
    
                this.SortBy = sortBy;
                var sortExp = 'ASC';
                if (this.SortExp == 'ASC') {
                    sortExp = 'DESC';
                }
                this.SortExp = sortExp;
                this.PageNumber = 1;
                this.FetchData();
            },
    
            cancel() {
                this.update = false
                Object.assign(this.deviceSetup, this.form)
                this.numberInfo = []
                this.users = []
                this.$emit('twilioAddPage', false)
            },
            formSubmit() {
                
            },
            pagerMethod: function (value) {
                this.PageSize = value.PageSize;
                this.PageNumber = value.PageNumber;
                this.FetchData();
            },
            updateStatus(record) {
                DataService.AddTwilio(record)
            },
            
            deleteRecord(record) {
                const vm = this;
                vm.confirmR(vm.$t("ConfirmDeleteAccount"), true, vm.$t("Delete"), async function () {
                    DataService.DeleteTwilio(`id=${record.TwilioCredentialId}`).then((result) => {
                        if (result.data) {
                            vm.store.$state.twilioListaState = vm.store.getTwilioList.filter((item) => item.TwilioCredentialId !== record.TwilioCredentialId)
                            vm.ShowAlert(vm.$t("TwilioDelete"), "success", true, vm.$t("Alert"));
                        } else {
                            vm.ShowAlert(vm.$t("Error"), "warning", true, vm.$t("Alert"));
                        }
                    })
                })
            },
            generateSecret(itm) {
                const vm = this;
                var obj = {
                    TWILIO_CREDENTIAL_ID: itm.TwilioCredentialId,
                    ACCOUNT_SID: itm.AccountSid,
                    AUTH_TOKEN: itm.AuthToken,
                    keyStatus: 'update'
                }
                vm.$socket.emit('createApiKey', obj, function (record) {
    
                    if (record.STATUS == 1) {
                        vm.ShowAlert(vm.$t("KeyAndSecretUpdate"), "success", true, vm.$t("Alert"));
                    } else {
                        vm.ShowAlert(vm.$t("Error"), "warning", true, vm.$t("Alert"));
                    }
                })
            },
            numberAssignTouserShowPopup(itm) {
                this.assignUserInfo = itm
                console.log("numberAssignToUser", itm)
                this.userAssignPopup = true
    
            },
            assignUser() {
                // console.log("testt",this.assignUserInfo)
                // console.log("this.deviceSetup",this.deviceSetup)
                let obj = {
                    "extension": this.assignUserInfo.phoneNumber,
                    "twilioCredentialId": this.deviceSetup.TwilioCredentialId,
                    "status_id": '1001',
                    "config_id": '',
                    "name": '',
                    "to_User_Id": ''
    
                }
                this.users.map((item, index) => {
                    let objectName = this.store.getContactList.find(data => data.USER_ID == item)
                    obj.name += index == 0 ? objectName.CONTACTNAME : ',' + objectName.CONTACTNAME
                    obj.to_User_Id += index == 0 ? item : ',' + item
                })
                DataService.AssignNumberToUser(obj).then((result) => {
                    this.users = []
                    this.userAssignPopup = false
                    this.userSearch = ''
                    this.store.GetTwilioUserConfigDetail()
                    if (result.data && result.data[0].value == "1") {
                        this.ShowAlert(this.$t('NumberAssign'), "success", true, this.$t("Alert"));
                    } else {
                        this.ShowAlert(this.$t('SomeThingWent'), "danger", true, this.$t("Alert"));
                    }
                })
    
            },
            userSearchGetData(data) {
                let user = data.find(item=>item.USER_ID==this.store.GetSenderDetail.id)
                if(!user){
                data.push({"CONTACTNAME" :this.store.GetSenderDetail.name,"USER_ID":this.store.GetSenderDetail.id,"USER_IMAGE":this.store.GetSenderDetail.imgPath})
                }
                if (this.userSearch) {
                    var results = [];
                    results = data.filter(obj => obj.CONTACTNAME.toLowerCase().includes(this.userSearch.toLowerCase()));
                    return this.userSearch != '' ? results : data
                } else {
                    return data
                }
            },
            userAssignClose() {
                this.users = []
                this.userAssignPopup = false
                this.userSearch = ''
            }
    
        },
    
    }
    </script>
    