                    <div class="accordion-body p-2">

                        <ul class="nav nav-tabs accordiontabs" id="myTab" role="tablist">
                            <listItem text="Video" @click="activeTab('video')" :className="{'active':activeLeftLink=='video'}"/>
                        </ul>

                    </div>
                    <template v-slot:icon>
                        <i class="fas fa-video skybluetxt me-1"></i>
                    </template>
                </AccordionItem> -->
