<script>
import AccordionItem from '@/components/Call//AccordionItem.vue';
import listItem from '@/components/Common/ListItem.vue';
export default {
    inject: ['responsiveCssFunction'],
    components: {
        AccordionItem,
        listItem
    },
    props: {
        store: {
            type: Object
        }
    },
    data() {
        return {
            activeLeftLink:''
        };
    },
    created() {
        const ww = document.body.clientWidth;
            if (ww > 992) {
               this.activeTab('')
            }
    },
    methods: {
        activeTab(event){
           this.activeLeftLink = event
           this.$emit('settingLeftTabActive',event)
           this.responsiveCssFunction()
        }
    }
}
</script>
