<template>
<div class="tab-pane fade show active" id="pills-chat" role="tabpanel" aria-labelledby="pills-chat-tab">
    <!-- Start chats content -->
    <div>
        <div class="px-3 pt-3">
            <h4  class="mb-3 d-flex " :class="smsListShow ? 'justify-content-between' :'justify-content-left' "><i class="fas fa-arrow-left pe-2 handponter" style="cursor: pointer;" v-if="!smsListShow" @click="backToChat();searchNull()" title="Back To SMS"></i>  {{ $t('SMS') }}<i v-if="smsListShow" class="ri-add-line handpointer" :title="'add'" @click="smsListShow=false;searchNull();"></i></h4>
        </div>
        
        <div class="grid-view" >
            <div class="px-3 ">
                <div class="search-box chat-search-box">
                    <div class="input-group mb-3 rounded-3">
                        <input type="text" class="form-control bg-light" v-model="txtSearchChatGroups" id="UserSearch" @input="searchContact();groupContact();" placeholder="Search By Contact Name" aria-label="Search messages or users" aria-describedby="basic-addon1">
                        <span class="input-group-text text-muted bg-light pe-3 ps-3 border-0" id="basic-addon1">
                            <i v-if="smsList.length==0 && txtSearchChatGroups && smsListShow" class="ri-add-line search-icon font-size-18 handpointer" @click="addMessage()"></i>
                            <i v-if="txtSearchChatGroups" class="ri-close-line search-icon font-size-18 handpointer" @click="searchNull();searchContact();groupContact();"></i>
                            <i v-else class="ri-search-line search-icon font-size-18 handpointer"></i>
                            
                        </span>
                    </div>

                </div> <!-- Search Box-->
            </div>
            <div v-if="smsListShow">
            <div class="tab-pane fade show"  id="group" role="tabpanel" aria-labelledby="group-tab">
                    <div class="simplebar-content" v-if="smsList.length==0"><span class="no_record_found">{{ $t('NoRecordfound') }}</span></div>
                    <div class="chat-message-list px-3" data-simplebar>

                        <ul class="list-unstyled chat-list chat-user-list mt-2">
                           
                            <li v-for="userItems, index in  smsList" :key="index">
                                
                            <a>
            <div class="d-flex align-items-center">
                <ImageORColor @click="openSMS(userItems)" class="handpointer"
                    imageUperDivClass="chat-user-img align-self-center me-3 ms-0" :title="userItems.first_name? userItems.first_name : userItems.smsTo"
                    imageClass="rounded-circle avatar-xs" spanUperDivClass="avatar-xs"
                    spanClass="avatar-title rounded-circle bg-red-subtle" :name="userItems.first_name? userItems.first_name : userItems.smsTo" :image="userItems.AVATAR"
                    >
                </ImageORColor>

                <div class="flex-grow-1 overflow-hidden" @click="openSMS(userItems)">
                    <h5 class="text-truncate font-size-14 mb-1">
                        <span class="float-left handpointer" :title="userItems.first_name? userItems.first_name : userItems.otherphone">{{ userItems.first_name? userItems.first_name : userItems.otherphone }}</span>

                    </h5>
                    <p class="chat-user-message text-truncate mb-0">
                        {{userItems.body }}
                       
                    </p>
                </div>

                <!-- <p class="ut d-none"><img :src="leftIsTyping"></p> -->

                
               

            </div>
        </a>
        </li>
                            
                        </ul>
                    </div>

                </div>

        </div>
            <!-- .p-4 -->

            <!-- Start user status -->
            <div class="px-3 pb-4" dir="ltr" v-if="!smsListShow">

                <ul class="nav nav-tabs customtabs" id="myTab" role="tablist">
                    <li class="nav-item " role="presentation" @click="changeTabs('All')">
                        <button class="nav-link" :class="{'active':activeTab=='All'}" type="button">{{ $t('AllContact') }}</button>
                    </li>
                    <li class="nav-item" role="presentation" @click="changeTabs('group')">
                        <button class="nav-link " :class="{'active':activeTab=='group'}" type="button">{{ $t('Group') }}</button>
                    </li>
                </ul>
                <!-- end user status carousel -->
            </div>
            <!-- end user status -->

            <!-- Start chat-message-list -->

            <div class="tab-content" id="myTabContent" v-if="!smsListShow">
                <div class="tab-pane fade show " :class="{'active':activeTab=='All'}">
                    <div v-if="filterdContacts.length==0  "><span class="no_record_found">{{ $t('NoDataTodisplay') }}</span></div>
                    <div class="chat-message-list px-2" id="group-contacts" data-simplebar>
                        <ul class="list-unstyled chat-list chat-user-list">
                            <li v-for="contact,index in filterdContacts" :key="index">
                                
                                <a>
                                    <div class="d-flex" :class="{'align-items-center':contact.DEPARTMENT_NAME==null}">
                                        <div class="chat-user-img online align-self-center me-3 ms-0" v-if="contact.USER_IMAGE">
                                            <img :src="contact.USER_IMAGE ? contact.USER_IMAGE : 'https://talygenv.github.io/Vue-UI-Content/images/UC/uc_user_new.jpg'" class="rounded-circle avatar-xs" alt="">

                                        </div>
                                        <div class="avatar-xs me-2" v-else>
                                            <span class="avatar-title rounded-circle bg-red-subtle " :style="{ backgroundColor: getFirstTwoLettersWithColor(contact.CONTACTNAME).color }">
                                                {{ getFirstTwoLettersWithColor(contact.CONTACTNAME).letters}}
                                            </span>
                                        </div>
                                        <div class="flex-grow-1 overflow-hidden">
                                            <h5 class="text-truncate font-size-14 mb-1 handpointer">{{ contact.CONTACTNAME }}</h5>
                                            <p class="chat-user-message text-truncate mb-0">{{ contact.DEPARTMENT_NAME  }}</p>
                                        </div>
                                      
                                        <div class="form-check ">
                                            <input type="checkbox" v-model="smsContactSelect" :value="contact.USER_PHONE" @click="checkBoxAutoChecked" class="form-check-input" id="privacy-lastseenSwitch">
                                            <label class="form-check-label" for="privacy-lastseenSwitch"></label>
                                        </div>
                                    </div>
                                </a>
                            </li>
                        </ul>
                    </div>
                    <div class="btn-next-bottom checklist-text" :class="smsContactSelect.length ==0 ?'disabled':''"><button type="button" class="next-btn btn btn-primary" @click="sendMessageInBulk">Send</button></div>
                </div>
                <div class="tab-pane fade active show" v-if="activeTab=='group'">
                    <div v-if="departmentAndLoactionContact.length==0  "><span class="no_record_found">{{ $t('NoDataTodisplay') }}</span></div>
                    <div class="chat-message-list px-3" id="group-contacts" data-simplebar>
                        <div class="heading_department_group">
                            <template v-for="item of departmentAndLoactionContact">
                                {{ item.TYPE }}<span>{{ item.DATA.length }}
                                <div class="form-check ">
                                    <input type="checkbox" v-if="item.DATA.length>0" v-model="selectAllCheck" @click="allCheckBoxClick($event,item)" :value="item.TYPE" class="form-check-input" id="privacy-lastseenSwitch">
                                    <label class="form-check-label" for="privacy-lastseenSwitch"></label>
                                </div>
                            </span>
                                <div class="clear"></div>
                                <ul class="list-unstyled chat-list chat-user-list">
                                    <li v-for="contact,index in item.DATA">
                                        <a>
                                            <div class="d-flex">
                                                <div class="chat-user-img align-self-center me-2 ms-0">
                                                    <div class="chat-user-img online align-self-center me-3 ms-0" v-if="contact.USER_IMAGE">
                                                        <img :src="contact.USER_IMAGE" class="rounded-circle avatar-xs" alt="">

                                                    </div>
                                                    <div class="avatar-xs me-2" v-else>
                                                        <span class="avatar-title rounded-circle bg-red-subtle " :style="{ backgroundColor: getFirstTwoLettersWithColor(contact.CONTACTNAME).color }">
                                                            {{ getFirstTwoLettersWithColor(contact.CONTACTNAME).letters}}
                                                        </span>
                                                    </div>
                                                </div>
                                                <div class="flex-grow-1 overflow-hidden">
                                                    <h5 class="text-truncate font-size-14 mb-1 handpointer">{{ contact.CONTACTNAME }}</h5>
                                                    <p class="chat-user-message text-truncate mb-0">{{ contact.DEPARTMENT_NAME ? contact.DEPARTMENT_NAME : '-' }}</p>
                                                </div>

                                                <div class="form-check ">
                                                    <input type="checkbox" v-model="smsContactSelect" :value="contact.MOBILE_PHONE" @click="checkBoxAutoChecked" class="form-check-input" id="privacy-lastseenSwitch">
                                                    <label class="form-check-label" for="privacy-lastseenSwitch"></label>
                                                </div>
                                            </div>
                                        </a>
                                    </li>

                                </ul>
                            </template>
                        </div>

                    </div>
                    <div class="btn-next-bottom checklist-text" :class="smsContactSelect.length ==0 ?'disabled':''"><button type="button" class="next-btn btn btn-primary"  @click="sendMessageInBulk">{{ $t('Send') }}</button></div>
                </div>
                
                

            </div>

            <!-- End chat-message-list -->
        </div>

    </div>
    <!-- Start chats content -->
</div>
</template>

<script>
import {
    getFirstTwoLettersWithColor
} from "@/assets/common/vue-common"
export default {
    name: "LeftSMSTab",
    components: {

    },
    props: {
        store: {
            type: Object
        },
    },
    created() {
        this.fetchContacts();
    },
    sockets:{
        getListOfUserWithMessage:function(data){
            debugger
          this.smsGetFromServer = data
        }
    },
    computed:{
        filterdContacts(){
            return this.searchContact()
        },
        smsList(){
            return this.searchSMSList()
        }


    },
    methods: {
        async changeTabs(event) {
            this.activeTab = event;
            // if(this.activeTab == 'All'){
            //     this.searchContact()
            // }else{
            //     this.groupContact()
            // }
        },
        // async deparmentAndLocation(type, id) {
        //     const query = type === 'Department' ?
        //         `search=&pageSize=&pageNum=&sortBy=&sortExp=&type=&city=&departmentId=${id}` :
        //         `search=&pageSize=&pageNum=&sortBy=&sortExp=&type=&city=${id}&departmentId=`;
        //     await this.store.getContact(query);
        //     this.$parent.contactChatChange({
        //         view: this.contactView,
        //         userInformation: '',
        //         contactDetailShow: false
        //     });
        //     this.$parent.changeActiveTab()
        // },
        async fetchContacts() {
            this.txtSearchChatGroups = ''
            const url = `search=&pageSize=&pageNum=&sortBy=&sortExp=&type=company&city=&departmentId=`;
            const query = `city=&departmentId=&groupBy=All`;
            await this.store.unifiedContactList(query);
            await this.store.getContact(url);
            this.searchContact()
            this.groupContact()
            let data = {
                LOGINUSER_ID: this.store.GetSenderDetail.id,
                COMPANY_ID: this.store.GetSenderDetail.companyId,
                PhonNo:this.from
            }
            this.$socket.emit('GetsmsListbyid',data)

        },
        searchContact() {
            const contactWithNumber = this.store.getContactList.filter(item => item.USER_PHONE && item.USER_PHONE.trim() !== '');
            let searchQuery = this.txtSearchChatGroups.toLowerCase();
            const filterList = (list, key) => list.filter(item => item[key].toLowerCase().includes(searchQuery));
            return filterList(contactWithNumber, 'CONTACTNAME');
        },
        searchSMSList() {
            let searchQuery = this.txtSearchChatGroups.toLowerCase();
            const filterList = (list, keys) => {
                return list.filter(item => {
                    return keys.some(key => item[key] && item[key].toLowerCase().includes(searchQuery));
                });
            };
            return filterList(this.smsGetFromServer, ['phone_number']);
            //return this.smsGetFromServer
        },
        // departmentContacts(name) {
        //     return this.filterdContacts.filter(item => item['DEPARTMENT_NAME'] == name)
        // },
        groupContact() {
            const filteredData = this.store.getUnifiedContacts.map(group => {
  return {
    ...group,
    DATA: group.DATA.filter(contact => contact.MOBILE_PHONE && contact.MOBILE_PHONE.trim() !== '')
  };
});
            this.departmentAndLoactionContact = []
            let searchQuery = this.txtSearchChatGroups.toLowerCase();
            const filterList = (list, key) => list.filter(item => item[key].toLowerCase().includes(searchQuery));
            const groupedContacts = filterList(filteredData, 'TYPE')
            const sortedGroupedContacts = groupedContacts.sort((a, b) => a.TYPE.localeCompare(b.TYPE))

            // Assign the sorted contacts to the data property
            this.departmentAndLoactionContact = sortedGroupedContacts;
        },
        // cityContacts(name) {
        //     return this.filterdContacts.filter(item => item['CITY'] == name)
        // },
   
     
        allCheckBoxClick(event, item) {
    if (event.target.checked) {
      item.DATA.forEach((record) => {
        if (!this.smsContactSelect.includes(record.USER_PHONE)) {
          this.smsContactSelect.push(record.USER_PHONE);
        }
      });
    } else {
      item.DATA.forEach((record) => {
        const index = this.smsContactSelect.indexOf(record.USER_PHONE);
        if (index > -1) {
          this.smsContactSelect.splice(index, 1);
        }
      });
    }
    this.checkBoxAutoChecked();
  },

  checkBoxAutoChecked() {
    this.store.getUnifiedContacts.forEach((item) => {
      let status = false;
      item.DATA.forEach((record) => {
        
        if (!this.smsContactSelect.includes(record.MOBILE_PHONE)) {
           status = true;
        }
        console.log(item.TYPE,status)
      });

      const typeIndex = this.selectAllCheck.indexOf(item.TYPE);
      if (!status && typeIndex === -1) {
        this.selectAllCheck.push(item.TYPE);
      } else if (status && typeIndex > -1) {
        this.selectAllCheck.splice(typeIndex, 1);
      }
    });
  },
  openSMS(record){
    this.smsContactSelect = []
    let data = {
                LOGINUSER_ID: this.store.GetSenderDetail.id,
                COMPANY_ID: this.store.GetSenderDetail.companyId,
                PhonNo:record.otherphone,
                from:this.from,
                emailId:record.email_id
            }

            this.$socket.emit('GetsmsListforCurrentUsers', {data:data,userDetail:record})
            this.$emit("sendMessageInBulk",[])
            
  },
  addMessage(){
    this.smsContactSelect = []
    let data = {
                LOGINUSER_ID: this.store.GetSenderDetail.id,
                COMPANY_ID: this.store.GetSenderDetail.companyId,
                PhonNo:this.txtSearchChatGroups,
                from:this.from,
                emailId:''
            }
          let record ={
            otherphone:this.txtSearchChatGroups,
            first_name:'',
            AVATAR:'',
            emailId:''

          }
            this.$socket.emit('GetsmsListforCurrentUsers', {data:data,userDetail:record})
            this.$emit("sendMessageInBulk",[])
            this.txtSearchChatGroups = ''
  },
  sendMessageInBulk(){
    this.$emit("sendMessageInBulk",this.smsContactSelect)
    this.smsContactSelect = []
    this.smsListShow = true
  },
  backToChat(){
    this.smsContactSelect = []
    this.smsListShow = !this.smsListShow
  },
  searchNull(){
    this.txtSearchChatGroups = ''
  }


    },

    setup() {
        return {
            getFirstTwoLettersWithColor
        }
    },
    data() {
        return {

            activeTab: 'All',
            //grid view expend node
            txtSearchChatGroups: '',
            departmentAndLoactionContact: [],
            smsContactSelect: [],
            selectAllCheck: [],
            smsListShow:true,
            smsGetFromServer:[],
            from: this.store.getTwilioAccountDetails?.NUMBER
        }
    },
}
</script>
