<script>
// import {
//     ValidationProvider,
//     //extend,
//     ValidationObserver
// } from 'vee-validate';

import TwilioSetup from './TwilioSetup.vue';
import ChatSetupSetup from './ChatSetup.vue';
import NotificationSetup from './NotificationSetup.vue';
import Asterisk from './Asterisk.vue';
import Nexmo  from './Nexmo.vue';
import Tokbox from './Tokbox.vue';
import Vonage from './Vonage.vue';

export default {
    name: "Setting",
    components: {
        //ValidationProvider,
        //ValidationObserver,
        TwilioSetup,
        ChatSetupSetup,
        NotificationSetup,
        Asterisk,
        Nexmo,
        Tokbox,
        Vonage
    },
    props: {
        store: {
            type: Object
        },
        tabSetting: {
            type: String
        },
        selectedFilter: {
            type: String
        },
    },
    data() {
        return {
            deviceSetuppopupShow: false,
            deviceType: '',
            openChat: false,
            pageTitle: '',
            twilioSetup:false
        }
    },
    created() {

    },
    watch: {
        selectedFilter: function (newVal, oldVal) { // watch it
            console.warn(oldVal)
            this.deviceType = ''
            this.deviceSetuppopupShow = false
            this.pageTitle = newVal
        }
    },
    //   computed: {
    //     deviceSetupTitle: function () {
    //             console.log("props")
    //             
    //         return this.selectedFilter
    //     }
    // },
    methods: {
        removeClass() {
            let element = document.querySelector(".user-chat");
            element.classList.remove("user-chat-show");
        },
        /**
         * if open in mobile view then add class 
         */
         checkScreenAndAddCall() {
            var ww = document.body.clientWidth;
            if (ww < 992) {
                const responsiveDiv = document.querySelector(".user-chat")
                responsiveDiv.classList.add("user-chat-show")
            }

        },
        deviceSelect(e) {
            const vm = this;
            vm.deviceType = e
            vm.deviceSetuppopupShow = false
        },
        deviceSetupPageShow() {
            if (this.pageTitle == 'Chat') {
                this.openChat = true
                this.deviceSetuppopupShow = false
            } else {
                this.deviceSetuppopupShow = true
            }
        },
        addTwilio(e){
            this.twilioSetup =e
        },
        deviceOpen(e){
            this.$emit('settingTabInfo',e)
            this.deviceSetuppopupShow=false
        }
    },

}
</script>
