<template>
<div class="user-chat w-100 overflow-hidden">

        <!-- <div class="secondtimeuser d-flex justify-content-center align-items-center text-center" v-if="!callPage">
            <div class="secondtimeuser-content">
                <img class="blank-page-img-regular-chat" src="https://appfilemedia.talygen.com/Upload/UnifiedCommunication/338e83cf-0636-43df-ad99-a70dfff34025.png">
                <h3 class="my-3">No Recent calls</h3>
                <p> Get started by calling a contact. </p>
            </div>
        </div> -->
    
    <div class="d-lg-flex " >
        <!-- Start chat conversation section -->
        <div class="w-100 bg-calllog overflow-hidden position-relative p-3 " >
            
            <div class="pb-3 call-heading user-chat-topbar">
                <div class="row align-items-center">
                    <div class="col-sm-12">
                        <div class="d-flex align-items-center">
                            <div class="d-block d-lg-none me-2 ms-0" @click="removeClass()">
                                    <a href="javascript: void(0);" class="user-chat-remove text-muted font-size-16 p-2"><i class="ri-arrow-left-s-line"></i></a>
                            </div>
                            <h5 class="font-size-16 mb-0 text-truncate">{{ $t('AllCalls') }}</h5>
                        </div>
                    </div>
                </div>
            </div>

            <div class="card  Contacts-cardView-box" data-simplebar>
                <ul class="callloglist" >
                    <li v-for="(recentCall, index) in store.getRecentCall" :key="index">
                  
                        <div class="col1">
                            <div class="d-flex chat-box">
                                <div class="chat-user-img online align-self-center me-3 ms-0">
                                    <img class="rounded-circle avatar-xs" :src="recentCall.USER_IMAGE ? recentCall.USER_IMAGE :'https://talygenv.github.io/Vue-UI-Content/images/UC/uc_user_new.jpg'" alt="andrew">
                                </div>
                                <div class="flex-grow-1 overflow-hidden">
                                    <h5 class="text-truncate font-size-14 mb-1">{{ recentCall.CALLER_NAME }}</h5>
                                    <p class="chat-user-message text-truncate mb-0" > {{ recentCall.CALL_TYPE=='Outgoing' && recentCall.CallMedium !="WEBRTC"? recentCall.CALL_TO : '' }} </p>
                                </div>
                            </div>
                        </div>
                        <div class="col2">
                            <label>Duration</label>
                            <span class="sub-c-details">
                                <p class="text-olive" >
                                    {{recentCall.CALL_TYPE == 'Incomming' && (typeof recentCall.START_TIME === 'undefined' || recentCall.START_TIME == null) 
                                            ? 'Missed Call' : recentCall.CALL_TYPE == 'Outgoing' && (typeof recentCall.START_TIME === 'undefined' || recentCall.START_TIME == null) ? recentCall.CALL_TYPE+ ' - Not Picked' : secondsToHms(recentCall.DURATION)  }}</p>
                            </span>
                        </div>
                       
                        <div class="col3">
                            <label>Type</label>
                            <div class="typecall"><span :class="recentCall.CALL_TYPE == 'Incomming' ? 'icon icon-received': recentCall.CALL_TYPE == 'Outgoing' ? 'icon icon-call' : 'icon icon-miss' ">
                                    <i :class="recentCall.CALL_TYPE == 'Incomming' ? 'ri-arrow-left-down-line': recentCall.CALL_TYPE == 'Outgoing' ? 'ri-arrow-right-up-line' : 'ri-arrow-left-down-line'"></i></span>
                                    {{ recentCall.CALL_TYPE }} 
                                   
                                    <!-- {{recentCall.CALL_TYPE == 'Incomming' && (typeof recentCall.START_TIME === 'undefined' || recentCall.START_TIME == null) 
                                            ? 'Missed Call' : recentCall.CALL_TYPE == 'Outgoing' && (typeof recentCall.START_TIME === 'undefined' || recentCall.START_TIME == null) ? recentCall.CALL_TYPE+ ' - Not Picked' :recentCall.CALL_TYPE }} -->
                            </div>
                        </div>
                        <div class="col4">
                            <label>{{ $t('DateAndTime') }}</label>
                            
                            {{ getPreviousDay(recentCall.CREATED_AT)+' '+ getTime(recentCall.CREATED_AT) }}
                        </div>
                        <div class="col5">
                            <div class="callvideo rounded-circle handpointer" :class="store.getTalygenRunningCall ? 'disabled': ''" @click="redirectCall(recentCall)">
                                 <i :class="recentCall.CALL_TYPE=='video' ? 'fas fa-video': 'fas fa-phone-alt'"></i> 
                            </div>
                        </div>
                    </li>
                    <div class="recent-calls-listing-wrapper scrollbar-inner scroll-content" v-if="store.getRecentCall.length==0" id="div_forRecentCallList" style="height: auto; margin-bottom: 0px; margin-right: 0px; ">
                        <div class="text-center text-danger border p-2 bg-white m-1">{{ $t('No_Record_Found') }}</div>
                    </div>
                </ul>
            </div>
        </div>

        <!-- Start User profile detail sidebar -->

    </div>
</div>
</template>

<script>
import {
    secondsToHms,
    getPreviousDay
} from "@/assets/common/vue-common"
export default {
    props: {
        store: {
            type: Object
        }
    },
    methods: {
        removeClass() {
            let element = document.querySelector(".user-chat");
            element.classList.remove("user-chat-show");
        },
        getTime(date) {
            const newInputDate = date.replace(" ", "T");

            const timeStamp = new Date(newInputDate);
            return timeStamp.toLocaleTimeString(navigator.language, {
                hour: '2-digit',
                minute: '2-digit'
            })
        },
        checkScreenAndAddCall() {
            this.callPage= true
            var ww = document.body.clientWidth;
            if (ww < 992) {
                const responsiveDiv = document.querySelector(".user-chat")
                responsiveDiv.classList.add("user-chat-show")
            }

        },
        redirectCall(event) {
           // console.log(event)
            if(event.CallMedium=="WEBRTC"){
                this.videoCreate(event)
            }else{
            if (this.store.$state.callToken) {
                this.dailNumber = event.CALL_TYPE=='Outgoing' ? event.CALL_TO : event.CALL_FROMevent
                var params = {
                    To:  this.dailNumber,
                };
                this.store.makeOutgoingCall(params)
            } else {
                this.ShowAlert(this.$t("ConnectDevice"), "failure", false, this.$t("Alert"));
            }
        }

        },
        async videoCreate(data) {
        let obj = {
                USER_ID: data.CALL_TO,
                CONTACTNAME: data.CALLER_NAME,
                USER_IMAGE: data.USER_IMAGE,
                GROUP_NAME_ALIAS: data.CALL_TO+'_'+data.CALL_FROM,
                IS_GROUP: false,
                //room: data,
                calltype:data.CALL_TYPE=="VIDEO" ? 'video' : 'audio' 
            }
              this.$parent.videoCreate(obj)
          
            
        },
    },
    data() {
        return {
          dailNumber:'',
          callSatus:'',
          callPage:false
        };
    },
    sockets: {
        callingFrom: function (message) {
            console.log("callingFrom", message)

        },
        incomingCall: function (call) {
            console.warn(call)

        },
        audioPayload: function (message) {
            console.warn(message)

        },
        
       
    },
    setup() {
        return {
            secondsToHms,
            getPreviousDay
        };
    }
};
</script>
