<template>
    <div class="dropzonebase">
      <span>Max Files Allowed: {{ dropzoneOptions.maxFiles }}</span>
    <div class="file_cross" @click="this.$parent.fileDragClose"><i class="fa fa-close text-danger" style="cursor: pointer;"></i></div>
  <!-- <loader :is-visible="isLoading"></loader> -->
  <!-- <div class="row">
    <div class="col-12 mb-2 mt-2">
      <label>Allowed File Type:</label>
      <div class="mx-2 d-inline-block doc-ico-legend" v-for="(item,index) in fileTypeFormats" :key="index">
        <em id="helpText"
          :class="GetFileIcon(capitalizeFirstLetter(item))"></em>
         {{ capitalizeFirstLetter(item) }}
      </div>
      <div class="float-right">
        <label class="">Allowed File Size:</label>
         <div class="ml-1 d-inline-block doc-ico-legend font-weight-bold">
       {{ fileSize }} MB
      </div>
      </div>
    </div> 
    
  </div>-->
  <div class="col-12 p-0 float-left text-left position-relative" v-if="dropzoneOptions.url!=''">
    <DropZone ref="dropzone" id="dropzone" :options="dropzoneOptions"  :uploadOnDrop="false"
      @errorAdd="onError"  @vdropzone-file-added="onFileAdd"  @vdropzone-sending="onSending"  @vdropzone-complete-multiple="onMultipleQueueComplete"
       @vdropzone-complete="vdropzonecomplete" @vdropzone-success-multiple="onMultipleUpload">
       <template v-slot:message="">Click, or drag the file/folder here.</template>
      </DropZone>
    <!-- <button id="upload" @click="onUpload" class="btn btn-success mt-2 uploadfilesbtn" style="z-index:99"><em class="fa fa-upload pr-2"></em>Upload</button> -->
  </div>

</div>
</template> 

<script>
const docstorage= process.env.VUE_APP_DOCSTORAGE_API;
import DataService from "../services/DataService";
import DropZone from 'vue2-dropzone'
import 'vue2-dropzone/dist/vue2Dropzone.min.css'
export default {
  components:{
    DropZone
  },
  data() {
    return {
      uploadUrl:'',
      filePath: [],
      fileType: [],
      fileTypeFormats: [],
      token: null,
      uploadedFileCount: 0,
      isLoading: false,
      isDisabled:false,
      fileSize:null,
      checkFileSize:false,
      fileName:null,
      userConsumedStorage:null,
      userAllowedStorage:null,
      userAvaliableStorage:null,
      Options:[],
      dropzoneOptions:{
        maxFiles:3,
        url:'',
        uploadOnDrop:false,
        autoProcessQueue: false,
        addRemoveLinks:true,
        multipleUpload:true,
        parallelUpload:5,
        headers:null,
        acceptedFiles:null,
        maxFileSize:null,
        dictDefaultMessage: "<i class='fa fa-cloud-upload'></i>"+ this.$t('SelectToUpload')

      },
      FileTypeData:[],
      allowedfiletype:[],
      checkFileType:false,
      copyFileInfo: null,
      isShowCopyFileInfo:false,
      folderId:0,
      fileDetails:[]
    }
  },
  async created() {
    
    this.isDisabled=true;
    this.token = this.GetUserInfo.Token;
    this.uploadUrl=docstorage+ '/UploadStreamNew';
    this.dropzoneOptions.headers={'Authorization':'Bearer '+ this.token}
    this.dropzoneOptions.url= this.uploadUrl;
     await this.BindFileTypeDDL();
     await this.getfileTypes();
     await this.getfileSize();
     await this.GetUserStorage();
  },
  methods: {
    onMultipleQueueComplete(response)
    {
      debugger
      console.log('onMultipleQueueComplete',response)
    },
    onMultipleUpload(file, response)
    {
      debugger
      console.log('multipleResponse',response)
      if(file!=undefined)
    {
      let objs=[];
      objs.push(file.upload)
      this.uploadedFileCount += objs.length;
      if (this.$refs.dropzone.dropzone.files.length == this.uploadedFileCount) {
        this.ShowAlert(this.$t("FilesUploadedSuccessfully"), "success", true, this.$t("Alert"));
        this.$refs.dropzone.all = {};
        $(this.$refs.dropzone.$el).html('').append('<div class="dropzone__message dropzone__message--style dropzone-clickable">Drop here</div>');
        this.isDisabled=true;
        } 
        else
        {
        this.onUpload();
      }
    }
    },
    BindFileTypeDDL: async function () {
      const vm = this;
      vm.Options = [];
      var params=`moduleName=UnifiedCommunication`;
      await DataService.GetFileType(params).then((response) => {
        vm.FileTypeData=response.data;
       vm.FileTypeData.forEach((item, index) => {
        vm.Options.push({
           value: item.MimeTypes,
           label: item.FileType,
         });
       });
        //vm.getfileTypes();
      })
    },
    getfileTypes: async function () {  
      const vm = this;
      let params = `moduleName=UnifiedCommunication&keyValue=UnifiedCommunicationAllowedFileTypes,UnifiedCommunicationAllowedFileSize,VoiceNoteDurationLimit`;
      await DataService.GetConfigDataValue(params).then((response) => {
        vm.isLoading = true;  
        vm.fileType = JSON.parse(response.data.ConfigValue)[0].CONFIG_DATA_VALUE;
       vm.dropzoneOptions.acceptedFiles=vm.fileType;
        vm.fileKey = JSON.parse(response.data.ConfigValue)[0].CONFIG_DATA_KEY;
        vm.fileTypeFormats = vm.fileType.split(',');
        let selectedValues = vm.Options.filter(option => {
                                return vm.fileTypeFormats.some(format => {
                                    return option.label.toLowerCase().includes(format);
                                });
                            });
        // var selectedValues= vm.Options.filter((x)=>{return vm.fileTypeFormats.some((y)=>{ return x.value.indexOf(y)!=-1})}); 
        console.log('selectedValues',selectedValues)
       // vm.fileTypeFormats=selectedValues.map(x=>x.label);
        vm.allowedfiletype=selectedValues.map(x=>x.value);  
        vm.isLoading = false;
      })
    },
    capitalizeFirstLetter:function(str) {
      if (str.length === 0) return str; // Return empty string if input is empty

      // Convert the entire string to lowercase and capitalize the first letter
      return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
    },
    getfileSize: function () {
      const vm = this;
      var params = `moduleName=UnifiedCommunication&keyValue=UnifiedCommunicationAllowedFileSize`;
      DataService.GetConfigDataValue(params).then((response) => {
        vm.isLoading = true;
        vm.fileSize = JSON.parse(response.data.ConfigValue)[0].CONFIG_DATA_VALUE;
        vm.dropzoneOptions.maxFileSize=vm.fileSize*1000000;
        vm.isLoading = false;
      })
    },
    GetUserStorage: async function(){
      const vm=this;
      await DataService.GetUserStorage().then((response) => {
        vm.userAllowedStorage=response.data.ALLOWEDUSERSTORAGE[0].config_data_value;
        if(response.data.CONSUMEDUSERSTORAGEDETAIL.length>0){
          vm.userConsumedStorage= response.data.CONSUMEDUSERSTORAGEDETAIL[0].config_data_value;
        }
        else{
            vm.userConsumedStorage=0
        }
        vm.userAvaliableStorage=parseFloat(vm.userAllowedStorage)-parseFloat(Math.abs(vm.userConsumedStorage));
      })
    },
    async onFileAddFromCopy(item) {
      debugger
      const file = item.getAsFile();
      this.$refs.dropzone.addFile(file);
    },

    onFileAdd: async function (item) {
      debugger
      const vm=this;
      var obj = {}
      vm.checkFileSize=false;
      if(vm.userAvaliableStorage==null)
      {
        await vm.BindFileTypeDDL();
        await vm.getfileTypes();
        await vm.getfileSize();
        await vm.GetUserStorage();
      }
     if(parseFloat(item.upload.total/1048576)<=vm.userAvaliableStorage)
      {
        // $("#upload").removeClass("disabled");
        if(parseFloat(item.upload.total/1048576)>parseFloat(this.fileSize))
        {
          vm.fileName=item.upload.filename;
          vm.removeThisFile(item,'size');
        }
      }
      else{
          vm.ShowAlert(vm.$t("NoStorageAvaliable"), "warning");
          // Select the element with id "upload"
          var uploadElement = document.getElementById("upload");

          // Add the "disabled" class to the element
          uploadElement.classList.add("disabled");
      }
      vm.checkFileType=false;
      // if((vm.allowedfiletype.some(x=>x.includes(item.type)))==false){
      //   vm.fileName=item.upload.filename;
      //   vm.removeThisFile(item,'filetype');
      //    return false
      // }
      // if(item.type!='image/jpeg' && item.type!='image/png'){
      //   $($(this.$refs.dropzone.dropzone.previewsContainer).find(".dz-image")[this.$refs.dropzone.dropzone.files.length-1]).find("img").attr('src','https://img.icons8.com/?size=512&id=11651&format=png');
      // }
      // $(".dropzone__details dropzone__details--style").addClass("d-none");
      obj.fullPath = item.hasOwnProperty('fullPath') ? item.fullPath.split('/' + item.upload.filename)[0] : ''; 
      obj.name = item.upload.filename;
      obj.id = item.upload.uuid;
      item.upload.fullPath = obj.fullPath;
      item.upload.uuid = obj.id;
      this.isDisabled=false;
      return false;
    },
    vdropzonecomplete: function (response)
    {
      debugger
      this.fileDetails=JSON.parse(JSON.parse(response.xhr.response));
      if(this.fileDetails!=undefined)
    {

      this.$parent.SendAttachment(this.fileDetails)
    }
      console.log('responseresponse',response)
    },
    onSending: function (files, xhr, formData) {
      const vm = this;
      vm.filePath = [];
      var obj = {}
     let objs=[];
      objs.push(files.upload)
   
      objs.forEach(element => {
        obj = {}
        obj.id = element.uuid;
        obj.fullPath = element.fullPath==undefined?'':element.fullPath;
        vm.filePath.push(obj);
      }); 
      formData.append("folderId", 0);
      formData.append("isGlobal", 0);
      formData.append("moduleName", 'UnifiedCommunication');
      formData.append("subModuleName", '');
      formData.append('fileDetails', JSON.stringify(vm.filePath));
      this.onMultipleUpload();
    },
    // onUploaded: function (file, progress, bytesSent) {
    //   console.log('responsefile',file)
    //   console.log('responseprogress',progress)
    //   console.log('responsebytesSent',bytesSent)
    // if(file!=undefined)
    // {
    //   let objs=[];
    //   objs.push(file.upload)
    //   this.uploadedFileCount += objs.length;
    //   if (this.$refs.dropzone.dropzone.files.length == this.uploadedFileCount) {
    //     this.ShowAlert(this.$t("FilesUploadedSuccessfully"), "success", true, this.$t("Alert"));
    //     this.$refs.dropzone.all = {};
    //     $(this.$refs.dropzone.$el).html('').append('<div class="dropzone__message dropzone__message--style dropzone-clickable">Drop here</div>');
    //     this.isDisabled=true;
    //     } 
    //     else
    //     {
    //     this.onUpload();
    //   }
    // }
    // },
    onUpload( file, response) {
      debugger
      // if(this.checkFileSize==true){
      //   this.ShowAlert(this.fileName+ " Size limit exceed","warning");
      //   return false;
      // }
      // if(this.checkFileType==true){
      //   this.ShowAlert(this.fileName+ " has not allowed file Type","warning");
      //   return false;
      // }
    
      if(this.$refs.dropzone.dropzone.files.length>0){
       // $("#upload").removeClass("disabled");
        this.$refs.dropzone.processQueue();
       
      }
      else{
        this.ShowAlert(this.$t("PleaseSelectFile"), "warning")
      }
      
    },
    onError(error){
      ;
      if(error.error='MAX_FILE_SIZE')
      {
        this.ShowAlert(error.files[0].name+ "Size Limit Exceed.", "warning")
      }
    },
    removeThisFile: function(item,type){
        this.$refs.dropzone.removeFile(item);
        if(type=='filetype'){
          this.ShowAlert(item.upload.filename+ " has not allowed file Type","warning")
        }
        else{
          this.ShowAlert(item.upload.filename+ " size not more than allowed file size.","warning")
        }
    },
    GetFileIcon: function(extnsn){
      var cls=null;
      if(extnsn=='Audio'){
        cls="fa fa-file-audio-o text-danger"
      }
      else if(extnsn=='Video'){
         cls="fa fa-file-video-o text-info"
      }
      else if(extnsn=='Document'){
         cls="fa fa-file-word-o text-primary"
      }
      else if(extnsn=='PDF'){
         cls="fa fa-file-pdf-o"
      }
      else if(extnsn=='Image'){
         cls="fa fa-file-image-o"
      }
      else if(extnsn=="Spreadsheet"){
          cls="fa fa-file-excel-o text-sucess"
      }
      else if(extnsn=="Compressed"){
          cls="fa fa-file-archive-o"
      }
      else if(extnsn=="Email"){
          cls="fa fa-envelope-o text-danger"
      }
      else if(extnsn=="Font"){
          cls="fa fa-font"
      }
      else if(extnsn=="Presentation"){
          cls="fa fa-file-powerpoint-o text-primary"
      }
      else if(extnsn=="Programming"){
          cls="fa fa-file-code-o"
      }
      else if(extnsn=="Web"){
          cls="fa fa-globe text-primary"
      }
      else{
        cls="fa fa-file-o"
      }
      return cls;
    },
    fileExist: function (FileId) {
      const vm = this;
      var params = `fileIds=${FileId}&destFolderId=${vm.folderId}&opr=Copy&doccode=1`;
      DataService.StartCopyMoveOpr(params).then((response) => {
         console.log(response);
         vm.copyFileInfo=response.data.fileList;
         vm.isShowCopyFileInfo=true;
          //$("#upload").addClass("disabled");
      })
    },
    SaveCopyFile(fileList){
      const vm = this;
      var data = JSON.stringify(fileList);     
      DataService.CloneFilesInFolder(data).then(function (response) {
          console.log(response);
          vm.$parent.updatelistafterupload(vm.folderId);
          vm.copyFileInfo=null;
          setTimeout(() => {
           vm.copyFileInfo=response.data;
          }, 100);
      })
    }

  }
}
</script>


<style>
.dz-clickable { line-height: 80px !important; color: #999b9d!important; background: #f3f9ff; padding: 40px 0px; font-size: 15px; text-transform: capitalize;  border: 2px dashed #b1c2d2!important;}
.dropzone .dz-message{margin:25px 0px 0px 0px;}

.vue-dropzone>.dz-preview .dz-image img:not([src]) {
    width: 100px!important; height: 100px!important;
}

.dropzone .dz-preview .dz-image img { display: block; width: 100px; height: 100px; border: 4px solid #fff;}
.dz-clickable{padding: 4px 0px;}
.dropzone .dz-preview{border: 1px solid #b1c2d2; border-radius: 5px;}
.dropzone .dz-preview .dz-progress{ border: 1px solid #bfbcbc; height: 6px; left: 60%; top: 96%; width: 65px; z-index:99;}
.dz-details{display: none;}
.dropzone .dz-preview{min-height: 107px;}
.dropzone .dz-preview:not(.dz-processing) .dz-progress{animation: none;}
.vue-dropzone>.dz-preview .dz-image { padding: 5px;}
.vue-dropzone>.dz-preview .dz-progress .dz-upload{background: #28aeff;}

.vue-dropzone>.dz-preview .dz-error-mark, .vue-dropzone>.dz-preview .dz-success-mark {top: 10%; height:65px;}
.dropzone .dz-preview .dz-success-mark svg{width: 44px; height: 44px; color:#28aeff; background: #57b740;border-radius: 100%;} 
.dropzone .dz-preview .dz-error-mark svg{width: 44px; height: 44px; color:#28aeff; background: #ff8787;border-radius: 100%;}
.dropzone .dz-preview.dz-error .dz-error-message{display: none;}

.dropzone .dz-preview.dz-file-preview .dz-image{background: #fff;}

/* .dropzone .dz-preview .dz-remove{opacity: 12!important; color: #428ceb!important; height:40px!important; width: 100%!important; line-height: 18px!important; padding:2px 0px!important;
  z-index: 999!important; margin: 0px!important; top: 1px!important; font-size: 12px!important;cursor: pointer!important; background:#ccc!important;} */

.dropzone .dz-preview .dz-remove {
    opacity: 12!important;    color: #428ceb!important;    height: 30px!important;
    width: 100%!important;    line-height: 15px!important;    padding: 2px 0px!important;
    z-index: 10;    margin: 0px!important;   font-size: 11px!important;
    cursor: pointer!important;  background: #ccc!important; bottom: 0!important; font-weight: 600; border:none; text-transform: capitalize;letter-spacing: normal;
}
i.gg-close {
    background: #525f65;
}
.gg-close:hover {
  color: black;
}
.dropzone__details {
  visibility: hidden;
}
</style>

