<template>
<div id="contact_call_details" class="draggable-block user-profile-desc " :class="{'minimizeWindows':minimize}" v-draggable ref="contactCallDetails">
    <div class="video-headerinfo d-flex align-items-center justify-content-between">
        <div class="video-headerinfoleft">
            <h5 class="mb-0 font-size-14">{{ store.getContactDetails ? store.getContactDetails.Name : store.getIncomingCallData ? store.getIncomingCallData.parameters.From : localNumber ? localNumber :this.store.getDialNumber }}</h5>
        </div>
        <div class="videoadjust">
            <a  @click="minimize = ! minimize;removeInlineStyles();" class="handpointer"><i class="fas fa-minus"></i></a>
            <a  @click="fullScreen = !fullScreen" class="handpointer"><i class="far fa-square"></i></a>
            <a @click="store.hangup()" class="handpointer"><i class="fas fa-times"></i></a>
        </div>
    </div>
    <button class="button_call_dialer_contactDetail" @click="detail()">{{ contactDetail ? $t('ShowCall') :$t('ShowContactDetail')  }}</button>
    <div id="contact_Detail_VoiceCall" class="externalLinks mt-2" v-if="contactDetail" >
        <nav>
            <div class="nav nav-tabs" id="nav-tab" role="tablist">
                <button class="nav-link " :class="activeContactTab=='crm' ? 'active' : ''" id="nav-media-tab" data-bs-toggle="tab" data-bs-target="#nav-media" type="button" role="tab" aria-controls="nav-media" aria-selected="true" @click="contactActiveTab('crm')">CRM</button>
                <button class="nav-link" :class="activeContactTab=='Ticket' ? 'active' : ''" id="nav-doc-tab" data-bs-toggle="tab" data-bs-target="#nav-doc" type="button" role="tab" aria-controls="nav-doc" aria-selected="false" @click="contactActiveTab('Ticket')">Ticketing</button>
                <button class="nav-link" :class="activeContactTab=='project' ? 'active' : ''" id="nav-links-tab" data-bs-toggle="tab" data-bs-target="#nav-links" type="button" role="tab" aria-controls="nav-links" aria-selected="false" @click="contactActiveTab('project')">Project Management</button>
            </div>
        </nav>
        <div class="tab-content mt-2" id="nav-tabContent">

            <div class="uc_tabcontent" :class="'current' " id="pills-tabContent" v-if="activeContactTab=='Ticket' || activeContactTab=='project'">
                <div class="tab-content current" id="pills-ticketing" role="tabpanel" aria-labelledby="pills-ticketing-tab">
                    <div id="container" class="chatpanesbase chatpane_100 pt-0">
                        <div id="chat-window" class="chatpanesbasemid border">
                            <div id="message-list" class="" style="overflow-x:hidden;height:51vh" data-simplebar="">
                                <div class="col-12 float-left p-0">
                                    <div class="table-responsive">
                                        <table class="table table-bordered " id="table_for_Call_Ticketing">
                                            <thead class="thead-light">
                                                <tr>
                                                    <th v-for="header in CRMcolumn[0][activeContactTab]" :key="header.name">{{ header.name }}</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                <tr v-for="ticket,index in store.getCallTabsInformation" :key="index">
                                                    <td v-for="header in CRMcolumn[0][activeContactTab]" :key="header.name">
                                                        <div v-if="header.name=='Action'">
                                                            <a @click="viewRecords(ticket[header.dataBaseName])">View </a>
                                                        </div>
                                                        <div v-else-if="header.dataBaseName=='PLANNED_START_DATE' || header.dataBaseName=='PLANNED_END_DATE' || header.dataBaseName=='CREATED_AT'">
                                                            {{ ticket[header.dataBaseName] ?  getDateInFormat(ticket[header.dataBaseName]) :'' }}
                                                        </div>
                                                        <div v-else> {{ ticket[header.dataBaseName] }}</div>
                                                    </td>
                                                </tr>
                                                <tr v-if="store.getCallTabsInformation.length == 0">
                                                    <td colspan="10" class="text-center text-danger no-record">{{ $t('NoRecordfound')}}</td>
                                                </tr>
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

            </div>
            <div v-if="activeContactTab=='crm'" :class="activeContactTab=='crm' ?'current' : '' " class="tab-content current" id="pills-crm" role="tabpanel" aria-labelledby="pills-crm">
                <div class="crm-detail">
                    <div class="menu_left">
                        <ul id="pills-tab" role="tablist">
                            <li :class="crmTabSelect=='Leads' ? 'current':''">
                                <a class="handpointer" id="pills-leads-tab" data-toggle="pill" role="tab" aria-controls="pills-leads" aria-selected="true" @click="getOrderDetails('Leads')"><i class="fa fa-users"></i><span> {{ $t('Leads') }}</span></a>
                            </li>
                            <li :class="crmTabSelect=='CRM_DEALS' ? 'current':''">
                                <a class="handpointer" id="pills-deals-tab" data-toggle="pill" role="tab" aria-controls="pills-deals" aria-selected="false" @click="getOrderDetails('CRM_DEALS')"><i class="fa fa-file-text"></i><span> {{ $t('CRM_DEALS') }}</span></a>
                            </li>
                            <li :class="crmTabSelect=='Quote' ? 'current':''">
                                <a class="handpointer" id="pills-quotes-tab" data-toggle="pill" role="tab" aria-controls="pills-quotes" aria-selected="false" @click="getOrderDetails('Quote')"><i class="fa fa-list"></i><span>{{ $t('Quote') }} </span></a>
                            </li>
                            <li :class="crmTabSelect=='PurchaseOrderWithoutRef' ? 'current':''">
                                <a class="handpointer" id="pills-purchaseOrder-tab" data-toggle="pill" role="tab" aria-controls="pills-purchaseOrder" aria-selected="false" @click="getOrderDetails('PurchaseOrderWithoutRef')"><i class="fa fa-bar-chart"></i><span>{{ $t('PurchaseOrderWithoutRef') }} </span></a>
                            </li>
                            <li :class="crmTabSelect=='CRM_SALES_ORDERS' ? 'current':''">
                                <a class="handpointer" id="pills-Sales-Order-tab" data-toggle="pill" role="tab" aria-controls="pills-salesOrders" aria-selected="true" @click="getOrderDetails('CRM_SALES_ORDERS')"><i class="fa fa-line-chart"></i><span>{{ $t('CRM_SALES_ORDERS') }}</span></a>
                            </li>
                            <li :class="crmTabSelect=='Invoices' ? 'current':''">
                                <a class="handpointer" id="pills-Invoice-tab" data-toggle="pill" role="tab" aria-controls="pills-invoice" aria-selected="true" @click="getOrderDetails('Invoices')"><i class="fa fa-file"></i><span>{{ $t('Invoices') }} </span></a>
                            </li>
                        </ul>
                    </div>
                    <div class="detail_right uc_tabcontent" id="pills-tabContent">
                        <div class="internal-tab-content current" id="pills-leads" role="tabpanel" aria-labelledby="pills-leads-tab">
                            <div class="detail_heading">
                                <h3>{{ $t(crmTabSelect) }}</h3>
                                <!-- <span class="add"><a href="javascript:;" id="btn_addLead" onclick="loadFormForAddLeadOrContact('CRM_LEADS')" style="color: #fff;"><i class="fa fa-plus"></i> Add a Lead</a></span> -->
                            </div>
                            <div id="container" class="chatpanesbase chatpane_100 pt-0">
                                <div class="recent-contacts mt-0">
                                    <div class="col-12 float-left p-0">
                                        <div class="table-responsive">
                                            <table class="table table-bordered " id="table_for_Call_LeadDetails">
                                                <thead class="thead-light">
                                                    <tr>

                                                        <th v-for="header in CRMcolumn[0][crmTabSelect]" :key="header.name">{{ header.name }}</th>

                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    <tr v-for="record,index in store.getCrmDetailRecord" :key="index">
                                                        <td v-for="header in CRMcolumn[0][crmTabSelect]" :key="header.name">
                                                            <div v-if="header.name=='Action'">
                                                                <a @click="viewRecords(record[header.dataBaseName])">View </a>
                                                            </div>
                                                            <div v-if="header.name!='Action'">
                                                                {{ record[header.dataBaseName] }}
                                                            </div>
                                                        </td>
                                                    </tr>
                                                    <tr v-if="store.getCrmDetailRecord.length == 0">
                                                        <td colspan="10" class="text-center text-danger no-record">{{ $t('NoRecordfound')}}</td>
                                                    </tr>
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <!-- <div class="links mt-3"><a>View More</a></div> -->
    </div>
    <div class="phone d-flex align-items-center" v-else>
        <div class="callerid">
            <div class="info">
                <p>{{ callStatus=='ringing' ? 'RINGING...' :''}}</p>
                <p>{{ secondsToHms(store.$state.timerStart) }}</p>
                <h1 v-if="store.getContactDetails"> {{ store.getContactDetails.Name }}</h1>
                <p>{{ store.getIncomingCallData ? store.getIncomingCallData.parameters.From : localNumber ? localNumber :this.store.getDialNumber  }}</p>
            </div>

            <div class="call-icons">
                <ul class="text-center p-0">
                    <li><a @click="toggleMute"><i class="fas" :class="muteUnmuteIcon"></i><span>{{ muteUnmuteLabel }}</span></a></li>
                    <li><a><i class="fas fa-th"></i><span>Keypad</span></a></li>
                    <li><a><i class="fas fa-volume-up"></i><span>Speaker</span></a></li>
                    <!-- <li><a><i class="fas fa-plus"></i><span>Add Call</span></a></li> -->
                    <!-- <li><a><i class="fas fa-video"></i><span>Video</span></a></li> -->
                    <li class="dropdown oncall-moreoption">
                        <a role="button" id="dropdownMenuLink" data-bs-toggle="dropdown" aria-expanded="false">
                            <i class="fas fa-ellipsis-h" @click="isExpandedCalling =!isExpandedCalling"></i>

                            <div class="dropdown-menu py-0" :class="{'d-block':isExpandedCalling}">
                                <span><a class="dropdown-item ps-2" @click="toggleHold">{{ holdLabel }}</a></span>
                                <span><a class="dropdown-item ps-2" @click="transferCall">Transfer</a></span>
                                <!-- <span><a class="dropdown-item ps-2" >Record</a></span> -->
                            </div>
                        </a>
                    </li>
                </ul>
            </div>

            <div class="cut">
                <div class="decline handpointer" @click="store.hangup()">
                    <i class="fas fa-phone-alt"></i>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '@/services/DataService';
import CRMcolumn from "../CrmColmun"
import {
    getPreviousDay,
    getDateInFormat,
    documentIcon,
    secondsToHms
} from "@/assets/common/vue-common"
export default {
    name: "VoiceCall",
    props: {
        number: {
            type: String
        },
        store: {
            type: Object
        },

    },
    components: {

    },
    data() {
        return {
            activeContactTab: 'crm',
            crmTabSelect: 'Leads',
            callStatus: '',
            isMuted: false,
            isOnHold: false,
            callStatus: '',
            isExpandedCalling: false,
            contactDetail: false,
            minimize: false,
            fullScreen: true,
            localNumber:this.number
        }
    },
    sockets: {
        call_status: function (message) {
            let vm = this;
            this.callStatus = message.call.CallStatus
        }
    },
    created: async function () {
        this.localNumber = this.store.getIncomingCallData ? this.store.getIncomingCallData.parameters.From  : this.store.getDialNumber ? this.store.getDialNumber : this.number
        this.store.contactInformation(`phone=${encodeURIComponent(this.localNumber)}`)
    },
    computed: {
        muteUnmuteIcon() {
            return this.isMuted ? 'fa-microphone-slash' : 'fa-microphone';
        },
        muteUnmuteLabel() {
            return this.isMuted ? 'Unmute' : 'Mute';
        },
        holdLabel() {
            return this.isOnHold ? 'Unhold' : 'Hold';
        },
    },
    mounted() {

    },
    methods: {
        removeInlineStyles() {
      // Access the element using ref and remove the style attribute
      const element = this.$refs.contactCallDetails;
      if (element) {
        element.removeAttribute('style');
      }
    },
        detail() {
            this.contactDetail = !this.contactDetail
        },
        //contact Details Tabs 
        contactActiveTab(event) {
            this.activeContactTab = event
        },
        getOrderDetails(event) {
            this.crmTabSelect = event
            if (this.store.getContactDetails) {
                this.store.crmDetailRecord({
                    params: `contactId=${this.store.getContactDetails.contact_id}`,
                    tab: event
                })
            }
        },
        // Mute the call
        toggleMute() {
            let callRunningData = this.store.getIncomingCallData ? this.store.getIncomingCallData : this.store.getOutGoingcallData
            if (callRunningData) {
                this.isMuted = !this.isMuted;
                callRunningData.mute(this.isMuted);
            }
        },
        toggleHold() {
            let callRunningData = this.store.getIncomingCallData ? this.store.getIncomingCallData : this.store.getOutGoingcallData
            if (callRunningData) {
                this.isOnHold = !this.isOnHold;
                const event = this.isOnHold ? 'hold-call' : 'resume-call';
                this.$socket.emit(event, callRunningData.parameters.CallSid);
            }
        },
        transferCall() {
            let callRunningData = this.store.getIncomingCallData ? this.store.getIncomingCallData : this.store.getOutGoingcallData
            if (callRunningData) {
                this.$socket.emit('transfer', {
                    number: this.localNumber
                });
                this.$socket.on('transferred', (response) => {
                    console.log('Call transferred:', response);
                    // Handle the response (e.g., update UI or notify the user)
                });
                this.$socket.on('transfer_error', (error) => {
                    console.error('Transfer failed:', error);
                    // Handle the error (e.g., show an error message)
                });
            }
        },

    },

    setup() {

        return {
            secondsToHms,
            CRMcolumn,

        }
    }
}
</script>
