            <h4 class="mb-4 d-flex justify-content-between align-items-center">{{ $t('Contacts') }} <span><span class="gridview handpointer" @click="leftContactView('gridview');changeTabs('Favorite')" v-if="contactView=='listview'"><i class="fas fa-th-large"></i></span> <span v-if="contactView=='gridview'" @click="leftContactView('listview')" class="listview handpointer"><i class="fas fa-list"></i></span></span></h4>
        </div>
        <div class="grid-view" v-if="contactView=='listview'">
            <div class="px-3 ">
                <div class="search-box chat-search-box">
