                        <span class="input-group-text text-muted bg-light pe-3 ps-3 border-0" id="basic-addon1">
                            <i v-if="txtSearchChatGroups" class="ri-close-line search-icon font-size-18 handpointer" @click="txtSearchChatGroups='';searchContact()"></i>
                            <i v-else class="ri-search-line search-icon font-size-18 handpointer"></i>
                        </span>
                    </div>
                </div> <!-- Search Box-->
            </div>
