            <!-- Start user status -->
            <div class="px-3 pb-4" dir="ltr">

                <ul class="nav nav-tabs customtabs" id="myTab" role="tablist">
                    <li class="nav-item " role="presentation" @click="changeTabs('company')">
                        <button class="nav-link" :class="{'active':activeTab=='company'}" type="button">{{ $t('AllContact') }}</button>
                    </li>
                    <li class="nav-item" role="presentation" @click="changeTabs('Department');departmentORLocationFilter()">
                        <button class="nav-link " :class="{'active':activeTab=='Department'}" type="button">{{ $t('IconsTypeFor') }}</button>
                    </li>
                    <li class="nav-item" role="presentation" @click="changeTabs('location');departmentORLocationFilter()">
                        <button class="nav-link" :class="{'active':activeTab=='location'}" type="button">{{ $t('LocationId') }}</button>
                    </li>
                    <li class="nav-item" role="presentation" @click="changeTabs('Favorite')">
                        <button class="nav-link" :class="{'active':activeTab=='Favorite'}" type="button">{{ $t('Favourite') }}</button>
                    </li>

                </ul>
                <!-- end user status carousel -->
            </div>
            <!-- end user status -->

            <!-- Start chat-message-list -->

            <div class="tab-content" id="myTabContent">

                <div class="tab-pane fade show " :class="{'active':activeTab=='company' || activeTab=='Favorite'}">
                    <div class="simplebar-content" v-if="filterdContacts.length==0  "><span class="no_record_found">{{ $t('NoDataTodisplay') }}</span></div>
                    <div class="chat-message-list px-2" data-simplebar>
                        <ul class="list-unstyled chat-list chat-user-list">
                            <li v-for="contact,index in filterdContacts" :key="index">
                                <a>
                                    <div class="d-flex" :class="{'align-items-center':contact.DEPARTMENT_NAME==null}">
                                        <div class="chat-user-img online align-self-center me-3 ms-0" v-if="contact.USER_IMAGE">
                                            <img :src="contact.USER_IMAGE ? contact.USER_IMAGE : 'https://talygenv.github.io/Vue-UI-Content/images/UC/uc_user_new.jpg'" class="rounded-circle avatar-xs" alt="">

                                        </div>
                                        <div class="avatar-xs me-2" v-else>
                                            <span class="avatar-title rounded-circle bg-red-subtle " :style="{ backgroundColor: getFirstTwoLettersWithColor(contact.CONTACTNAME).color }">
                                                {{ getFirstTwoLettersWithColor(contact.CONTACTNAME).letters}}
                                            </span>
                                        </div>
                                        <div class="flex-grow-1 overflow-hidden">
                                            <h5 class="text-truncate font-size-14 mb-1 handpointer" @click="contactDetail(contact)">{{ contact.CONTACTNAME }}</h5>
                                            <p class="chat-user-message text-truncate mb-0">{{ contact.DEPARTMENT_NAME  }}</p>
                                        </div>

                                    </div>
                                </a>
                            </li>
                        </ul>
                    </div>

                </div>
                <div class="tab-pane fade active show" v-if="activeTab=='Department'">
                    <div v-if="departmentAndLoactionContact.length==0  "><span class="no_record_found">{{ $t('NoDataTodisplay') }}</span></div>
                    <div class="chat-message-list px-3" data-simplebar>
                        <div class="heading_department_group">
                            <template v-for="item of departmentAndLoactionContact">
                                {{ item.TYPE }}<span>{{ item.TOTALRECORD}}
                                
                            </span>
                                <div class="clear"></div>
                                <ul class="list-unstyled chat-list chat-user-list">
                                    <li v-for="contact,index in item.DATA">
                                        <a>
                                            <div class="d-flex">
                                                <div class="chat-user-img align-self-center me-2 ms-0">
                                                    <div class="chat-user-img online align-self-center me-3 ms-0" v-if="contact.USER_IMAGE">
                                                        <img :src="contact.USER_IMAGE" class="rounded-circle avatar-xs" alt="">

                                                    </div>
                                                    <div class="avatar-xs me-2" v-else>
                                                        <span class="avatar-title rounded-circle bg-red-subtle " :style="{ backgroundColor: getFirstTwoLettersWithColor(contact.CONTACTNAME).color }">
                                                            {{ getFirstTwoLettersWithColor(contact.CONTACTNAME).letters}}
                                                        </span>
                                                    </div>
                                                </div>
                                                <div class="flex-grow-1 overflow-hidden">
                                                    <h5 class="text-truncate font-size-14 mb-1 handpointer" @click="contactDetail(contact)">{{ contact.CONTACTNAME }}</h5>
                                                    <p class="chat-user-message text-truncate mb-0">{{ contact.TYPE ? contact.TYPE : '-' }}</p>
                                                </div>
                                            </div>
                                        </a>
                                    </li>

                                </ul>
                            </template>
                        </div>

                    </div>
                </div>
                <div class="tab-pane fade active show"  v-if="activeTab=='location'">
                    <div class="chat-message-list px-3" data-simplebar>

                        <div class="heading_department_group">
                            <template v-for="item,index of departmentAndLoactionContact">
                                {{ index == 'null' ? '--': index}}<span>{{ departmentAndLoactionContact[index].length }}</span>
                                <div class="clear"></div>
                                <ul class="list-unstyled chat-list chat-user-list">

                                    <li v-for="contact,index in item">
                                        <a>
                                            <div class="d-flex">
                                                <div class="chat-user-img align-self-center me-2 ms-0">
                                                    <div class="chat-user-img online align-self-center me-3 ms-0" v-if="contact.USER_IMAGE">
                                                        <img :src="contact.USER_IMAGE" class="rounded-circle avatar-xs" alt="">

                                                    </div>
                                                    <div class="avatar-xs me-2" v-else>
                                                        <span class="avatar-title rounded-circle bg-red-subtle " :style="{ backgroundColor: getFirstTwoLettersWithColor(contact.CONTACTNAME).color }">
                                                            {{ getFirstTwoLettersWithColor(contact.CONTACTNAME).letters}}
                                                        </span>
                                                    </div>
                                                </div>
                                                <div class="flex-grow-1 overflow-hidden">
                                                    <h5 class="text-truncate font-size-14 mb-1 handpointer" @click="contactDetail(contact)">{{ contact.CONTACTNAME }}</h5>
                                                    <p class="chat-user-message text-truncate mb-0">{{ contact.CITY ? contact.CITY : '-' }}</p>
                                                </div>

                                            </div>
                                        </a>
                                    </li>

                                </ul>
                            </template>
                        </div>

                    </div>
                </div>

               
               

            </div>

            <!-- End chat-message-list -->
        </div>

        <div class="list-view" v-else>
            <div class="px-3 pt-0">
                <div class="accordion">
                    <div style="height: 100%;" class="accordion-item card  mb-2" v-for="itemType,index in store.getLeftSideFilter" :key="index">
                        <AccordionItem id="allcall" :title="itemType.type" :expanded="false" >

<div class="accordion-body p-2">

    <ul class="nav nav-tabs accordiontabs cont_location" id="myTab" role="tablist" data-simplebar>
        <listItem v-for="item in itemType.data" :key="item.department_id" :text="item.department_name" @click="deparmentAndLocation(itemType.type, itemType.type == 'Department' ? item.department_id :item.user_city)" :className="{'active':activeDepOrLoc==item.department_id || activeDepOrLoc==item.user_city}">
            <template v-slot:count>
                <span class="font-size-14 text-right">{{ item.count }}</span>
                    </template>
        </listItem>
    </ul>

</div>

</AccordionItem>
                        
                    </div>
                    <AccordionItem id="allcall" :title="$t('Favourite')" :expanded="false" >

                        <div class="simplebar-content" v-if="filterdContacts.length==0  "><span class="no_record_found">{{ $t('NoDataTodisplay') }}</span></div>
                    <div class="chat-message-list px-2" data-simplebar>
                        <ul class="list-unstyled chat-list chat-user-list">
                            <li v-for="contact,index in filterdContacts" :key="index">
                                <a>
                                    <div class="d-flex" :class="{'align-items-center':contact.DEPARTMENT_NAME==null}">
                                        <div class="chat-user-img online align-self-center me-3 ms-0" v-if="contact.USER_IMAGE">
                                            <img :src="contact.USER_IMAGE ? contact.USER_IMAGE : 'https://talygenv.github.io/Vue-UI-Content/images/UC/uc_user_new.jpg'" class="rounded-circle avatar-xs" alt="">

                                        </div>
                                        <div class="avatar-xs me-2" v-else>
                                            <span class="avatar-title rounded-circle bg-red-subtle " :style="{ backgroundColor: getFirstTwoLettersWithColor(contact.CONTACTNAME).color }">
                                                {{ getFirstTwoLettersWithColor(contact.CONTACTNAME).letters}}
                                            </span>
                                        </div>
                                        <div class="flex-grow-1 overflow-hidden">
                                            <h5 class="text-truncate font-size-14 mb-1 handpointer" @click="contactDetail(contact)">{{ contact.CONTACTNAME }}</h5>
                                            <p class="chat-user-message text-truncate mb-0">{{ contact.DEPARTMENT_NAME  }}</p>
                                        </div>

                                    </div>
                                </a>
                            </li>
                        </ul>
                    </div>

</AccordionItem>
                    <!-- end personal info card -->

                    <!-- end security card -->

                </div>
            </div>
        </div>

    </div>
    <!-- Start chats content -->
</div>
</template>

<script>
import {
    getFirstTwoLettersWithColor
} from "@/assets/common/vue-common"
import AccordionItem from '@/components/Call//AccordionItem.vue';
import listItem from '@/components/Common/ListItem.vue';
export default {
    inject: ['responsiveCssFunction'],
    name: "LeftContactTab",
    components: {
        AccordionItem,
        listItem
    },
    props: {
        store: {
            type: Object
        },
    },
    created() {
        this.fetchContacts();
        this.store.leftSideFilter();
        const query = `city=&departmentId=&groupBy=All`;
        this.store.unifiedContactList(query);

    },
    methods: {
        async changeTabs(event) {
            this.activeTab = event;
            await this.fetchContacts();

        },
        
        async leftContactView(event) {
            this.activeDepOrLoc = ''
            this.contactView = event;
            if (event === 'listview') {
                await this.fetchContacts();
            } else {
                this.$parent.changeActiveTab()
            }
            this.$parent.contactChatChange({
                view: event,
                userInformation: '',
                contactDetailShow: false
            });
        },
        contactDetail(event) {
            if (event.USER_PHONE) {
                this.store.contactInformation(`phone=${encodeURIComponent(event.USER_PHONE)}`)
            }
            this.$parent.contactChatChange({
                view: this.contactView,
                userInformation: event,
                contactDetailShow: true
            });
            this.responsiveCssFunction()
        },
        async deparmentAndLocation(type, id) {
            this.activeDepOrLoc = id
            const query = type === 'Department' ?
                `search=&pageSize=&pageNum=&sortBy=&sortExp=&type=&city=&departmentId=${id}` :
                `search=&pageSize=&pageNum=&sortBy=&sortExp=&type=&city=${id}&departmentId=`;
            await this.store.getContact(query);
            this.$parent.contactChatChange({
                view: this.contactView,
                userInformation: '',
                contactDetailShow: false
            });
            this.$parent.changeActiveTab()
            this.responsiveCssFunction()
        },
        async fetchContacts() {
            this.txtSearchChatGroups = ''
            const query = `search=&pageSize=&pageNum=&sortBy=&sortExp=&type=${this.activeTab}&city=&departmentId=`;
            await this.store.getContact(query);
            this.searchContact()
        },
        searchContact() {
            let searchQuery = this.txtSearchChatGroups.toLowerCase();
            const filterList = (list, key) => list.filter(item => item[key].toLowerCase().includes(searchQuery));
            if(this.activeTab=='Favorite'){
                let FAVOURITE_ID = this.store.getContactList.filter(item =>item.FAVOURITE_ID !=null )
                console.log("checkk",FAVOURITE_ID)
                this.filterdContacts = filterList(FAVOURITE_ID, 'CONTACTNAME');  
            }else{
                this.filterdContacts = filterList(this.store.getContactList, 'CONTACTNAME');  
            }
            if (this.activeTab == 'Department' || this.activeTab == 'location') {
                this.departmentORLocationFilter()
            }
        },
        departmentContacts(name) {
            return this.filterdContacts.filter(item => item['DEPARTMENT_NAME'] == name)
        },
        departmentORLocationFilter() {
            this.departmentAndLoactionContact = []
            let sortedGroupedContacts = []
            if (this.activeTab == 'Department') {
                sortedGroupedContacts = this.groupContact()
            }else{
             const groupedContacts = this.filterdContacts.reduce((acc, contact) => {
                    const {
                        CITY
                    } = contact;
                    if (!acc[CITY]) {
                        acc[CITY] = [];
                    }
                    acc[CITY].push(contact);
                return acc;
            }, {});
            sortedGroupedContacts = Object.keys(groupedContacts)
                .sort()
                .reduce((sortedAcc, key) => {
                    sortedAcc[key] = groupedContacts[key];
                    return sortedAcc;
                }, {});
        }
        console.log("checkk",sortedGroupedContacts)
            
            this.departmentAndLoactionContact = sortedGroupedContacts;

        },
        cityContacts(name) {
            return this.filterdContacts.filter(item => item['CITY'] == name)
        },
        groupContact() {
            this.departmentAndLoactionContact = []
            let searchQuery = this.txtSearchChatGroups.toLowerCase();
            const filterList = (list, key) => list.filter(item => item[key].toLowerCase().includes(searchQuery));
            const groupedContacts =  filterList(this.store.getUnifiedContacts, 'TYPE')
             return groupedContacts.sort((a, b) => a.TYPE.localeCompare(b.TYPE))

        },

    },

    setup() {
        return {
            getFirstTwoLettersWithColor
        }
    },
    data() {
        return {
            //grid and list view
            contactView: 'listview',
            //list view active tab
            activeTab: 'company',
            //grid view expend node
            //activeDepLoc: '',
            txtSearchChatGroups: '',
            filterdContacts: [],
            departmentAndLoactionContact: [],
            activeDepOrLoc:''
        }
    },
}
</script>
