</template>

<script>
import DataService from '../services/DataService';
import CRMcolumn from "./CrmColmun"
import {
    getDateOnly,
    getDateInFormat,
    getPreviousDay,
    getFirstTwoLettersWithColor
} from "../assets/common/vue-common"
export default {
    components: {

    },
    name: "Contacts",
    props: {
        store: {
            type: Object
        },

        sideBarFilter: {
            type: Object
        },
        contactPageDetails: {
            type: Object,
            required: true
        },

    },
    data() {
        return {
            messageList: [],
            smsPopupShow: false,
            fromNumber: this.store.getTwilioAccountDetails?.NUMBER,
            toNumber: "",
            message: '',
            sendMessageVia: 0,
            txtSearchChatGroups: '',
            addNewContact: false,
            filterContactList: [],
            activeContactTab: 'Chat',
            crmTabSelect: 'Leads',
            is_first_time: 1,
            lastrow: 0,
            noRecord: false,
            RecNumber: 50,
            activityData: [],
            Filterdate: [],

        }
    },
    created: async function () {
        this.updateFilteredContacts();
    },

    mounted() {

        //console.log("checkk",this.store.getContactList)

    },
    beforeDestroy() {},
    computed: {},
    sockets: {
        connect() {
            console.log('Connected to server');
        },
        disconnect() {
            console.log('Disconnected from server');
        },
        messageGet: function (details) {
            //this.toNumber = "+16506660036"
            // this.toNumber = "+16506660036"
            //console.log("details", details)
            if (this.toNumber == details.From) {
                details.body = details.Body
                details.from = details.From
                details.to = details.To
                details.status = details.SmsStatus
                details.dateCreated = new Date()
                details.blinking = true
                details.dateCreated = details.dateCreated.toString()
                this.messageList.push(details)
            }
            ///console.log("details", details)
        },
        messageStatus: function (details) {
            //this.toNumber = "+16506660036"
            if (this.toNumber == details.To) {
                var foundIndex = this.messageList.findIndex(item => item.sid == details.SmsSid)
                this.messageList[foundIndex] ? this.messageList[foundIndex].status = details.SmsStatus : ''
            }
        },

    },
    watch: {
        contactPageDetails: function () { // watch it
            this.txtSearchChatGroups = ''
        }
    },
    methods: {
        /**
         * if open in mobile view then add class 
         */
        checkScreenAndAddCall() {
            var ww = document.body.clientWidth;
            if (ww < 992) {
                setTimeout(()=>{
                    const responsiveDiv = document.querySelector(".user-chat")
                    responsiveDiv.classList.add("user-chat-show")
                },100)
                
            }

        },
        removeClass() {
            let element = document.querySelector(".user-chat");
            element.classList.remove("user-chat-show");
        },
        callTouser: async function (number) {
            const vm = this;
            if (number) {
                if (vm.store.$state.callToken) {
                var params = {
                    To: number,
                };
                vm.store.makeOutgoingCall(params)
                //this.store.insertNotifications({type:'call'})
                   // vm.$parent.callFromOtherTab(number)
                } else {
                    vm.ShowAlert(vm.$t("ConnectDevice"), "failure", true, vm.$t("Alert"));
                }

            } else {
                vm.ShowAlert(vm.$t('MobileNotAvailable'), "failure", vm.$t('Alert'));
            }
        },
        smsToContact(itm) {
            // this.userInformation = itm
            // if (itm.USER_PHONE) {
            //     this.toNumber = itm.USER_PHONE
            //     this.smsPopupShow = true
            // } else {
            //     this.ShowAlert(this.$t('MobileNotAvailable'), "failure", this.$t('Alert'));
            // }
        },
        // contactDetail(itm) {
        //     const vm = this;
        //     if (itm.USER_PHONE) {
        //         vm.userInformation = itm
        //         vm.toNumber = itm.USER_PHONE
        //         vm.contactDetailShow = true
        //         vm.$socket.emit('smsList', {
        //             from: vm.fromNumber, //this.fromNumber
        //             to: vm.toNumber
        //         }, function (record) {
        //             vm.messageList = record
        //         })
        //     } else {
        //         this.ShowAlert(this.$t('MobileNotAvailable'), "failure", this.$t('Alert'));
        //     }
        // },

        messageSend(event) {
            const vm = this;
            if (vm.message != '') {
                if (vm.sendMessageVia == 'twilio' || event == 'twilio') {
                    vm.$socket.emit('twilioSendMessage', {
                        from: '+12513095602', //this.fromNumber
                        to: '+16506660036', //this.toNumber
                        body: vm.message,
                    }, function (record) {
                        vm.message = ''
                        console.log("createApiKey", record)
                        vm.messageList.push(record)

                    })
                }
            } else {
                this.ShowAlert(this.$t('PleaseEnterMessage'), "failure", this.$t('Alert'));
            }
        },
        //     validateEmailAddress: function(event) {
        //         console.log("testt",event.key)
        //         if (event.shiftKey!==true && event.key === "Enter") {
        //     messageSend('twilio')
        //   }    

        //},
        clear() {
            this.message = ''
        },

        videoCreate(contect) {
            let obj = {
                USER_ID: contect.USER_ID,
                CONTACTNAME: contect.CONTACTNAME,
                USER_IMAGE: contect.USER_IMAGE,
                IS_GROUP:0


            }
            this.$parent.videoCreate(obj)
        },
        NewChat(item) {
            console.log("item", item)
            this.$parent.ticketReceiver(item)
            //this.$emit('')
        },
        detail(event) {
            
            this.contactPageDetails.contactDetailShow = true
            this.contactPageDetails.userInformation = event
            this.BindActivity()
            if (event.USER_PHONE) {
                this.store.contactInformation(`phone=${encodeURIComponent(event.USER_PHONE)}`)
            }
        },
        favourite(item) {
            item.FAVOURITE_ID = !item.FAVOURITE_ID ? 'yes' : null
            var param=`ReceiverId=${item.USER_ID}&emaiId=${item.EMAIL_ID}`
            DataService.ContactFavouriteUpdate(param).then(response=>{
            })
        },
        searchContact(data) {
            let searchQuery = this.txtSearchChatGroups.toLowerCase();
            const filterList = (list, keys) => {
                return list.filter(item => {
                    return keys.some(key => item[key] && item[key].toLowerCase().includes(searchQuery));
                });
            };
            return filterList(data, ['CONTACTNAME', 'EMAIL_ID', 'USER_PHONE']);
        },
        updateFilteredContacts() {

            this.filterContactList = this.searchContact(this.store.getContactList);
        },
        //contact Details Tabs 
        contactActiveTab(event) {
            this.activeContactTab = event
        },
        //CRM child tab Details
        getOrderDetails(event) {
            this.crmTabSelect = event
            if (this.store.getContactDetails) {
                this.store.crmDetailRecord({
                    params: `contactId=${this.store.getContactDetails.contact_id}`,
                    tab: event
                })
            }
        },
        BindActivity() {

            const vm = this;
            vm.noRecord = false;
            vm.Filterdate = []
            let type = vm.activeContactTab == 'Chat' ? 'CHAT' : 'CALLS'
            let url = `to_user_number=${vm.contactPageDetails.userInformation.USER_PHONE ? vm.contactPageDetails.userInformation.USER_PHONE : ''}&current_user_number=${vm.store.getTwilioAccountDetails?.NUMBER ? vm.store.getTwilioAccountDetails?.NUMBER : ''}&to_user_Id=${vm.contactPageDetails.userInformation.USER_ID ? vm.contactPageDetails.userInformation.USER_ID : null}&emaiId=${vm.contactPageDetails.userInformation.EMAIL_ID ? vm.contactPageDetails.userInformation.EMAIL_ID : null}&is_first_time=${vm.is_first_time}&lastrow=${vm.lastrow}&recordNumber=${vm.RecNumber}&FromDate=&ToDate=&type=${type}`;
            DataService.GetAllActivity(url).then(response => {
                
                console.log("typeof response.data",typeof response.data)
                // if (typeof response.data == 'string' ? null : response.data != null) {
                    if (JSON.parse(response.data).length > 0) {
                        vm.activityData = JSON.parse(response.data)
                        let group = {};

                        // vm.activityData.forEach(item => {
                        // let data = item.CALL_TIME.substring(0, 10);
                        // if (group[data]) {
                        //     group[data].push(item);
                        // } 
                        // else {
                        //     group[data] = [];
                        //     group[data].push(item);
                        // }
                        // vm.Filterdate = group;
                        ///});
                        vm.noRecord = false;
                    }
                // } 
                else {
                    vm.activityData = []
                    vm.noRecord = true;
                }
            });
        },
        getTime(date) {
            const newInputDate = date.replace(" ", "T");
            const timeStamp = new Date(newInputDate);
            return timeStamp.toLocaleTimeString(navigator.language, {
                hour: '2-digit',
                minute: '2-digit'
            })
        },
    },
    destroyed() {

        this.contactPageDetails = {
            view: '',
            userInformation: '',
            contactDetailShow: false
        }
        this.txtSearchChatGroups = ''
        this.$emit('contactDestroyed', this.contactPageDetails)

    },
    setup() {
        return {
            getDateOnly,
            getDateInFormat,
            getPreviousDay,
            getFirstTwoLettersWithColor,
            CRMcolumn,

        }
    }
}
</script>
