<template>
    <li>
        <a>
            <div class="d-flex align-items-center">
                <ImageORColor @click="$emit('JoinRoom', itemObj)" class="handpointer"
                    imageUperDivClass="chat-user-img align-self-center me-3 ms-0" :title="userName"
                    imageClass="rounded-circle avatar-xs" spanUperDivClass="avatar-xs"
                    spanClass="avatar-title rounded-circle bg-red-subtle" :name="userName" :image="image"
                    :class="{ 'online': checkIsOnline(itemObj.RECEIVER_ID) == 1 && itemObj.IS_GROUP != true, 'offline': checkIsOnline(itemObj.RECEIVER_ID) == 0 && itemObj.IS_GROUP != true }">
                    <slot name="online"></slot>
                </ImageORColor>

                <div class="flex-grow-1 overflow-hidden" @click="$emit('JoinRoom', itemObj)">
                    <h5 class="text-truncate font-size-14 mb-1">
                        <span class="float-left handpointer" :title="userName">{{ userName }}</span>
                        <span v-if="itemObj.IS_PINNED" class="user-status" :class="{ 'pinned': itemObj.IS_PINNED }">
                            <i class="fas fa-thumbtack"></i>

                        </span>

                        <span v-if="itemObj.IS_MUTE" class="user-status muted"><i class="far fa-bell-slash"></i></span>
                    </h5>
                    <p class="chat-user-message text-truncate mb-0" :class="{ 'animate-typing': isShowTypingForLeft == true && isTypingToGroup == itemObj.GROUP_ID }">
                        <span v-html="isShowTypingForLeft == true && isTypingToGroup == itemObj.GROUP_ID ? 'typing' : (itemObj.IS_ATTACHMENTS==null ?
                            (itemObj.MESSAGE !=null && itemObj.MESSAGE.includes('src') ? '[GIF]' : stripHtmlTags(itemObj.MESSAGE)) : 'attachment')"></span>
                        <!-- {{ isShowTypingForLeft == true && isTypingToGroup == itemObj.GROUP_ID ? 'typing' : (itemObj.IS_ATTACHMENTS==null ?
                            (itemObj.MESSAGE !=null && itemObj.MESSAGE.includes('src') ? '[GIF]' : itemObj.MESSAGE) : 'attachment') }} -->
                        <span v-if="isShowTypingForLeft && isTypingToGroup == itemObj.GROUP_ID" class="dot"></span>
                        <span v-if="isShowTypingForLeft && isTypingToGroup == itemObj.GROUP_ID" class="dot"></span>
                        <span v-if="isShowTypingForLeft && isTypingToGroup == itemObj.GROUP_ID" class="dot"></span>
                    </p>
                </div>

                <!-- <p class="ut d-none"><img :src="leftIsTyping"></p> -->

                <div class="font-size-11 position_relative"
                    v-if="itemObj.hasOwnProperty('CREATED_AT') && itemObj.MESSAGE != null">
                    {{ formattedDate }}
                    <span class=" d-block text-center mt-2" v-if="itemObj.UNREAD_USER_MESSAGE == 0"
                        :class="{ 'read': itemObj.IS_READ == 1, 'unread': itemObj.IS_READ == 0 }">
                        <i class="ri-check-double-line font-size-15"></i>

                    </span>
                    <div class="unread-message">
                        <span class="badge badge-soft-info rounded-pill" v-if="itemObj.UNREAD_USER_MESSAGE > 0">{{
                            itemObj.UNREAD_USER_MESSAGE }}</span>
                    </div>
                </div>
                <span class="nav-item dropdown dropsideopt " :class="{ 'down-arrowhover': itemObj.MESSAGE == null }">
                    <div class="nav-link dropdown-toggle" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                        <i class="fas fa-angle-down"></i>
                    </div>
                    <div class="dropdown-menu">
                        <button class="button" @click="$emit('ArchiveUserGroup', itemObj)">{{ itemObj.IS_ARCHIVE == 0 ||
                            itemObj.IS_ARCHIVE == null ? 'Archive Chat' : 'Un-Archive Chat'
                            }}</button>
                        <button class="button" @click="$emit('MuteUnmuteUserGroup', itemObj)">{{ itemObj.IS_MUTE == 0 ||
                            itemObj.IS_MUTE == null ? 'Mute' : 'UnMute' }}</button>
                        <!--<button class="button" v-on:click="UserGroupDelete(itemObj, 'Delete')">Delete chat</button> -->
                        <button class="button" @click="$emit('PinUserGroup', itemObj)">{{ itemObj.IS_PINNED == true ?
                            'UnPin Chat' : 'Pin Chat'
                            }}</button>
                    </div>
                </span>

            </div>
        </a>
    </li>
</template>
<script>
export default {
    props: {
        itemObj: {
            type: Object,
            required: true
        },
        userName: {
            type: String,
            required: true
        },
        image: {
            type: String
        },
        isTypingToGroup: {
            type: [String, Array],
        },
        isShowTypingForLeft: {
            type: Boolean,
            required: true
        }

    },
    data() {
        return {
            onlineUsers: [],
            formattedDate: ''
        }
    },
    sockets: {
        connectedSockets: function (activeUsers) {
            this.onlineUsers = []
            this.onlineUsers = activeUsers

        },
    },
    watch: {
    'itemObj.CREATED_AT': 'updateFormattedDate'
  },
  created() {
    this.updateFormattedDate();
    this.startDateUpdateInterval();
  },
  beforeDestroy() {
    if (this.dateUpdateInterval) {
      clearInterval(this.dateUpdateInterval);
    }
  },
    methods: {
        stripHtmlTags(text) {
            
            if (!text) return '';
            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = text;
            return tempDiv.textContent || tempDiv.innerText || '';
        },
        checkIsOnline: function (itm) {
            var users = this.onlineUsers.findIndex(x => x.ID == itm.toString());
            if (users != undefined && users != -1) {
                return 1
            } else {
                return 0
            }
        },
        DateDifference(ActualDate) {
    const vm = this;
    const GetCurrentDate = new Date();
    const GetValueInSeconds = Math.ceil((GetCurrentDate.getTime() - new Date(ActualDate).getTime()) / 1000);
    
    // Time unit constants in seconds
    const secondsInMinute = 60;
    const secondsInHour = 3600;
    const secondsInDay = 86400;
    const secondsInMonth = 2592000; // Approx. 30 days
    const secondsInYear = 31536000; // Approx. 365 days
    
    if (GetValueInSeconds < secondsInMinute) {
        return vm.$t('now');
    } 
    if (GetValueInSeconds < 2 * secondsInMinute) {
        return vm.$t('minute');
    } 
    if (GetValueInSeconds < secondsInHour) {
        return Math.floor(GetValueInSeconds / secondsInMinute) + ' ' + vm.$t('minutes');
    } 
    if (GetValueInSeconds < 2 * secondsInHour) {
        return vm.$t('an') + ' ' + vm.$t('hour');
    } 
    if (GetValueInSeconds < secondsInDay) {
        return Math.floor(GetValueInSeconds / secondsInHour) + ' ' + vm.$t('hours');
    } 
    if (GetValueInSeconds < 2 * secondsInDay) {
        return vm.$t('Yesterday');
    } 
    if (GetValueInSeconds < secondsInMonth) {
        return Math.floor(GetValueInSeconds / secondsInDay) + ' ' + vm.$t('days');
    } 
    if (GetValueInSeconds < secondsInYear) {
        const months = Math.floor(GetValueInSeconds / secondsInMonth);
        return months <= 1 ? '1 ' + vm.$t('month') : months + ' ' + vm.$t('months');
    } 

    const years = Math.floor(GetValueInSeconds / secondsInYear);
    return years <= 1 ? '1 ' + vm.$t('year') : years + ' ' + vm.$t('years');
},
        updateFormattedDate() {
      this.formattedDate = this.DateDifference(this.itemObj.CREATED_AT);
    },
    startDateUpdateInterval() {
      this.dateUpdateInterval = setInterval(() => {
        this.updateFormattedDate();
      }, 60000); // Update every minute
    }
    },
}

</script>