<template>
  <div class="progress-bar-container" @mousedown="startDrag">
    <div class="progress-bar" :style="{ width: progressPercentage + '%' }"></div>
    <div class="progress-pointer" :style="{ left: progressPercentage + '%' }"></div>
  </div>
</template>

<script>
export default {
  model: {
    prop: 'value',
    event: 'input'
  },
  props: {
    value: {
      type: Number,
      required: true
    },
    min: {
      type: Number,
      default: 0
    },
    max: {
      type: Number,
      default: 100
    }
  },
  computed: {
    progressPercentage() {
      const range = this.max - this.min;
      return ((this.internalProgress - this.min) / range) * 100;
    }
  },
  data() {
    return {
      internalProgress: this.value,
      dragging: false
    };
  },
  watch: {
    value(newVal) {
      this.internalProgress = newVal;
    }
  },
  methods: {
    startDrag(event) {
      this.dragging = true;
      this.updateProgress(event);
      document.addEventListener('mousemove', this.updateProgress);
      document.addEventListener('mouseup', this.stopDrag);
    },
    updateProgress(event) {
      if (this.dragging) {
        const rect = this.$el.getBoundingClientRect();
        const offsetX = event.clientX - rect.left;
        let newProgress = (offsetX / rect.width) * (this.max - this.min) + this.min;
        newProgress = Math.round(Math.max(this.min, Math.min(this.max, newProgress)))
        this.internalProgress = newProgress;
        this.$emit('input', newProgress);
      }
    },
    stopDrag() {
      this.dragging = false;
      document.removeEventListener('mousemove', this.updateProgress);
      document.removeEventListener('mouseup', this.stopDrag);
    }
  },
  beforeDestroy() {
    document.removeEventListener('mousemove', this.updateProgress);
    document.removeEventListener('mouseup', this.stopDrag);
  }
};
</script>

<style scoped>
.progress-bar-container {
  width: 100%;
  height: 30px;
  background-color: #e0e0e0;
  border-radius: 5px;
  overflow: hidden;
  position: relative;
  cursor: pointer;
}

.progress-bar {
  height: 100%;
  background-color: #76c7c0;
  transition: width 0.1s;
}

.progress-pointer {
  width: 10px;
  height: 30px;
  background-color: #333;
  position: absolute;
  top: 0;
  transform: translateX(-50%);
  cursor: pointer;
}
</style>
