<template>
<!-- videocall  bar-->
<!--  -->
<section :class="videoCallShow || audioCallPopupShow ? 'user-videocall-sidebar' : ''">
    
    <div class=""   v-show="(videoCallShow || audioCallPopupShow) && (!networkSlowMessage && ![0].includes(participantsList.length) || isMobile())">
        <div 
        ref="myIframe"
      id="jitsi-container" 
      style="width: 100%;  margin-top: 10px; height: 100%;">
      
</div>

    <li class="addnewparticipants" v-if="(isgroupcall || incomingVideoCallinfo && incomingVideoCallinfo.isGroup) ">
        <a @click="addNewMember()" :class="{'disabled':totalUniqueMembers==store.getUserByGroupId.length}"><i class="fas fa-user-plus"></i> {{ $t('AddNewParticipant') }}</a>
    </li>
    </div>

    <div class="uerprof ringing" v-if="participantsList.length==0 && !networkSlowMessage && callToUserInfo  && isMobile()==false">
                <div class="imgbase">
                           
         <div class="ring" >
            <div class="coccoc-alo-phone coccoc-alo-green coccoc-alo-show">
                <div class="coccoc-alo-ph-circle"></div>
                <div class="coccoc-alo-ph-circle-fill"></div>
                <div class="coccoc-alo-ph-img-circle"><img :src="callToUserInfo.USER_IMAGE ? callToUserInfo.USER_IMAGE : 'https://talygenv.github.io/Vue-UI-Content/images/UC/uc_user_new.jpg'" alt="user" /></div></div>
                <span class="font-size-28 my-3 fw-semibold">{{ incomingVideoCallinfo ? incomingVideoCallinfo.groupName ? incomingVideoCallinfo.groupName : incomingVideoCallinfo.fromName : callToUserInfo.CONTACTNAME }}</span>
                <span>{{ $t('Ringing') }}..</span>
         
            </div>
         </div>
                <button type="button" class="btn btn-danger end-call-btn callend avatar-sm rounded-circle" data-bs-dismiss="modal" @click="disconnectVideo(); stopRingTune()">
                                    <span class="avatar-title bg-transparent font-size-28">
                                        <i :class="'ri-phone-fill'"></i>
                                    </span>
                                </button>
            </div>
    <div  v-if="networkSlowMessage && (videoCallShow || audioCallPopupShow) && isMobile()==false" class="d-flex align-items-center justify-content-center w-100 h-100">
        <span class="loader"></span>
    </div>
    <!-- add participant Modal -->
    
    <!-- Ringing  Modal -->

    <div class="modal-dialog " v-if="inComingCallingPopup || incomingaudiocallpopup">
        <div class="modal-content">
            <div class="modal-body">
                <div class="d-flex p-0 align-items-center">{{ callToUserInfo }}
                    <div class="avatar-md me-2 ">
                        <img :src="incomingVideoCallinfo.fromUserPath ? incomingVideoCallinfo.fromUserPath : 'https://talygenv.github.io/Vue-UI-Content/images/UC/uc_user_new.jpg'" alt="" class="img-thumbnail rounded-circle">
                    </div>
                    <div class="avatar-info me-auto">
                        <h5 class="text-truncate mb-1" :title="incomingVideoCallinfo ? incomingVideoCallinfo.groupName ?
                                incomingVideoCallinfo.groupName : incomingVideoCallinfo.fromName :
                                GroupCallVideoInfo.groupName">{{ truncateWord(incomingVideoCallinfo ? incomingVideoCallinfo.groupName ?
                                incomingVideoCallinfo.groupName : incomingVideoCallinfo.fromName :
                                GroupCallVideoInfo.groupName,15) }}</h5>
                        <p class=" mb-0"><i :class="incomingVideoCallinfo.calltype == 'audio' ? 'ri-phone-fill' : 'fas fa-video'"></i>
                            {{ $t('incomingCallTypeCall', [incomingVideoCallinfo.calltype == 'audio' ? $t('Audio') :
                                    $t('Video')]) }}</p>
                    </div>
                    <div class="mt-0">
                        <ul class="list-inline mb-1">
                            <li class="list-inline-item ms-0">
                                <button type="button" class="btn btn-danger callend avatar-sm rounded-circle" data-bs-dismiss="modal" @click="disconnectVideo('reject'); stopRingTune()">
                                    <span class="avatar-title bg-transparent font-size-20">
                                        <i :class="'ri-phone-fill'"></i>
                                    </span>
                                </button>
                            </li>
                            <li class="list-inline-item">
                                <button type="button" class="btn btn-success avatar-sm rounded-circle" @click="VideoCallPickupMethod(); stopRingTune()">
                                    <span class="avatar-title bg-transparent font-size-20">
                                        <i :class="'ri-phone-fill'"></i>
                                    </span>
                                </button>
                            </li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    </div>
  
    
    <div class="modal d-block modalpart" id="selectparticipatn"  v-if="groupSelectMemberPopupShow" style="display: block;">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-head p-3 ">
                    <h4 class="font-size-16 mb-0">{{ $t('SelectParticipants') }}ghjgh</h4>
                    <button type="button" class="close" data-bs-dismiss="modal"  @click="groupSelectMemberPopupShow = false; selectedGroupMembers = []">
                        <span aria-hidden="true">&times;</span>
                    </button>
                </div>
                <div class="modal-body">
                    <div class="contactlist">
                        <div class="d-flex checkmessage align-items-center mb-4" v-for="users, index in filteredArray" :key="index">
                            <div class="chat-user-img online align-self-center me-3 ms-0">
                                <img :src="users.avatar ? users.avatar : defaultImg" class="rounded-circle avatar-xs" alt="">
                            </div>

                            <div class="flex-grow-1 overflow-hidden">
                                <h5 class="text-truncate font-size-14 mb-1">{{ users.useR_NAME }}</h5>
                                <p class="chat-user-message text-truncate mb-0">{{ users.designatioN_NAME }}</p>
                            </div>
                            <!-- <div class="font-size-11 disable">  
                                <input id="check3" type="checkbox" name="check1" v-model="selectedGroupMember" :value="users.useR_ID" >  
                                <label for="check3"></label>      
                            </div> -->
                            <div class="checkbox-main">
                                <section>
                                    <label class="checkbox">
                                        <input id="check3" type="checkbox" name="check1" class="form-check-input" v-model="selectedGroupMembers" :value="users.useR_ID" @change="handleCheckboxChange" :disabled="(totalUniqueMembers) >= 10 && !selectedGroupMembers.includes(users.useR_ID)">
                                    </label>
                                </section>
                            </div>
                        </div>

                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-default" @click="groupSelectMemberPopupShow = false; selectedGroupMembers = []">Cancel</button>
                    <button class="btn btn-primary" @click="videoCallFromGroup" >{{ $t('AddParticipants') }}</button>
                </div>
            </div>
        </div>
    </div>
</section>
<!-- videocall bar end-->
</template> 
<script>
import {
    dateFromat,
    secondsToHms,
    getFirstTwoLettersWithColor
} from "@/assets/common/vue-common"
export default {
    name: "VideoCall",
    props: {
        store: {
        type: Object,
        required: true,  // Ensures the store prop is always passed
        default() {
            return {};  // Return an empty object as a fallback
        }
    }
    },
    setup() {
        return {
            secondsToHms,
            getFirstTwoLettersWithColor,
            api: null,         
         meetingStarted: false,
        }
    },
    sockets: {
        /*********video call sockets**********/
        /**
         * video call popup open from sender
         *get new video room from socket
         * @param {*} data
         */
        newRoomVideo: function (data) {

            this.videoPopUpCall(data, 0, '');
        },
       
        getvideoCallReceiver(data) {
            
            const {
                room,
                roomId,
                toUserId,
                calltype
            } = data;

            if (Number(toUserId) === this.store.getUserInformation.ID) {
                if (this.store.$state.talygenCallRunning) {
                    this.$socket.emit('missed video call', data);
                    this.disconnectVideo();
                    
                } else {
                    console.log("data",data)
                    this.groupidSearch = room
                    this.incomingVideoCallinfo = JSON.parse(JSON.stringify(data));
                    this.displayIncomingCallPopup(calltype);
                    

                    // Auto-miss call if unanswered after 30 seconds
                    this.timerOut = setTimeout(() => {
                        this.$socket.emit('missed video call', data);
                        this.disconnectVideo();
                    }, 30000);

                    this.playRingTune();
                }
            }
        },

        /**
         * join video from sender
         * @param {} data
         */
        ChannelJoinVideo: function (data) {
           
            this.videoroomID = data.room
            this.$socket.emit('joinVideo', {
                "channel": data.room,
                "userdata": data.id
            })
            
            this.initializeJitsiMeet(data.room,this.sender.name)
           
       
            
        },
      
        addUserStream(config) {
            const idList = config.IdList.split('_').map(Number);
            if (idList.includes(this.sender.id)) {
                
                const exists = this.videoAudioCallStreaming.some(record => record.socketId === config.socketId);
                if (!exists) {
                    this.alreadySelectedMembers.push(config.userId)
                    //this.addNewMember()
                    this.videoAudioCallStreaming.push(config);
                }
            }
        },
        removeUserStream(data) {
            let idList = [];
            if (Array.isArray(this.videoAudioCallStreaming) && this.videoAudioCallStreaming.length > 0) {
               idList = this.videoAudioCallStreaming[0].IdList.split('_').map(Number);
            }
            
                this.alreadySelectedMembers = this.alreadySelectedMembers.filter(item => item !== data.userId)
                this.videoAudioCallStreaming = this.videoAudioCallStreaming.filter(item => item.socketId !== data.socketId);
                if (idList.includes(this.sender.id)) {
                     if(this.videoAudioCallStreaming.length == 0){
                          this.removeVideoCallParams()
                    }
                }
                //this.addNewMember()
            },
        /**
         * Receive call another user
         * Receiver open video call popup and start the call
         * @param {} data
         */
        getNewVideo(data) {     
            const {
                receiver,
                contactname,
                calltype,
                IdList,
                isGroup
            } = data;
            if (this.sender.id === receiver) {
                
                clearInterval(this.started);
                this.started = setInterval(this.clockRunning, 1000);
                this.stopRingTune();
            }

            if (this.sender.id === data.id) {
                
                clearInterval(this.started);
                this.videoCallCounting = 0;
                this.started = setInterval(this.clockRunning, 1000);

                const [token, alias, room] = data.room.split('~');
                const params = {
                    ...JSON.parse(JSON.stringify(this.sender)),
                    room,
                    alias,
                    token,
                    receiver,
                    calltype,
                    isGroup,
                    isSender: 0,
                    Receiver_name: this.replaceAll(contactname, "%20", " ") || '',
                    IdList
                };
                
                this.callParams = params;
                this.callType = calltype
                this.VideoCallPopUP(params);
                
                this.initializeJitsiMeet(token,this.sender.name)
                
            }
        },

       
        CallDiscounted(data) {
            if (data?.users.includes(this.sender.id)) {
                this.handleGroupCallEnd(data);
            }
        },
       
         rejectNewVideo(param) {
            if ([param.id, param.receiver].includes(this.sender.id)) {
                this.handleRejectNewVideo(param);
            }
        },
        missedVideoCall() {
            // if (this.remoteStreams.length === 0) {
            
            // }
        },

    },
    watch: {
    '$route.query': {
      handler: async function (newVal) {
        if (!newVal || Object.keys(newVal).length === 0) return;

        if (['twilio'].includes(newVal.type)) {
          const params = {
            To: newVal.number,
          };
setTimeout(async()=>{
    await this.store.intitializeDevice();
    this.store.makeOutgoingCall(params);
},3000);
          
        } 
        else if (['outAudio', 'outVideo'].includes(newVal.type)) {
          await this.store.getContact(`search=&pageSize=&pageNum=&sortBy=&sortExp=&type=company&city=&departmentId=`);
          let user = this.store.getContactList.find(x => x.USER_ID == newVal.userId);
          let obj = {
            USER_ID: user.USER_ID,
            CONTACTNAME: user.CONTACTNAME,
            USER_IMAGE: user.USER_IMAGE,
            IS_GROUP: 0,
            calltype: newVal.type === 'outAudio' ? 'audio' : 'video'
          };
          this.videoCreate(obj);

          this.cleanQuery(['type', 'userId']);
        } 
        else if (['chat'].includes(newVal.type)) {
          await this.store.getContact(`search=&pageSize=&pageNum=&sortBy=&sortExp=&type=company&city=&departmentId=`);
          let user = this.store.getContactList.find(x => x.USER_ID == newVal.userId);
          this.$parent.ticketReceiver(user);
          
          this.cleanQuery(['type', 'userId']);
        } 
        else if (['group'].includes(newVal.type)) {
          await this.store.getContact(`search=&pageSize=&pageNum=&sortBy=&sortExp=&type=company&city=&departmentId=`);
          let user = this.store.recentChatuser.find(x => x.GROUP_ID == newVal.groupId);
          
          this.$parent.joinOnUpdateProfile(user.GROUP_ID);
          
          this.cleanQuery(['type', 'groupId']);
        } 
        else if (['InCallVideo', 'InCallAudio'].includes(newVal.type)) {
          // Retrieve video call parameters from localStorage
          const jsonString = localStorage.getItem('videoCallParams');
          const videoCallParams = jsonString ? JSON.parse(jsonString) : null;

          if (videoCallParams) {
            this.incomingVideoCallinfo = videoCallParams;
            this.videoCallFromUrl(videoCallParams);
          }

          this.cleanQuery(['videoCall']);
        }
      },
      immediate: true
    }
  },
  mounted() {
    console.log("Mounted, checking route query:", this.$route.query);
    // Run the function on page refresh/load
    if (Object.keys(this.$route.query).length > 0) {
      this.$watch('$route.query', this['$route.query'].handler, { immediate: true });
    }
  },
    computed: {
  totalUniqueMembers() {
    const selectedIds = this.selectedGroupMembers.map(member =>member);
    const alreadySelectedIds = this.alreadySelectedMembers.map(member => member);
    
    // Combine both arrays and create a Set to filter out duplicate IDs
    const uniqueIds = new Set([...selectedIds, ...alreadySelectedIds]);
    
    // Return the total count of unique IDs
    return uniqueIds.size;
  }
},
    methods: {
        cleanQuery(keysToRemove) {
      const query = { ...this.$route.query };
      keysToRemove.forEach(key => delete query[key]);

      this.$router.replace({ query });
    },

        handleGroupCallEnd(data) {
                if (this.isgroupcall) {
                    this.alreadySelectedMembers = this.alreadySelectedMembers.filter(item => item !== data.userId);
                    this.callParams.aliasSel = this.callParams.aliasSel.split('_')
                        .filter(item => item !== data.userId).join('_');
                }
                this.remoteStreams = this.remoteStreams.filter(item => item.id !== data.remoteId);
                if (!this.remoteStreams.length) {
                    this.disconnectVideo();
                    this.removeVideoCallParams();
                }
            },
        displayIncomingCallPopup(calltype) {
            this.store.$state.talygenCallRunning = true;
            this[calltype === 'audio' ? 'incomingaudiocallpopup' : 'inComingCallingPopup'] = true;

            if (!this.isMobile() && this.store.getMessageAndNotification.enable_notification) {
                this.notifyMe(this.incomingVideoCallinfo, '');
            }
        },
        
      
        handleCheckboxChange(event) {
              
            if ((this.totalUniqueMembers) == 10) {
               
                this.ShowAlert(this.$t("SelectUserForVideoCall"), "warning", true, this.$t("Alert"));
                return false;
            }
        },
        handleBeforeUnload(event) {
            // Ensure the call is disconnected before the page is refreshed or closed
            if (this.videoCallShow || this.audioCallPopupShow || this.inComingCallingPopup || this.incomingaudiocallpopup) {
                this.disconnectVideo();
                // Optionally show a confirmation dialog (modern browsers may ignore custom messages)
                event.preventDefault();
                event.returnValue = ''; // Required for older browsers to trigger the dialog
            }
        },
        isMobile() {
    const userAgentCheck = /Android|webOS|iPhone|iPad|iPod|BlackBerry|Windows Phone|Opera Mini|IEMobile/i.test(navigator.userAgent);
    const touchSupport = 'ontouchstart' in window || navigator.maxTouchPoints > 0 || navigator.msMaxTouchPoints > 0;
    console.log("userAgentCheck",userAgentCheck,touchSupport)
    return userAgentCheck || touchSupport;
},

        playRingTune() {
            // Clear any existing timer
            clearTimeout(this.ringTuneTimer);

            try {
                if (!this.isMobile() && this.store.getMessageAndNotification.incoming_calls_sound) {
                    // Determine the audio source based on the call type
                    const audioSource = this.inComingCallingPopup || this.incomingaudiocallpopup ?
                        "https://appfilemedia.talygen.com/Upload/UnifiedCommunication/88084cf1-f794-41eb-aea0-4c1267cf6d34.mp3" :
                        "https://appfilemedia.talygen.com/Upload/UnifiedCommunication/3a32194a-a407-4da4-9b89-898efeb32206.mp3"

                    // Initialize and play the ring tune
                    this.ringTune = new Audio(audioSource);
                    this.ringTune.loop = true;

                    // Play the audio and handle possible errors
                    this.ringTune.play().then(() => {}).catch((error) => {
                        console.error('Error playing ring tune:', error);
                    });
                }
                // Stop the ring tune after 15 seconds
                this.ringTuneTimer = setTimeout(() => {
                    this.stopRingTune();
                    this.disconnectVideo();
                }, 32000);

            } catch (error) {
                console.error('Error initializing ring tune:', error);
            }
        },
        stopRingTune() {
            if (this.ringTune) {
                this.ringTune.pause();
                this.ringTune.currentTime = 0; // Reset the audio
            }
            clearTimeout(this.ringTuneTimer);
        },
        
        videoCallFromGroup() {
            var param = {}
            param.room = this.groupidSearch,
            param.calltype = this.callType,
            param.isGroup = 0;
            param.alias = this.sender.id + '_0';
            param.IsSel = this.callParams.IsSel
            param.isSender = 1
            param.token = this.videoroomID
            param.name = this.callParams.groupName
            param.aliasSel = this.callParams.aliasSel + '_' + this.selectedGroupMembers.join('_');
            param.IdList = param.aliasSel
            this.selectedGroupMembers.map((item) => {
                param.receiver = item
                this.alreadySelectedMembers.push(Number(item))
                this.$socket.emit('addNewVideoMember', param);
            })
            this.selectedGroupMembers = []

            this.groupSelectMemberPopupShow = false
            clearInterval(this.checkWhoPickCall)
            this.checkUserPickCall()
        },
        //Video call Methode
        videoPopUpCall(data, isSelUsr, selUserData) {

            let videoCallParam = JSON.parse(JSON.stringify(this.sender))
            this.videoCallShow = true
            videoCallParam.imgPath = "testtttttt.png"
            videoCallParam.room = data.room
            videoCallParam.calltype = data.calltype
            videoCallParam.isGroup = data.IS_GROUP ? data.IS_GROUP : 0;
            videoCallParam.aliasSel = selUserData + "_" + this.store.getUserInformation.ID
            videoCallParam.alias = this.store.getUserInformation.ID + "_" + this.callToUserInfo.USER_ID;
            videoCallParam.IsSel = isSelUsr
            videoCallParam.receiver = this.callToUserInfo.USER_ID
            videoCallParam.groupName = data.CONTACTNAME
            videoCallParam.isSender = 1
            videoCallParam.token = ''
            videoCallParam.id=  this.store.getUserInformation.ID
            videoCallParam.companyId = this.store.getUserInformation.CompanyId
            videoCallParam.emaiId =this.store.getUserInformation.Email
            videoCallParam.email = this.store.getUserInformation.Email
            videoCallParam.imgPath = data.IS_GROUP ? data.USER_IMAGE : this.store.getUserInformation.Avatar ? this.store.getBlobUserUrl + this.store.getUserInformation.Avatar : ''
            videoCallParam.name = this.store.getUserInformation.Name
            videoCallParam.type = 'web'
            if (isSelUsr > 0)
            videoCallParam.IdList = videoCallParam.aliasSel + "_" + videoCallParam.id;
            else
            videoCallParam.IdList = videoCallParam.alias;
            /// this.videoCall(param);
            videoCallParam.url = window.location.href
            this.GroupCallVideoInfo = videoCallParam
            this.callParams = videoCallParam
            this.setup_local_media(videoCallParam)
            
            
        },
        
        VideoCallPopUP(param) {
            //this.videoCallShow = true
            this.callToUserInfo = param
            if (param.isSender == 1) {
                param.groupName = param.name;
            } else {
                try {
                    param.groupName = param.Receiver_name;

                } catch (e) {
                    alert(e);
                }
                this.inComingCallingPopup = false
                this.incomingaudiocallpopup = false
            }

            this.setup_local_media(param)

        },
        /**
         * user side video call start
         * @param {*} contect
         */
        videoCreate(contect) {
            this.store.$state.talygenCallRunning = true
            this.groupidSearch = contect.room
            this.alreadySelectedMembers = contect.GROUP_NAME_ALIAS ? contect.GROUP_NAME_ALIAS.replace(/_/g, ',').split(',').map(Number) : [];
            //this.videoCallShow = true
            //this.sender.imgPath = this.store.getBlobUserUrl + this.store.getUserInformation.Avatar
            this.callToUserInfo  = JSON.parse(JSON.stringify(contect));
            let receiver = contect.USER_ID;
            const params = {
                emaild: this.store.getUserInformation.Email,
                name: contect.CONTACTNAME, // Corrected typo in property name
                id: this.store.getUserInformation.ID,
                type: "web",
                companyId: this.store.getUserInformation.CompanyId,
                imgPath: contect.USER_IMAGE,
                userType: 'vdrt',
                alias: this.store.getUserInformation.ID + "_" + receiver,
                room: this.store.getUserInformation.ID + "_" + receiver,
                isSender: 1,
                IdList: this.store.getUserInformation.ID + "_" + receiver,
                IS_GROUP: contect.IS_GROUP,
                calltype: contect.calltype,
                receiver: receiver,
                url: window.location.href
            };
             
            this.callType = contect.calltype
            if (contect.IS_GROUP) {
                this.isgroupcall = true
                params.alias = contect.GROUP_NAME_ALIAS
                params.IS_GROUP = 1,
                params.room = contect.room

                this.videoPopUpCall(contect, 1, params.alias)
            } else {

                params.alias = this.store.getUserInformation.ID + "_" + receiver
                this.$socket.emit('createRoom', params);
            }
            this.playRingTune()
            this.checkUserPickCall()
        },
        checkUserPickCall(){
            this.checkWhoPickCall = setInterval(() => {
  // Convert videoAudioCallStreaming into a Set for faster lookup
  const activeUserIds = new Set(this.videoAudioCallStreaming.map(record => record.userId));

  // Use the Set for efficient filtering of alreadySelectedMembers
  this.alreadySelectedMembers = this.alreadySelectedMembers.filter(item => activeUserIds.has(item));

  // Clear interval if there are no more members
  if (this.alreadySelectedMembers.length === 0) {
    clearInterval(this.checkWhoPickCall);
  }

}, 32000);
        },

        setup_local_media(param, callback, errorback) {
    try {
        // Open the call sidebar
        this.$parent.openCallSideBar(true);

        // Emit user stream event
        const userStreamData = {
            socketId: this.$socket.id,
            streamId: '',
            userId: this.sender.id,
            IdList: param.IdList || param.alias,
            name: this.sender.name,
            
        };
        this.$socket.emit('addUserStream', userStreamData);

        // Handle sender logic
        if (param.isSender === 1) {
            this.streamerName = param.name;
            param.url = window.location.href;
             
            this.$socket.emit('video call', param, () => {
                this.showPopup(param);
            });
        } else {
            // Handle receiver logic
            const joinVideoData = {
                channel: param.token,
                userdata: this.store.getUserInformation.ID,
                calltype: param.calltype
            };

            this.$socket.emit('joinVideo', joinVideoData, () => {
                this.showPopup(param);
            });
        }

        // Invoke the callback after setup completes
        if (callback) callback();
    } catch (error) {
        // Handle errors and invoke the error callback if provided
        this.disconnectVideo('reject');
        if (errorback) errorback(error);
    }
},

showPopup(param) {
    if (param.calltype === 'audio') {
        this.audioCallPopupShow = true;
        this.pauseResumeVideo = 'pause';
    } else {
        this.videoCallShow = true;
    }
},
        VideoCallPickupMethod(type) {
            this.inComingCallingPopup = false
            this.incomingaudiocallpopup = false
            
            clearTimeout(this.timerOut);
            const room_accept = this.incomingVideoCallinfo.roomId + '~' + this.incomingVideoCallinfo.actRoom + '~' + this.incomingVideoCallinfo.actRoomId
            const receiverId_accept = this.incomingVideoCallinfo.fromUserId;
            const contactname_accept = this.incomingVideoCallinfo.fromName;
            const newparam = new Object();
            newparam.receiver = receiverId_accept;
            newparam.contactname = contactname_accept;
