        notifyMe(data, type) {

            const body = "You have received a " + data.calltype + " call from " + data?.fromName.replace(/%20/g, " ");
            const icon = data.fromUserPath;
            const title = this.$t("TALYGEN") + ":" + this.$t("UnifiedCommunication");
            const linkAccept = "joinVideoCall"; // Adjust this based on your requirements
            const duration = 4000;

            if (!("Notification" in window)) {
                alert("This browser does not support desktop notification");
            } else if (Notification.permission === "granted") {
                this.displayNotification(body, icon, title, linkAccept, duration, data, type);
            } else if (Notification.permission !== "denied") {
                Notification.requestPermission().then((permission) => {
                    if (permission === "granted") {
                        this.displayNotification(body, icon, title, linkAccept, duration, data, type);
                    }
                });
            }
        },
        videoCallFromUrl(data) {
            var newparam = {};
            //   if (type == "talygen") {
            newparam.room = `${data.roomId}~${data.actRoom}~${data.actRoomId}`;
            newparam.receiver = data.fromUserId;
            newparam.contactname = data.fromName;
            newparam.id = data.toUserId;
            this.$socket.emit('add video on chat', newparam);
            this.inComingCallingPopup = false
            this.incomingaudiocallpopup = false
            this.store.$state.talygenCallRunning = true
            this.stopRingTune()
        },
        displayNotification(body, icon, title, linkAccept, duration, data, type) {
            duration = duration || 4000;
            var options = {
                icon: icon,
                body: body
            };

            var n = new Notification(title, options);

            n.onclick = () => {
                var isMobile = window.orientation > -1;

                if (isMobile) {
                    localStorage.removeItem('clientOpen');
                    chatlogwindow.close();
                }
                this.videoCallFromUrl(data)
               
                n.close();
                
            };
            setTimeout(n.close.bind(n), duration);
        },
        removeVideoCallParams() {

            clearTimeout(this.timerOut);
            clearInterval(this.started)
            this.videoCallCounting = 0
            this.videoCallShow = false
            this.audioCallPopupShow = false
            this.inComingCallingPopup = false
            this.incomingaudiocallpopup = false
            this.remoteStreams = []
            this.peer = {}
            this.localMediaStream = null;
            this.peer_connection = ''
            this.peers = {}
            this.peer_media_elements = {}
            this.MUTE_AUDIO_BY_DEFAULT = false
            this.incomingVideoCallinfo = ''
            this.callParams = ''
            this.stopRingTune()
