        disconnectVideo(event) {
            
            this.$socket.emit('deleteSocket', this.$socket.id)
            this.$socket.emit('removeUserStream', {
                "socketId": this.$socket.id
            })
            if (event == 'reject') {
                let params = this.incomingVideoCallinfo ? this.incomingVideoCallinfo : this.callParams
                params.room = this.callParams ? this.callParams.room : this.incomingVideoCallinfo.actRoom
                this.$socket.emit('video call reject', params)
            } 
            this.removeVideoCallParams()
            if (this.api) {
    this.participantsList = [];
    this.api.dispose(); // Clean up the Jitsi instance
    this.videoCallShow = false; // Hide the video call UI
  }
        },
     
        initializeJitsiMeet(room, name) {
            
            let videoStatus = this.callType === "audio" ? false :true
  const options = {
    roomName: room,
    width: "100%",
    height: 700,
    parentNode: document.querySelector("#jitsi-container"),
    userInfo: {
      displayName: name, // Pass custom name here
      id: this.sender.id,
    },
    configOverwrite: {
      prejoinConfig: {
        enabled: false, // Disable pre-join screen
        
      },
      startWithVideoMuted: this.callType === "audio" ? true :  false, // Start with video muted (voice call only)
    },
    // Show all toolbar buttons
    interfaceConfigOverwrite: {
        SHOW_JITSI_WATERMARK: false,         // Hides the Jitsi logo watermark
    SHOW_WATERMARK_FOR_GUESTS: false,    // Hides watermark for guests
    SHOW_BRAND_WATERMARK: false, 
        DEFAULT_LOGO_URL: '',
        watermark:false,
        DISPLAY_WELCOME_PAGE_CONTENT: false, 
        DEFAULT_REMOTE_DISPLAY_NAME: 'Custom Room Name',
        VIDEO_QUALITY_LABEL_DISABLED: this.callType === "audio" ? false :  true,
        TOOLBAR_BUTTONS: [
          'microphone', 
          'camera', 
          'hangup',  
          'settings', 
          'tileview', 
          'fullscreen'
          // Exclude 'fullscreen' to hide the fullscreen button
          // Add or remove other buttons as necessary
        ],
        // Optional: Disable Picture-in-Picture for participants
        ENABLE_PIP: false,
    },
  };

  try {
    this.videoCallShow = true
    this.api = new JitsiMeetExternalAPI(this.domain, options);
     // Inject CSS to hide room name after joining
  
    
    // Event: Conference joined
    this.api.addEventListener("videoConferenceJoined", () => {
        this.networkSlowMessage= false
        setTimeout(() => {
    this.api.executeCommand('subject', this.incomingVideoCallinfo ? this.incomingVideoCallinfo.groupName ?
    this.incomingVideoCallinfo.groupName : this.incomingVideoCallinfo.fromName :
    this.callToUserInfo.CONTACTNAME);
    
  }, 1000); 
        if(this.callType === "audio"){
        this.api.executeCommand('toggleVideo');
    }
   
    

    });

    // Event: Participant joined
    this.api.addEventListener("participantJoined", (participant) => {
        
    console.log("Participant joined", participant);
    this.addOrUpdateParticipant(participant); // Add the new participant to the list
});

    // Event: Conference left or meeting closed
    this.api.addEventListener("readyToClose", this.leaveMeeting);

    // Event: Raise hand updated
    this.api.addEventListener("raiseHandUpdated", (event) => {
        
      console.log("Raise hand event:", event);
    });

    // Event: Audio muted/unmuted
    this.api.addEventListener("audioMuteStatusChanged", (payload) => {
    
      console.log("Audio mute status changed:", payload.muted ? "Muted" : "Unmuted");
    });

    // Event: Video muted/unmuted
    this.api.addEventListener("videoMuteStatusChanged", (payload) => {
        if (!payload.muted && !videoStatus) {
            this.api.executeCommand('toggleVideo');
            videoStatus = true
    }
      console.log("Video mute status changed:", payload.muted ? "Muted" : "Unmuted");
    });

    // Event: Participant left
    this.api.addEventListener("participantLeft", (participant) => {
        console.log("participant participant:", participant);
        const participants = this.api.getParticipantsInfo();
        this.participantsList = this.participantsList.filter(p => p.id !== participant.id);
        if(participants.length ==1 || participants.length ==0){
            this.leaveMeeting()
        }
    });

    // Event: Chat message received
    this.api.addEventListener("incomingMessage", (message) => {
        
      console.log("New message received:", message);
    });

    // Event: Screen sharing enabled/disabled
    this.api.addEventListener("screenSharingStatusChanged", (event) => {
        
      console.log("Screen sharing status:", event.on ? "Enabled" : "Disabled");
    });

    // Event: Toggle tile view (grid layout)
    this.api.addEventListener("tileViewChanged", (event) => {
        
      console.log("Tile view changed:", event.enabled ? "Enabled" : "Disabled");
    });

    // Event: Fullscreen mode toggled
    this.api.addEventListener("fullscreenChanged", (event) => {
        
      console.log("Fullscreen mode:", event.enabled ? "Enabled" : "Disabled");
    });

  } catch (error) {
    console.error("Failed to start Jitsi meeting", error);
  }
},
participantLeft(event){
console.log("event",event)
},


leaveMeeting() {
  if (this.api) {
    this.participantsList = [];
    this.api.dispose(); // Clean up the Jitsi instance
    this.videoCallShow = false; // Hide the video call UI
    this.disconnectVideo()
  }
} ,
   
 addOrUpdateParticipant(participant)  {
    const existingParticipantIndex = this.participantsList.findIndex(p => p.id === participant.id);
    
    if (existingParticipantIndex > -1) {
        // Update existing participant
        this.participantsList[existingParticipantIndex].name = participant.name; // Update name if necessary
    } else {
        // Add new participant with custom ID and name
        this.participantsList.push({
            id: participant.id,
            name: participant.name || `Participant ${this.participantsList.length + 1}` // Default name if not provided
        });
    }
}, 
/**
 * truncate words
 * @param str set words
 * @param charLimit set limits of char
 */
truncateWord(str,charLimit){
            if(str){
                return str.length > charLimit ? str.slice(0, charLimit) + '...' : str;
            }else{
            return str
            }
