            selectedGroupMembers: [],
            alreadySelectedMembers: [],
            GroupCallVideoInfo: [],
            streamerName: '',
            videoAudioCallStreaming: [],
            activeSpeakerId: null, // ID of the currently active speaker
            audioLevels: {},
            checkWhoPickCall:'',
            defaultImg:'https://talygenv.github.io/Vue-UI-Content/images/UC/uc_user_new.jpg',
            domain: "jitsidocker.talygen.com",
            roomName: "demo", // You can dynamically generate room names
            options: null,
            api: null,
            participantsList:[],
            networkSlowMessage:false
        }
    },
};
