            this.logId = message.item.LOG_ID
        },
        call_status: function (message) {
            const vm = this;
            this.callStatus = message.call.CallStatus;
            
            let parmObject = {
                companyId: this.store.getUserInformation.CompanyId,
                Channel: '',
                extension: message.call.Caller,
                callFrom: message.call.Caller,
                callTo: message.call.To,
                callerIdName: '',
                CallType: message.call.From === this.store.getTwilioAccountDetails?.NUMBER ? 'Outgoing' : 'Incoming',
                QueryType: '',
                recentStatus: '',
                actionId: null,
                linkedId: message.call.ParentCallSid,
                uniqueId: message.call.CallSid,
                userId: this.store.getUserInformation.ID,
                logId: 0,
                callerImage: null,
                CallingMedium: 'twilio'
            };

            switch (message.call.CallStatus) {
                case 'ringing':
                   
                    parmObject.recentStatus = 'RINGING';
                    parmObject.QueryType = 'INSERT';
                    vm.$socket.emit('incomingOutGoingRecord', parmObject);
                    break;

                case 'in-progress':
                    vm.store.$state.callEnded = false;
                    parmObject.recentStatus = 'CALLSTART';
                    parmObject.QueryType = 'UPDATE';
                    parmObject.logId = vm.logId;
                    vm.$socket.emit('incomingOutGoingRecord', parmObject);
                    vm.store.callTimerStart();
                    vm.runningCallInformation = message.call;
                    break;

                case 'initiated':
                    // You can handle the 'initiated' status if necessary
                    break;

                case 'busy':
                    parmObject.recentStatus = 'BUSY';
                    parmObject.QueryType = 'UPDATE';
                    vm.$socket.emit('incomingOutGoingRecord', parmObject);
                    break;
                    case 'reject':
    parmObject.recentStatus = 'REJECTED';
    parmObject.QueryType = 'UPDATE';
    vm.$socket.emit('incomingOutGoingRecord', parmObject);
    break;
    case 'no-answer':
    parmObject.recentStatus = 'ANSWERED';
    parmObject.QueryType = 'UPDATE';
    vm.$socket.emit('incomingOutGoingRecord', parmObject);
    break;
                case 'completed':
                    parmObject.CallType = vm.store.$state.timerStart > 0 ? 'Missed' : parmObject.CallType;
                    vm.store.$state.incomingAndOutGoingCall = '';
                    var completeCall = {
                        logId: vm.logId,
                        QueryType: 'UPDATE',
                        recentStatus: 'HANGUP'
                    };
                    vm.$socket.emit('incomingOutGoingRecord', completeCall);
                    if (vm.store.$state.callEnded) {
                        vm.store.$state.outGoingcallData = '';
                        vm.store.$state.incomingCallData = '';
                    } else {
                        vm.hangup();
                    }
                    break;

                default:
                    
            }
        },
