            const vm = this;
            let findLatest = vm.store.getRecentChatUser.find(x => x.GROUP_ID == data.room);
            if(findLatest){
            var paramsObj = {
                alias: findLatest.GROUP_NAME_ALIAS,
                companyId: vm.sender.companyId,
                emaiId: vm.sender.emaiId,
                groupName: findLatest.GROUP_NAME,
                id: vm.sender.id,
                imgPath: vm.sender.imgPath,
                is_first_time: 1,
                isGlobalSearch: false,
                lastchatId: null,
                lastrow: 0,
                name: vm.sender.name,
                room: findLatest.GROUP_NAME_ALIAS
