        truncateMessage(message) {
            const maxLength = 200;
            var gifRegex = /(https?:\/\/.*\.(?:gif))/i;

            // Regular expression to match emojis
            //var emojiRegex = /[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/u;

            // Check if the text contains a GIF URL
            var hasGif = gifRegex.test(message);

            // Check if the text contains an emoji
            //var hasEmoji = emojiRegex.test(message);

            // Check if the message contains an HTML img tag or a GIF URL
            if (/<img[^>]+src="([^">]+)"/.test(message) || hasGif) {
                // If it contains an image tag or a GIF URL, return [GIF]
                message = message.replace(/<img[^>]+src="([^">]+)"(?: alt="[^"]*")?(?: style="[^">]*")?>/, '[GIF]');
            } else {
                if (message.length > maxLength) {
                    // If it doesn't contain an image tag or a GIF URL, truncate the message
                    return message.substring(0, maxLength) + '...';
                }
            }
            return message;
        },
        secondsToHms(secs) {

            if (secs) {
                var sec_num = parseInt(secs, 10)
                var hours = Math.floor(sec_num / 3600)
                var minutes = Math.floor(sec_num / 60) % 60
                var seconds = sec_num % 60

                return [hours, minutes, seconds]
                    .map(v => v < 10 ? "0" + v : v)
                    .filter((v, i) => v !== "00" || i > 0)
                    .join(":")
            } else {
                return ''
            }
        },
