        getStartOfWeek(date) {

            // Copy date if provided, or use current date if not
            date = date ? new Date(+date) : new Date();
            date.setHours(0, 0, 0, 0);

            // Set date to previous Sunday
            date.setDate(date.getDate() - date.getDay());

            return date;
        },
        getEndOfWeek(date) {
            date = this.getStartOfWeek(date);
            date.setDate(date.getDate() + 6);
            return date;
        },
        callFilter(event) {
            if (event == this.selectFilter) {
                this.selectFilter = ''
            } else {
                this.selectFilter = event
            }
            this.selectChildFilter = ''
            const vm = this;
            let to = null
            let from = null

            if (event == 'All') {
                from = null,
                    to = null
            } else if (event == 'Today') {
                const currentFromDate = moment();
                from = currentFromDate.format(dateFromat);
                const currentToDate = moment();
                to = currentToDate.format(dateFromat);
            } else if (event == 'Yesterday') {
                const currentDate = moment();
                const currentToDate = moment(currentDate).subtract(1, 'days');
                to = currentToDate.format(dateFromat);
                // vm.ToDate = moment();
                const currentFromDate = moment(currentDate).subtract(1, 'days');
                from = currentFromDate.format(dateFromat);
            } else if (event == 'thisWeek') {
                const currentToDate = moment(vm.getEndOfWeek(moment()));
                to = currentToDate.format(dateFromat);
                const currentFromDate = moment(vm.getStartOfWeek(moment()));
                from = currentFromDate.format(dateFromat);
            } else if (event == 'thisMonth') {
                const currentToDate = moment();
                to = currentToDate.format(dateFromat);
                var gettodaydate = currentToDate.format('DD');
                const currentFromDate = moment(currentToDate).subtract(parseInt(gettodaydate) - 1, 'days');
                from = currentFromDate.format(dateFromat);
            } else if (event == 'LastMonth') {
                var getcurrentdate = moment();
                const currentToDate = getcurrentdate.subtract(1, 'months').startOf('month');
                from = currentToDate.format(dateFromat);
                const currentFromDate = getcurrentdate.endOf('month').subtract(1, 'days');
                to = currentFromDate.format(dateFromat);
            }
            if (from && to) {
                from = from + " 00:00:00"
                to = to + " 23:59:59"
            }
            this.store.recentCalls(`fromDate=${encodeURIComponent(from)}&toDate=${encodeURIComponent(to)}&isLocalSearch=false`)
            // vm.$emit('Date-Pass','Text');
        },
