                const currentFromDate = moment();
                vm.FromDate = currentFromDate.format('MM/DD/YYYY');
                const currentToDate = moment();
                vm.ToDate = currentToDate.format('MM/DD/YYYY');
            } else if (event == 'Yesterday') {
                const currentDate = moment();
                const currentToDate = moment(currentDate).subtract(1, 'days');
                vm.ToDate = currentToDate.format('MM/DD/YYYY');
                // vm.ToDate = moment();
                const currentFromDate = moment(currentDate).subtract(1, 'days');
                vm.FromDate = currentFromDate.format('MM/DD/YYYY');
            } else if (event == 'thisWeek') {
                const currentToDate = moment();
                vm.ToDate = currentToDate.format('MM/DD/YYYY');
                const currentFromDate = moment(currentToDate).subtract(7, 'days');
                vm.FromDate = currentFromDate.format('MM/DD/YYYY');
            } else if (event == 'thisMonth') {
                const currentToDate = moment();
                vm.ToDate = currentToDate.format('MM/DD/YYYY');
                var gettodaydate = currentToDate.format('DD');
                const currentFromDate = moment(currentToDate).subtract(parseInt(gettodaydate) - 1, 'days');
