            const globalGroup = [];
            const groupBy = array.map((el) => el.MODULE_TYPE);
            const brandNames = [...new Set(groupBy)]; // This is one way to remove duplicate values from an Array

            // If you need your brands to appear in a particular order, you could sort them here

            for (let brandName of brandNames) {
                const brand = {
                    brandname: brandName,
                };

                brand.items = array
                    .filter((el) => el.MODULE_TYPE === brandName)
                    .map((el) => {
                        return {
                            ...el
