<style>
/* New combined class for the profile wrapper */
.new-profile-wrapper {
    display: flex;
    flex-direction: column;
    align-items: center;
    background-color: #f0f0f0;
    /* Optional background color */
    /* padding: 10px; */
    /* Optional padding */
}

/* New combined class for the profile image container */
.new-profile-img {
    position: relative;
    width: 100%;
    max-width: 640px;
    /* Maximum width for the video container */
    padding-top: 56.25%;
    /* 16:9 aspect ratio (9 / 16 = 0.5625) */
    background-color: #000;
    /* Background color to fill the space before the video loads */
    border-radius: 8px;
    /* Optional rounded corners */
    overflow: hidden;
    /* Ensures the video doesn't overflow the container */
}

/* New combined class for the local video element */
.new-local-video {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    /* Ensures the video covers the container without distortion */
    border-radius: 8px;
    /* Matches the container's rounded corners */
}

.blinkingcommon2 {
    animation: blinker 1s linear infinite;
    background-color: rgb(61, 176, 180);
    /* Light blue background */
}

@keyframes blinker {
    50% {
        opacity: 0;
    }
}

