                                <button type="button" class="btn nav-btn bluebg" data-bs-toggle="modal"
                                    data-bs-target="#videocallModal">
                                    <i class="fas fa-video"></i>
                                </button>
                            </li>



                            <li class="list-inline-item">
                                <div class="dropdown">
                                    <button class="btn nav-btn dropdown-toggle darkbg" type="button"
