                                        <i class="fas fa-ellipsis-v"></i>
                                    </button>
                                    <div class="dropdown-menu dropdown-menu-end d-block" style="float: left;"
                                        v-if="globalAction"
                                        v-closable="{ exclude: ['globalCahtPopup'], handler: 'globalPopupOpen' }">
                                        <!-- <a class="dropdown-item d-block d-lg-none user-profile-show" >{{$t('View')}}
                                            profile <i class="ri-user-2-line float-end text-muted"></i></a> -->
                                        <a class="dropdown-item d-block d-lg-none" :class="store.getTalygenRunningCall ? 'disabled': ''" :title="$t('VoiceCall')" @click="videoCreate('audio')"  data-bs-toggle="modal"
                                            data-bs-target="#audiocallModal">{{$t('Audio')}} <i
                                                class="ri-phone-line float-end text-muted"></i></a>
                                        <a class="dropdown-item d-block d-lg-none" :class="store.getTalygenRunningCall ? 'disabled': ''" :title="$t('VideoCall')" @click="videoCreate()"
                                            data-bs-toggle="modal" data-bs-target="#videocallModal">{{$t('Video')}} <i
                                                class="ri-vidicon-line float-end text-muted handpointer"></i></a>

                                            <a class="dropdown-item handpointer" @click="$parent.detailpopup({data:chatHistoryDetails.groupDetail,show:true});globalAction = !globalAction">{{ chatHistoryDetails.groupDetail.IS_GROUP ? $t('GroupInfo') : $t('ContactInfo') }}<i
                                                class="ri-contacts-book-2-line  float-end text-muted handpointer"></i></a>
                                            <a class="dropdown-item handpointer" v-on:click="ShowSearchMessageArea();globalAction = !globalAction">{{$t('Search')}}<i
                                                class="ri-search-2-line  float-end text-muted handpointer"></i></a>

                                            <!-- <a class="dropdown-item handpointer" @click="globalAction = !globalAction">{{ $t('Selectmessage') }}</a> -->
                                            <a class="dropdown-item handpointer"  v-on:click="$parent.UsrDeleteHistory(chatHistoryDetails.groupDetail, 'History');globalAction = !globalAction" title="Clear Chat">{{ $t('ClearChat') }}<i
                                                class="ri-delete-bin-2-line  float-end text-muted handpointer"></i></a>





                                        <!-- <a class="dropdown-item" v-on:click="$parent.ArchiveUserGroup(chatHistoryDetails.groupDetail)">{{ chatHistoryDetails.groupDetail.IS_ARCHIVE == true ? $t('UnArchive') : $t('ARCHIVED')}} <i
                                                class="ri-archive-line float-end text-muted"></i></a> -->
                                        <!-- <a class="dropdown-item" >Muted <i
                                                class="ri-volume-mute-line float-end text-muted"></i></a> -->

                                    </div>
                                </div>
                            </li>
                        </ul>
                    </div>
                </div>
            </div>
