                                                            <div :class="{'readLess' : !readMore.includes(item.CHATLOG_ID) && item.MESSAGE.length > 300}" class="ms-1 formatted-text mt-2 max-width-img">{{  item.MESSAGE }}</div>
                                                        </template>

                                                        <template v-else-if="isImage(item.FILEEXTENSION)">
