                                                            <div :class="{'readLess' : !readMore.includes(item.CHATLOG_ID) && item.MESSAGE.length > 300}"  class="ms-1 formatted-text mt-2 max-width-img" v-if="item.MESSAGE!=''">{{item.MESSAGE }}</div>
                                                        </template>

