                                                    <path
                                                        d="m12.67 20.74-.67.61-1.45-1.32c-5.15-4.67-8.55-7.76-8.55-11.53 0-3.09 2.42-5.5 5.5-5.5 1.74 0 3.41.81 4.5 2.08 1.09-1.27 2.76-2.08 4.5-2.08 3.08 0 5.5 2.41 5.5 5.5 0 1.43-.5 2.76-1.38 4.11-.62-.3-1.31-.5-2.03-.57.91-1.24 1.41-2.39 1.41-3.54 0-2-1.5-3.5-3.5-3.5-1.54 0-3.04 1-3.57 2.36h-1.86c-.53-1.36-2.03-2.36-3.57-2.36-2 0-3.5 1.5-3.5 3.5 0 2.89 3.14 5.74 7.89 10.05l.11.1.04-.04c.08.76.3 1.48.63 2.13m4.33-6.74v3h-3v2h3v3h2v-3h3v-2h-3v-3z" />
                                                </svg></a>
