                                                v-if="actionMessagePopupShow == item.CHATLOG_ID"
                                                v-closable="{ exclude: ['actionMessageButton'], handler: 'actionMessagePopup' }">
                                                <button class="dropdown-item handpointer" v-if="item.ATTACHMENT != 1 && !item.MESSAGE.includes('src')" 
                                                    v-on:click="copyToClipboard(item)">{{ $t('CopyToClipBoard') }} <i
                                                        class="ri-file-copy-line float-end text-muted"></i></button>
                                                <!-- <a class="dropdown-item" >Save <i class="ri-save-line float-end text-muted"></i></a> -->
                                                <button class="dropdown-item handpointer"
                                                    v-on:click="ForwardMessageTo(item)">{{$t('Forward')}} <i
                                                        class="ri-chat-forward-line float-end text-muted"></i></button>
                                                <button class="dropdown-item handpointer"
                                                    v-on:click="DeleteMessage(item, index)">{{$t('Delete')}} <i
                                                        class="ri-delete-bin-line float-end text-muted"></i></button>
