                                                    v-on:click="downloadFile(item)">{{$t('Download')}} <i
                                                        class="ri-download-line float-end text-muted"></i></button>
                                                <!-- <button class="dropdown-item" v-if="item.FROM_USER_ID==store.getUserInformation.ID && formatDateToISO(item.CREATED_AT).split('T')[0] == todayDate"
                                                v-on:click="EditMessage(item, index)">Edit <i
                                                        class="ri-pencil-bin-line float-end text-muted" title="Edit Message"></i></button> -->

                                                <button class="dropdown-item handpointer"  
                                                 v-on:click="$parent.editMessageInfo(item, index)">{{$t('INFO')}} <i
                                                        class="ri-information-line float-end text-muted" title="Message info"></i></button>

                                                       

                                            </div>
                                        </div>

                                    </div>



                                </div>


                            </div>

