        UpdateEmojiReactions: async function (item) {

            const vm = this;

            // let data = [];
            const index = vm.chatHistoryDetails.resultSet.findIndex(function (params) {
                return params.MESSAGE_TOKEN == item.message_token;
            });

            if (index !== -1) {
                let reactedUserData = JSON.parse(vm.chatHistoryDetails.resultSet[index].reactedUser);


                if (reactedUserData != undefined && reactedUserData != null) {
                    if (reactedUserData.DATA && reactedUserData.DATA.length > 0) {
                        // Check if the reaction already exists
                        const index2 = reactedUserData.DATA.findIndex(function (res) {
                            return Number(res.ReactionId) == Number(item.ReactionId);
                        });

                        if (index2 !== -1) {
                            // If found, update the reaction type
                            reactedUserData.DATA[index2].ReactionType = item.ReactionType;
                        } else {
                            // If not found, add the new reaction
                            reactedUserData.DATA.push(item);
                        }

                        // Ensure there are no duplicate reactions based on ReactionId
                        const uniqueReactions = reactedUserData.DATA.reduce((acc, current) => {
                            const x = acc.find(reaction => reaction.ReactionId === current.ReactionId);
                            if (!x) {
                                acc.push(current);
                            }
                            return acc;
                        }, []);

                        reactedUserData.DATA = uniqueReactions;

                    }
                    else {
                        // If DATA array is empty, add the new reaction
                        reactedUserData.DATA = [item];
                    }
                } else {
                    // If reactedUserData is undefined or null, initialize it with the new reaction
                    reactedUserData = { DATA: [item] };
                }

                // Update the chat history details with the modified reactedUserData
                vm.chatHistoryDetails.resultSet[index].reactedUser = JSON.stringify(reactedUserData);


            }
        },

