         formatMessage(message) {
            // Regex pattern to find URLs starting with http, https, ftp, file, or www
            const urlPattern = /(\b(?:https?:\/\/|ftp:\/\/|file:\/\/|www\.)[-A-Z0-9+&@#\/%?=~_|!:,.;]*[-A-Z0-9+&@#\/%=~_|])/ig;

            // Replace URLs with anchor tags
            return message.replace(urlPattern, url => {
                // Remove the protocol for display
                const displayUrl = url.replace(/^(https?:\/\/|ftp:\/\/|file:\/\/|\.)/, '');
                
                // Prepend "https://" if the URL starts with "www."
                const fullUrl = url.startsWith('www.') ? `https://${url}` : url;

                return `<a href="${fullUrl}" target="_blank" rel="noopener noreferrer">${displayUrl}</a>`;
            });
            },
