        CheckallowedFilesToSend: function (e) { 
            
            const vm = this;
            vm.allowedfiletype=[]
            vm.Options1=[]
            if(vm.AttachmentFileDetail.length>0)
            {
                
                let params = `moduleName=UnifiedCommunication`;
                    DataService.GetFileType(params).then((response) => {
                        vm.FileTypeData=response.data;
                        vm.FileTypeData.forEach((item, index) => {
                        vm.Options1.push({
                        value: item.MimeTypes,
                        label: item.FileType,
                        });
                    });
                    let params1 = `moduleName=UnifiedCommunication&keyValue=UnifiedCommunicationAllowedFileTypes,UnifiedCommunicationAllowedFileSize,VoiceNoteDurationLimit`;
                    DataService.GetConfigDataValue(params1).then((response) => {
                        
                        if(JSON.parse(response.data.ConfigValue).length>0)
                        {
                            vm.fileType = JSON.parse(response.data.ConfigValue)[0].CONFIG_DATA_VALUE;
                            vm.fileKey = JSON.parse(response.data.ConfigValue)[0].CONFIG_DATA_KEY;
                            let fileTypeFormats = vm.fileType.split('^');
                            //let selectedValues= vm.Options.filter((x)=>{return fileTypeFormats.some((y)=>{ return x.value.indexOf(y)!=-1})}); 
                            let selectedValues = vm.Options1.filter(option => {
                                return fileTypeFormats.some(format => {
                                    return option.label.toLowerCase().includes(format);
                                });
                            });
                            let fileSize = JSON.parse(response.data.ConfigValue).find(x=>x.CONFIG_DATA_KEY=='UnifiedCommunicationAllowedFileSize')
                            let timeDurationLimit = JSON.parse(response.data.ConfigValue).find(x=>x.CONFIG_DATA_KEY=='VoiceNoteDurationLimit')
                            let fsize=''
                            let countFiles=0;
                            vm.AttachmentFileDetail.forEach((fileItm,fileIndex)=>{
                                fsize= (fileItm.size / 1048576).toFixed(2);
                               
                                if (parseInt(fsize) <= parseInt(fileSize.CONFIG_DATA_VALUE)) {
                                    countFiles++;
                                    if((vm.AttachmentFileDetail.length)==countFiles)
                                    {
                                        vm.allowedfiletype=selectedValues.map(x=>x.value);  
                                        
                                    if((vm.allowedfiletype.some(x=>x.includes(vm.AttachmentFileDetail[0].type)))){
                                    
                                            if(vm.AttachmentFileDetail[0].type=='audio/x-wav')
                                            {
                                                if(parseInt(vm.recordingTime) <= parseInt(timeDurationLimit.CONFIG_DATA_VALUE))
                                                {
                                                    vm.SendAttachment()
                                                }
                                                else
                                                {
                                                    vm.ShowAlert('File type not allowed to share '+vm.recordingTime, "failure", vm.$t('Alert'));
                                                    vm.AttachmentFileDetail=[];
                                                }
                                            }
                                            else
                                            {
                                                vm.SendAttachment()
                                            }
                                        
                                    
                                    }
                                    else
                                    {
                                        vm.ShowAlert('File type not allowed to share '+vm.AttachmentFileDetail[0].type, "failure",false, vm.$t('Alert'));
                                        vm.AttachmentFileDetail=[];
                                    
                                 }
                                    }
                                }
                                else
                                {
                                    vm.ShowAlert('File size not allowed to share '+fsize +' MB', "failure",false, vm.$t('Alert'));
                                    return false
                                }
                                
                            })
                           
                           
                            
                        }
                    
                    })    
                    })
            }
