            // Debounce the scroll handler
            let debounceTimeout;

            listElm.addEventListener('scroll', () => {
                if (debounceTimeout) clearTimeout(debounceTimeout);

                debounceTimeout = setTimeout( () => {
                    // Check if scrolled to the top, and prevent multiple API hits with isLoading flag
                    if (listElm.scrollTop <= 0 && this.allRecordCount < this.totalRecord && !this.isLoading) {
