        async startRecording() {

            const constraints = {
                audio: true,
            };

            navigator.mediaDevices.getUserMedia(constraints)
                .then((stream) => {
                this.mediaRecorder = new MediaRecorder(stream);
                this.mediaRecorder.ondataavailable = event => {
                this.audioChunks.push(event.data);
                };
                this.mediaRecorder.start();
                this.mediaRecorder.onstop = this.handleStop;


                this.isRecording = true;
                this.recordingTime = 0;
                this.intervalId = setInterval(() => {
                this.recordingTime++;
                if (this.recordingTime == 10) {
                    //this.stopRecording();
                }
                }, 1000);
                  
                })
                .catch((error) => {
                    this.ShowAlert(this.$t("ConnectDevice"), "failure", false, this.$t("Alert"));
                });
        },



        stopRecording(event) {
            
            //if true then delete Recording
            this.recordingSendOrDelete = event
            clearInterval(this.intervalId);
            this.mediaRecorder.stop();
            this.isRecording = false;
        },
        handleStop() {

            if(!this.recordingSendOrDelete){
            this.audioBlob = new Blob(this.audioChunks, { type: 'audio/x-wav' });
            this.uploadAudio(this.audioBlob);
            }
            this.audioChunks = [];
            clearTimeout(this.recordingTimer);
            this.recordingTimer = null;

            // Clear the interval and reset the recording time
            clearInterval(this.intervalId);
            this.intervalId = null;
            this.mediaRecorder = null

            this.recordingTime = 0;
        },
        async uploadAudio(audio) {
            const vm = this;
            let parent_id='';
            let parent_text=''
            if (vm.replyOnData.length > 0) {
                 parent_id = vm.replyOnData[0].CHATLOG_ID;
                 parent_text = vm.replyOnData[0].MESSAGE;
                if (parent_id > 0) {
                    var detail = '';
                    if (parent_id > 0) {
                        detail = '1~' + vm.replyOnData[0].USER_NAME + '~' + vm.replyOnData[0].MESSAGE_TOKEN;
                    }
                    else {
                        detail = '0~' + vm.replyOnData[0].USER_NAME + '~' + vm.replyOnData[0].MESSAGE_TOKEN;
                    }
                }
            }

            this.token = vm.GetUserInfo ? vm.GetUserInfo.Token : ''
            const formData = new FormData();
            formData.append('file', audio, 'recording.wav');
            formData.append("fileId", 0);
            formData.append("folderId", 0);
            formData.append("moduleName", 'UnifiedCommunication');
            formData.append("subModuleName", '');
            formData.append("isGlobal", 0);
            await axios.post(vm.uploadUrl, formData, {
                headers: {
                    'Authorization': 'Bearer ' + vm.token
                }
            }).then((response) => {

                //vm.progressValue+=55;
                if (response.data.ErrorMsg == null) {
                    if (JSON.parse(response.data.FileId)[0].Value > 0) {
                        vm.SavedFileId = JSON.parse(response.data.FileId)[0].Value;
                        var params = {
                            companyId: vm.sender.companyId,
                            userId: vm.sender.id,
                            parentId: parent_id,
                            fileType: '',
                            parentTxt: ((typeof parent_text === 'undefined') ? "" : parent_text),
                            parentDetail: ((typeof detail === 'undefined') ? "" : detail),
                            roomId: vm.chatHistoryDetails.groupDetail.GROUP_ID,
                            email: vm.sender.Email,
                            storagefileId: parseInt(vm.SavedFileId),
                            finalUrl: null,
                            file: response.data.FileName,
                            size: response.data.FileSize,
                            url: response.data.FilePath,
                            from: vm.sender.id,
                            typePath: response.data.FileType,
                            fromUser:vm.sender.name
                        }
                        // vm.ShowAlert("File new version has been upload successfully", "success", true);
                        vm.$socket.emit('Send attachments', params)
                        vm.ReplyCross();
                        vm.isLoading = false;
                        setTimeout(() => {
                            vm.fileInProgress = false
                        }, 100)

                    }
                    //this.mediaRecorder.stop();
                    this.isRecording = false;
                    
                }
                else {
                    vm.fileInProgress = false;
                    //this.mediaRecorder.stop();
                    this.isRecording = false;
                    vm.ShowAlert(response.data.ErrorMsg, "failure", vm.$t('Alert'));

                }
                
                var objNew = {
                    roomId: vm.chatHistoryDetails.groupDetail.GROUP_ID,
                    senderId: vm.sender.id
                }
         
                vm.$socket.emit('chatTab blink new message', objNew);

            })
