                if (!groups[date]) {
                    groups[date] = [];
                }
                groups[date].push(data);
                return groups;
            }, {});

            // Edit: to add it in the array format instead
            return Object.keys(groups).map((date) => {
                return {
                    date,
                    data: groups[date]
                };
            });
