<template>
<div class="row mb-2">
    <div class="col-md-12 d-flex align-items-center justify-content-between   border p-3 mb-3">
        <p class="mb-0">Enable notification</p>
        <div class="user-setting"><input type="checkbox" v-model="chatSetting.enable_notification" id="switch" @change="formSubmit()" /><label for="switch">Toggle</label></div>
    </div>
    <div class="col-md-12 d-flex align-items-center justify-content-between   border p-3 mb-3">
        <p class="mb-0">Show message preview</p>
        <div class="user-setting"> <input type="checkbox" id="switch2" v-model="chatSetting.show_message_preview" @change="formSubmit()" /><label for="switch2">Toggle</label></div>
    </div>
    <div class="col-md-12 d-flex align-items-center justify-content-between   border p-3 mb-3">
        <p class="mb-0">Show notifications for calls</p>
        <div class="user-setting"><input type="checkbox" id="switch3" v-model="chatSetting.show_calls_notifications" @change="formSubmit()" /><label for="switch3">Toggle</label></div>
    </div>
    <div class="col-md-12 d-flex align-items-center justify-content-between   border p-3 mb-3">
        <p class="mb-0">Play sound for incoming calls and notifications</p>
        <div class="user-setting"><input type="checkbox" id="switch4" v-model="chatSetting.incoming_calls_sound" @change="formSubmit()" /><label for="switch4">Toggle</label></div>
    </div>
    <div class="col-md-12 mb-1 p-0">
        <h4 class="font-size-16" style="font-weight:500">In chat message sound</h4>

    </div>

    <div class="col-md-12 d-flex align-items-center justify-content-between   border p-3 mb-3">
        <p class="mb-0">Hear a notification sound for sent and received message while in the chat.</p>
        <div class="user-setting"><input type="checkbox" id="switch5" v-model="chatSetting.message_sound" @change="formSubmit()" /><label for="switch5">Toggle</label></div>
    </div>
</div>
</template>

    
<script>
import {
    ValidationObserver
} from 'vee-validate';

import DataService from '../services/DataService';
export default {
    name: "NotificationShow",
    components: {
        ValidationObserver,
    },
    props: {
        store: {
            type: Object
        },
    },
    data() {
        return {
            chatSetting: {
                enable_notification: false,
                show_calls_notifications: false,
                show_message_preview: false,
                incoming_calls_sound: false,
                message_sound: false,
                layout: 'Default',
                bg_color: '',
                keep_archived: false,
                read_receipts_enabled: false,
            }
        }
    },
    created() {
        this.FetchData()
    },
    methods: {
        async FetchData() {
            console.log("checkk", this.store.getMessageAndNotification)
            Object.assign(this.chatSetting, this.store.getMessageAndNotification)
        },
        formSubmit() {
            this.chatSetting.status_id = 101
            DataService.ChatSetting(this.chatSetting).then(() => {
                this.store.messageAndNotification()
                this.ShowAlert(this.$t("saveChatSetting",[this.$t('Notification')]), "success", true, this.$t("Alert"));
            })
        }

    },

}
</script>
