<script>
import DataService from '../services/DataService';
import {
    getPreviousDay
} from "@/assets/common/vue-common"
export default {
    components: {

    },
    name: "SMS",
    props: {
        store: {
            type: Object
        },
        bulkContactSMS:{
            type:Array
        }

    },
    data() {
        return {
            sendMessageVia: 'twilio',
            messageList: [],
            toNumber: '',
            from: this.store.getTwilioAccountDetails?.NUMBER,
            txtMessage: '',
            userDetail: ''

        }
    },
    created: async function () {

    },

    mounted() {
        //this.messageSend('twilio')
        //this.getSmsDetailList();
    },

    beforeDestroy() {},
    computed: {
        messageListData() {
            return this.groupByDate(this.messageList)
        }

    },
    sockets: {
        messageGet: function (details) {
            
            this.toNumber = this.userDetail?.otherphone
            // this.toNumber = "+16506660036"
            if (this.toNumber == details.From) {
          
                details.body = details.Body
                details.smsFrom = details.From
                details.smsTo = details.To
                details.smsStatus = details.SmsStatus
                details.dateCreated = new Date()
                details.blinking = true
                details.dateUpdated = details.dateCreated.toString()
                this.messageList.push(details)
            }
            ///console.log("details", details)
        },
        messageStatus: function (details) {
           
            this.toNumber = this.userDetail?.otherphone
            //this.toNumber = "+16506660036"
            if (this.toNumber == details.To) {
       
                var foundIndex = this.messageList.findIndex(item => item.sid == details.SmsSid)
                if(this.messageList[foundIndex]){
                    this.messageList[foundIndex].smsStatus = details.SmsStatus
                }
                // message.senderId = req.senderId
                // message.receiverId = req.receiverId
                // message.companyId = req.companyId
            }
        },
        getMessageSearchDataOut: function (record) {
            this.txtMessage = ''
            this.messageList = record.SMS
            this.userDetail = record.userDetail

        }

    },
    watch: {

    },
    methods: {
        /**
         * if open in mobile view then add class 
         */
        checkScreenAndAddCall() {
            var ww = document.body.clientWidth;
            if (ww < 992) {
                const responsiveDiv = document.querySelector(".user-chat")
                responsiveDiv.classList.add("user-chat-show")
            }

        },
        removeClass() {
            let element = document.querySelector(".user-chat");
            element.classList.remove("user-chat-show");
        },

        //console.log("checkk",this.store.getContactList
        messageSend(event) {
           
            let vm = this;
            if (vm.txtMessage != '') {
                vm.toNumber = vm.userDetail?.otherphone
                if (vm.sendMessageVia == 'twilio') {
                    if(vm.bulkContactSMS.length == 0){
                    vm.$socket.emit('twilioSendMessage', {
                        from: vm.from, //this.fromNumber
                        to: vm.toNumber, //this.toNumber
                        body: vm.txtMessage,
                        senderId: vm.store.GetSenderDetail.id,
                        receiverId:'',
                        companyId: vm.store.GetSenderDetail.companyId
                    }, function (record) {
                        vm.txtMessage = ''
                        record.smsFrom = record.from
                        record.smsTo = record.to
                        record.smsStatus= record.SmsStatus
                        vm.messageList.push(record)
                        let data = {
                LOGINUSER_ID: vm.store.GetSenderDetail.id,
                COMPANY_ID: vm.store.GetSenderDetail.companyId,
                PhonNo:vm.from
            }
            vm.$socket.emit('GetsmsListbyid',data)

                    })
                }else{
                    vm.bulkContactSMS.map((item)=>{
                    vm.$socket.emit('twilioSendMessage', {
                        from: vm.from, //this.fromNumber
                        to: item, //this.toNumber
                        body: vm.txtMessage,
                        senderId: vm.store.GetSenderDetail.id,
                        receiverId:'',
                        companyId: vm.store.GetSenderDetail.companyId
                    }, function (record) {
                        vm.txtMessage = ''
                        record.smsFrom = record.from
                        record.smsTo = record.to
                        record.smsStatus= record.SmsStatus
                        vm.messageList.push(record)
                        let data = {
                LOGINUSER_ID: vm.store.GetSenderDetail.id,
                COMPANY_ID: vm.store.GetSenderDetail.companyId,
                PhonNo:vm.from
            }
            vm.$socket.emit('GetsmsListbyid',data)

                    })
                })
                }
                

                }
            } else {
                this.ShowAlert(this.$t('PleaseEnterMessage'), "failure", this.$t('Alert'));
            }
        },
        // Used this method for date difference
        DateDifference(ActualDate) {
    const vm = this;
    const GetCurrentDate = new Date();
    const GetValueInSeconds = Math.ceil((GetCurrentDate.getTime() - new Date(ActualDate).getTime()) / 1000);
    
    // Time unit constants in seconds
    const secondsInMinute = 60;
    const secondsInHour = 3600;
    const secondsInDay = 86400;
    const secondsInMonth = 2592000; // Approx. 30 days
    const secondsInYear = 31536000; // Approx. 365 days
    
    if (GetValueInSeconds < secondsInMinute) {
        return vm.$t('now');
    } 
    if (GetValueInSeconds < 2 * secondsInMinute) {
        return vm.$t('minute');
    } 
    if (GetValueInSeconds < secondsInHour) {
        return Math.floor(GetValueInSeconds / secondsInMinute) + ' ' + vm.$t('minute');
    } 
    if (GetValueInSeconds < 2 * secondsInHour) {
        return vm.$t('an') + ' ' + vm.$t('hour');
    } 
    if (GetValueInSeconds < secondsInDay) {
        return Math.floor(GetValueInSeconds / secondsInHour) + ' ' + vm.$t('hour');
    } 
    if (GetValueInSeconds < 2 * secondsInDay) {
        return vm.$t('Yesterday');
    } 
    if (GetValueInSeconds < secondsInMonth) {
        return Math.floor(GetValueInSeconds / secondsInDay) + ' ' + vm.$t('day');
    } 
    if (GetValueInSeconds < secondsInYear) {
        const months = Math.floor(GetValueInSeconds / secondsInMonth);
        return months <= 1 ? '1 ' + vm.$t('month') : months + ' ' + vm.$t('months');
    } 

    const years = Math.floor(GetValueInSeconds / secondsInYear);
    return years <= 1 ? '1 ' + vm.$t('year') : years + ' ' + vm.$t('years');
},
        // getSmsDetailList() {

        //     let data = {
        //         LOGINUSER_ID: this.store.GetSenderDetail.id,
        //         COMPANY_ID: this.store.GetSenderDetail.companyId,
        //         PhonNo:this.from
        //     }

        //     this.$socket.emit('GetsmsListforCurrentUsers', data)
        //     //  this.$socket.emit('smsList', {
        //     //              from: this.from, //this.fromNumber
        //     //              to: this.toNumber
        //     //         }, function (record) {
        //     //              console.log("checkk",record)
        //     //          })

        // },
        getTime(date) {
            date = new Date(date)
            const newInputDate = date;

            const timeStamp = new Date(newInputDate);
            return timeStamp.toLocaleTimeString(navigator.language, {
                hour: '2-digit',
                minute: '2-digit'
            })
        },
        groupByDate(data) {
            return data.reduce((acc, item) => {
                const date = new Date(item.dateUpdated).toISOString().split('T')[0]; // Extract the date part
                if (!acc[date]) {
                    acc[date] = [];
                }

                acc[date].push(item);
               
                return acc;
            }, {});
        },
       async redirectCall(event) {
            if (this.store.$state.callToken) {
                var params = {
                    To:  event,
                };
               await this.store.makeOutgoingCall(params)
                //this.$parent.callFromOtherTab(event)
            } else {
                this.ShowAlert(this.$t("ConnectDevice"), "failure", true, this.$t("Alert"));
            }

        },
        childReset(){
           
            this.messageList = []
            this.txtMessage = ''
        }
    },

