<template>
<div class="row mb-2 device_scroll">
    
    <div class="col-md-12 mb-1 p-0">
        <h4 class="font-size-16" style="font-weight:500">{{ $t('KeepChatArchived') }}</h4>
    </div>
    <div class="col-md-12 d-flex align-items-center justify-content-between   border p-3 mb-3">
        <p class="mb-0">{{ $t('ArchivedChatsMessage') }}</p>
        <div class="user-setting"> <input type="checkbox" id="switch2" v-model="chatSetting.keep_archived"  @change="formSubmit()" /><label for="switch2">Toggle</label></div>
    </div>

    <div class="col-md-12 mb-1 p-0">
        <h4 class="font-size-16" style="font-weight:500">{{ $t('ReadReceipts') }}</h4>

    </div>
    <div class="col-md-12 d-flex align-items-center justify-content-between   border p-3 mb-3">
        <p class="mb-0">{{ $t('ReadReceiptsGroupChats') }}</p>
        <div class="user-setting"><input type="checkbox" id="switch3" v-model="chatSetting.read_receipts_enabled" @change="formSubmit()" /><label for="switch3">Toggle</label></div>
    </div>
    <div class="col-md-12 mb-1 mt-3 p-0">
        <h4 class="font-size-16" style="font-weight:500">{{ $t('ChooseColor') }}</h4>
        <div class="color-chooose">
            <div class="greenbg squarebx" @click="chatSetting.bg_color='light';formSubmit();themeChange('light')"><i v-if="chatSetting.bg_color=='light'" class="fas fa-check"></i></div>
            <div class="bluebg squarebx" @click="chatSetting.bg_color='blue';formSubmit();themeChange('blue')"><i v-if="chatSetting.bg_color=='blue'" class="fas fa-check"></i></div>
            <div class="orangebg squarebx" @click="chatSetting.bg_color='orange';formSubmit();themeChange('orange')"><i v-if="chatSetting.bg_color=='orange'" class="fas fa-check"></i></div>
            <div class="darkbluebg squarebx" @click="chatSetting.bg_color='dblue';formSubmit();themeChange('dblue')"><i v-if="chatSetting.bg_color=='dblue'" class="fas fa-check"></i></div>
        </div>
    </div>

    <div class="col-md-12 mb-1 mt-5 p-0" v-if="store.getUserInformation.UserType=='CA'">
        <h4 class="font-size-20" style="font-weight:500">{{ $t('FileConfigurationSettings') }}</h4>        
    </div>

<template v-if="store.getUserInformation.UserType=='CA'">
 
    
    <div class="col-md-12 mb-1 mt-3 p-0" >
      <h4 class="font-size-16" style="font-weight:500">{{ $t('AllowedFileMB') }}:</h4>
      <div class="col-md-12" >
        <ProgressBar v-model="systemSetting.fileSize"  :max="550"/>
        <p>Size: {{ systemSetting.fileSize }} {{ $t('MB') }}</p>
      </div>
    </div>

    <div class="col-md-12 mb-1 mt-3 p-0" >
      <h4 class="font-size-16 " style="font-weight:500">{{ $t('AllowedFileTypes') }}: 
        <a href="javascript:;" class="position-relative poppyview">
          <div class="poppy_base">{{ $t('AllowedFileTypes_desc') }}</div>
          <i class="far fa-question-circle text-popover" style="font-size: 14px;"></i>
        </a>
      </h4>
      <div class="col-md-12" >
        <multiselect v-model="systemSetting.allowFileType"  label="label" track-by="name" :options="Options" :multiple="true" :close-on-select="false" ></multiselect>
      </div>
    </div>

    <div class="col-md-12 mb-1 mt-3 p-0" >
      <h4 class="font-size-16" style="font-weight:500">{{ $t('VoiceNoteDurationLimit') }}:</h4>
      <div class="col-md-12" >
        <ProgressBar v-model="systemSetting.time"  :max="15"/>
        <p>Time: {{ systemSetting.time }} {{ $t('MIN') }}</p>
      </div>
    </div>
    <div class="text-end text-right" style="margin-top: -20px;">
        <!-- <button type="button" class="btn btn-warning float-left px-4" style="margin-left: 5px;"><i class="fa fa-chevron-left pr-2"></i> Reset</button> -->
        <button type="submit" class="btn btn-success" style="margin-left: 5px;" v-on:click="saveConfiguration"><i class="fa fa-save pr-2"></i> {{ $t('Save') }}</button>
    </div>
</template>


</div>
</template>

<script>
import {
    ValidationObserver
} from 'vee-validate';

import DataService from '../services/DataService';
import ProgressBar from '@/components/Common/ProgressBar.vue'
 import Multiselect from 'vue-multiselect'
export default {
    name: "ChatSetup",
    components: {
        ValidationObserver,
        ProgressBar,
        Multiselect
    },
    props: {
        store: {
            type: Object
        },
    },
    data() {
        return {
            chatSeetingBox: '',
            Options:[],
            chatSetting: {
                enable_notification: false,
                show_calls_notifications: false,
                show_message_preview: false,
                incoming_calls_sound: false,
                bg_color: '',
                keep_archived: false,
                read_receipts_enabled: false,
                layout:'Default',
                fileType : '',
                fileKey :'',
                fileSize :'',
                fileSizeKey:'',
            },
            systemSetting:{
                time:null,
                fileSize:null,
                allowFileType:[]
            },
            configSettingsData:[],
            allowedfiletypeValues:[],
            fileTypeData:''
        }
    },
    created() {
        this.FetchData()
        this.getAllowedFiletypes();
    },
    methods: {
        themeChange(event){
        const body = document.querySelector("body")
            //let bodyTheme = body.getAttribute("data-bs-theme") == 'dark' ? 'light' : 'dark'
            body.setAttribute("data-bs-theme", event)
        },
        async FetchData() {
            Object.assign(this.chatSetting,this.store.getMessageAndNotification)
            this.chatSetting.bg_color = this.chatSetting.bg_color ? this.chatSetting.bg_color : 'light'
        },
        formSubmit() {
            let vm = this
            vm.chatSetting.status_id = 101
            DataService.ChatSetting(vm.chatSetting).then(() => {
                 vm.store.messageAndNotification()
                 vm.ShowAlert(vm.$t("saveChatSetting",[vm.$t('Chat')]), "success");
            })
        },
        getAllowedFiletypes: function()
        {
            const vm=this;
            let params = `moduleName=UnifiedCommunication`;
                    DataService.GetFileType(params).then((response) => {
                        vm.FileTypeData=response.data;
                        vm.FileTypeData.forEach((item, index) => {
                        vm.Options.push({
                        name: item.FileType.toLowerCase(),
                        label: item.FileType.toLowerCase(),
                        });
                    });
            let params = `moduleName=UnifiedCommunication&keyValue=UnifiedCommunicationAllowedFileTypes,UnifiedCommunicationAllowedFileSize,VoiceNoteDurationLimit`;
                    DataService.GetConfigDataValue(params).then((response) => {
                        if(JSON.parse(response.data.ConfigValue).length>0)
                        {
                            vm.configSettingsData=JSON.parse(response.data.ConfigValue);

                            let fileSize = vm.configSettingsData.find(x=>x.CONFIG_DATA_KEY=='UnifiedCommunicationAllowedFileSize')
                            vm.systemSetting.fileSize=Number(fileSize.CONFIG_DATA_VALUE);
                            let timeDurationLimit = vm.configSettingsData.find(x=>x.CONFIG_DATA_KEY=='VoiceNoteDurationLimit')
                            vm.systemSetting.time=Number(timeDurationLimit.CONFIG_DATA_VALUE);

                            let findObject = vm.configSettingsData.find(item=>item.CONFIG_DATA_KEY=='UnifiedCommunicationAllowedFileTypes')
                            let fileTypeFormats = findObject.CONFIG_DATA_VALUE.split('^')
                             fileTypeFormats.forEach(function(x){
                                        vm.systemSetting.allowFileType.push({ label: x,
                                            name: x})
                                        })
                        }
                    })
                })
        },
        saveConfiguration: function() {
        const findIndexArray = ['UnifiedCommunicationAllowedFileTypes', 'UnifiedCommunicationAllowedFileSize', 'VoiceNoteDurationLimit'];
        const configObj = findIndexArray.map(item => {
            const key = this.configSettingsData.find(record => record.CONFIG_DATA_KEY === item);
            let DataValue;
            let val = "";
            switch(item) {
                case 'UnifiedCommunicationAllowedFileTypes':
                    this.systemSetting.allowFileType.forEach(function(item){
                        if(val == ""){
                            val = item.label;
                        } else {
                            val = val + '^' + item.label;
                        }
                    })
                    DataValue = val;
                    break;
                case 'UnifiedCommunicationAllowedFileSize':
                    DataValue = Number(this.systemSetting.fileSize);
                    break;
                case 'VoiceNoteDurationLimit':
                    DataValue = Number(this.systemSetting.time);
                    break;
                default:
                    DataValue = '';
            }

            return {
                DataId: key ? key.core_config_id : null,
                key: key ? key.CONFIG_DATA_KEY : null,
                DataValue: DataValue
            };
        });

        const paramObj = {
            configData: configObj,
            conditionData: {
                refCode: 'CompanySetting',
                moduleName: 'UnifiedCommunication'
            }
        };
    const data = JSON.stringify(paramObj);

    DataService.ManageDocUserStorageSettingData(data).then(response => {
        if (response && response.data === 1) {
            this.ShowAlert(this.$t('RecordsSavedSuccessfully'), 'success');
        } else {
            this.ShowAlert(this.$t("UnknownErrorOccur"), "failure", false, this.$t("Alert"));
        }
    });
}



    },

}
</script>
