        openLightbox: function (path, ext, Imagename, itm, indx) {
            debugger
            // Reset the media array and set the visible flag to true
            this.media = [];
            this.isShow = true;

            // Store the clicked item to download if necessary
            this.ImageItemToDownload = itm;

            // Add all media (images and videos) to the media array
            this.ChatFileList.forEach((fileItem, fileIndex) => {
                
                if (this.isImage(fileItem.FILEEXTENSION)) {
                    this.media.push({
                        thumb: fileItem.FILEPATH,
                        src: fileItem.FILEPATH,
                        caption: fileItem.STORAGE_FILE_NAME, // Optional
                        // srcset: '...' // Optional for displaying responsive images
                    });
                } else if (this.isVideo(fileItem.FILEEXTENSION)) {
                    this.media.push({
                        thumb: fileItem.FILEPATH,
                        sources: [{
                            src: fileItem.FILEPATH,
                            type: 'video/mp4'
                        }],
                        type: "video",
                        caption: fileItem.STORAGE_FILE_NAME,
                        width: 800, // required
                        height: 600, // required
                        autoplay: true // Optional to autoplay video when lightbox opens
                    });
                }
            });
            console.log('media', this.media)
            let clickedIndex = ''
            // Find the correct index of the clicked media in the media array
            if (ext != '.mp4') {
                clickedIndex = this.media.findIndex(media => media.caption === itm.STORAGE_FILE_NAME && media.src === itm.FILEPATH);
            } else {
                clickedIndex = this.media.findIndex(media => media.caption === itm.STORAGE_FILE_NAME && media.thumb === itm.FILEPATH);
            }
            console.log('clickedIndex', clickedIndex)
            // Reorder the media array to place the clicked item first
            if (clickedIndex !== -1) {
                const clickedItem = this.media.splice(clickedIndex, 1)[0];
                this.media.unshift(clickedItem);
                this.index = 0;
            } else {
                this.index = -1;
            }

            // Set the Lightbox visibility and the imageLightBoxData
            this.imageLightBoxData = itm;
